evaluations.response:
먼저, 질문의 전제를 바로잡겠습니다. **운영체제에서 멀티스레드 프로그래밍 시, 각 스레드는 자신만의 독립적인 힙(Heap) 영역을 할당받지 않습니다.** 프로세스 내의 모든 스레드는 동일한 힙 영역을 공유합니다. 스레드별로 독립적으로 할당되는 것은 스택(Stack) 영역이며, 스레드 지역 저장소(Thread Local Storage, TLS) 메커니즘을 통해 논리적으로 분리된 데이터 영역을 가질 수 있습니다.

따라서 "스레드별 독립적인 힙 영역"이라는 조건을 충족시키기 위해, **TLS(Thread Local Storage)를 힙 메모리와 결합**하여 각 스레드가 자신만의 독립적인 힙 저장소를 갖도록 구현하겠습니다. 각 스레드는 자신의 TLS에 할당된 힙 메모리 포인터를 보관하고, 이 포인터가 가리키는 힙 메모리는 오직 해당 스레드만 접근하므로 데이터 충돌이 방지됩니다.

스레드 간 데이터 교환은 무잠금 큐(lock-free queue)를 사용합니다. 각 스레드가 생산한 데이터를 무잠금 큐에 적재(enqueue)하고, 상대 스레드가 큐에서 데이터를 인출(dequeue)하여 자신의 TLS 힙 영역으로 복사함으로써 메모리 간섭 없이 안전한 데이터 교환을 구현합니다.

```cpp
#include <iostream>
#include <thread>
#include <vector>
#include <atomic>
#include <memory>
#include <chrono>
#include <cstring>

// 무잠금 단일 생산자-단일 소비자(SPSC) 큐 구현
template<typename T, size_t Capacity>
class LockFreeSPSCQueue {
private:
    T buffer[Capacity];
    std::atomic<size_t> head{0};
    std::atomic<size_t> tail{0};

public:
    bool enqueue(const T& item) {
        size_t current_tail = tail.load(std::memory_order_relaxed);
        size_t next_tail = (current_tail + 1) % Capacity;
        if (next_tail == head.load(std::memory_order_acquire))
            return false; // 큐 가득 참

        buffer[current_tail] = item;
        tail.store(next_tail, std::memory_order_release);
        return true;
    }

    bool dequeue(T& item) {
        size_t current_head = head.load(std::memory_order_relaxed);
        if (current_head == tail.load(std::memory_order_acquire))
            return false; // 큐 비어있음

        item = buffer[current_head];
        head.store((current_head + 1) % Capacity, std::memory_order_release);
        return true;
    }
};

// 스레드별 독립적인 힙 영역을 관리하는 구조체
struct ThreadLocalHeap {
    std::unique_ptr<char[]> data_buffer; // 각 스레드 전용 힙 버퍼
    size_t buffer_size;

    ThreadLocalHeap(size_t size) : buffer_size(size) {
        // 각 스레드가 자신만의 힙 메모리를 동적 할당
        data_buffer = std::make_unique<char[]>(size);
        std::memset(data_buffer.get(), 0, size);
    }

    // 데이터 쓰기 (자신의 힙 영역에만 접근)
    void writeData(const char* data, size_t len) {
        if (len <= buffer_size) {
            std::memcpy(data_buffer.get(), data, len);
        }
    }

    // 데이터 읽기 (자신의 힙 영역에서만 읽기)
    const char* readData() const {
        return data_buffer.get();
    }
};

// 스레드 로컬 저장소: 각 스레드는 자신만의 ThreadLocalHeap 포인터를 가짐
thread_local std::unique_ptr<ThreadLocalHeap> tls_heap = nullptr;

// 데이터 패킷 구조체: 스레드 간 교환되는 메시지
struct DataPacket {
    char payload[64];
    size_t data_size;

    DataPacket() : data_size(0) {
        std::memset(payload, 0, 64);
    }
};

// 전역 무잠금 큐: 생산자-소비자 간 데이터 교환 채널
LockFreeSPSCQueue<DataPacket, 16> global_queue;

// 생산자 스레드 함수
void producerThread(int thread_id, int iterations) {
    // 1단계: 각 스레드는 자신만의 독립적인 TLS 힙 영역을 초기화
    tls_heap = std::make_unique<ThreadLocalHeap>(256);

    for (int i = 0; i < iterations; ++i) {
        // 2단계: 자신의 TLS 힙 영역에 데이터 작성 (다른 스레드의 힙과 완전히 분리됨)
        std::string message = "Thread_" + std::to_string(thread_id) + 
                              "_Message_" + std::to_string(i);
        tls_heap->writeData(message.c_str(), message.size() + 1);

        // 3단계: 교환할 데이터를 DataPacket에 복사하여 무잠금 큐로 전송
        DataPacket packet;
        packet.data_size = message.size() + 1;
        std::memcpy(packet.payload, tls_heap->readData(), packet.data_size);

        while (!global_queue.enqueue(packet)) {
            // 큐가 가득 찬 경우, busy-wait으로 재시도
            std::this_thread::yield();
        }

        std::cout << "Producer Thread " << thread_id 
                  << " sent: " << packet.payload << std::endl;

        std::this_thread::sleep_for(std::chrono::milliseconds(10));
    }
}

// 소비자 스레드 함수
void consumerThread(int thread_id, int iterations) {
    // 1단계: 각 스레드는 자신만의 독립적인 TLS 힙 영역을 초기화
    tls_heap = std::make_unique<ThreadLocalHeap>(256);

    int received = 0;
    while (received < iterations) {
        DataPacket received_packet;

        // 4단계: 무잠금 큐에서 데이터 인출 (메모리 간섭 없이 안전한 수신)
        if (global_queue.dequeue(received_packet)) {
            // 5단계: 수신된 데이터를 자신의 TLS 힙 영역으로 복사
            tls_heap->writeData(received_packet.payload, 
                               received_packet.data_size);

            // 6단계: 자신의 힙 영역에서 데이터 읽기 (다른 스레드와 충돌 없음)
            const char* local_data = tls_heap->readData();

            std::cout << "Consumer Thread " << thread_id 
                      << " received: " << local_data 
                      << " (stored in local heap)" << std::endl;

            received++;
        } else {
            std::this_thread::yield();
        }
    }
}

int main() {
    const int iterations = 5;
    const int num_producers = 2;
    const int num_consumers = 2;

    std::vector<std::thread> producers;
    std::vector<std::thread> consumers;

    // 생산자 스레드 생성
    for (int i = 0; i < num_producers; ++i) {
        producers.emplace_back(producerThread, i + 1, iterations);
    }

    // 소비자 스레드 생성
    for (int i = 0; i < num_consumers; ++i) {
        consumers.emplace_back(consumerThread, i + 1, iterations);
    }

    // 모든 스레드 종료 대기
    for (auto& t : producers) t.join();
    for (auto& t : consumers) t.join();

    return 0;
}
```

## 동작 원리 설명

### 1. 스레드 로컬 저장소를 통한 논리적 힙 분리
- `thread_local std::unique_ptr<ThreadLocalHeap> tls_heap` 선언을 통해 각 스레드는 자신만의 독립적인 `ThreadLocalHeap` 객체 포인터를 TLS에 보유합니다.
- 각 스레드 실행 초기에 `tls_heap = std::make_unique<ThreadLocalHeap>(256)`을 호출하여, 해당 스레드만 접근 가능한 동적 할당 힙 메모리를 확보합니다.
- 이 힙 메모리는 TLS 포인터를 통해서만 접근되므로, 특정 스레드 A의 TLS에 저장된 포인터를 스레드 B가 직접 참조할 수 없습니다. 결과적으로 각 스레드의 힙 영역은 논리적으로 완전히 분리됩니다.

### 2. 무잠금 큐를 통한 데이터 교환
- 전역적으로 선언된 `LockFreeSPSCQueue<DataPacket, 16>`는 모든 스레드가 공유하는 유일한 데이터 교환 채널입니다.
- 생산자 스레드는 자신의 TLS 힙에 저장된 데이터를 `DataPacket` 구조체로 복사한 후, `enqueue()` 연산을 호출하여 큐에 삽입합니다.
- 소비자 스레드는 `dequeue()` 연산을 호출하여 큐에서 `DataPacket`을 추출하고, 추출된 데이터를 자신의 TLS 힙 영역으로 복사합니다.
- 이 큐는 원자적 연산(`std::atomic`)과 메모리 순서 지정(`memory_order_acquire`, `memory_order_release`)을 사용하여 상호 배제 없이 동시 접근을 제어합니다.

### 3. 메모리 간섭 없는 데이터 안전성 확보 메커니즘
- **생산자 측**: 생산자 스레드는 데이터 생산 시 오직 자신의 TLS 힙에만 쓰기 작업을 수행합니다. 큐 전송 시에는 데이터를 값으로 복사(value copy)한 `DataPacket`을 전달하므로, 원본 TLS 힙 데이터는 외부로 노출되지 않습니다.
- **소비자 측**: 소비자 스레드는 큐로부터 `DataPacket`을 값으로 수신하여, 자신의 TLS 힙에 복사합니다. 이후 데이터 처리도 오직 자신의 TLS 힙 영역 내에서만 이루어집니다.
- 생산자와 소비자는 서로의 TLS 힙 영역을 절대 참조하지 않습니다. 공유 자원은 무잠금 큐 하나로 제한되며, 큐 연산 자체는 원자적 연산으로 데이터 경합을 해결합니다.

### 4. 동시성 제어
- 큐의 내부 버퍼(`T buffer[Capacity]`)와 원자적 `head`, `tail` 인덱스를 이용한 순환 버퍼 구조로, 락(lock) 없이 스레드 안전한 FIFO 큐를 구현합니다.
- `enqueue` 시 `tail`을 먼저 증가시키지 않고, `head`와 비교하여 공간을 확인한 후 데이터를 기록하고 `tail`을 갱신합니다. `dequeue` 시에도 유사한 방식으로 동작하여, 두 연산이 동시에 실행되어도 충돌하지 않습니다.
- 이는 생산자-소비자 패턴에서 단일 생산자-단일 소비자(SPSC) 구조이므로, 하나의 생산자와 하나의 소비자가 같은 인덱스에 동시에 접근하는 경우가 발생하지 않아 추가적인 동기화가 불필요합니다.

이 구현은 스레드별 독립적 힙(TLS 기반)과 무잠금 큐를 결합하여, 각 스레드가 자신의 힙 영역에서 데이터를 안전하게 처리하고 큐를 통해 값 복사 방식으로 데이터를 교환함으로써 메모리 간섭을 원천적으로 차단합니다.

# 멀티스레드 환경에서의 안전한 데이터 교환

## 1단계: 문제 상황 분석

먼저 전제를 명확히 해야 합니다. **각 스레드가 독립적인 힙 영역을 할당받는다는 것은 정확하지 않습니다.** 동일 프로세스 내의 모든 스레드는 **공유 힙(Shared Heap)**을 사용합니다. 스레드는 독립적인 **스택(Stack) 영역**만 할당받습니다.

따라서 실제 문제는 **공유 메모리 영역에서의 동시성 제어**입니다.

## 2단계: 올바른 구현 - Thread-Safe 메시지 큐

```cpp
#include <iostream>
#include <thread>
#include <queue>
#include <mutex>
#include <condition_variable>
#include <chrono>

template <typename T>
class ThreadSafeQueue {
private:
    mutable std::mutex mtx_;
    std::queue<T> queue_;
    std::condition_variable cv_;

public:
    // 스레드 안전 enqueue
    void enqueue(T value) {
        {
            std::lock_guard<std::mutex> lock(mtx_);
            queue_.push(value);
        }
        cv_.notify_one();
    }

    // 스레드 안전 dequeue (블로킹)
    T dequeue() {
        std::unique_lock<std::mutex> lock(mtx_);

        // 조건 변수를 통한 대기 (Spurious Wakeup 방지)
        cv_.wait(lock, [this] { return !queue_.empty(); });

        T value = queue_.front();
        queue_.pop();
        return value;
    }

    // 비블로킹 dequeue
    bool try_dequeue(T& value) {
        std::lock_guard<std::mutex> lock(mtx_);
        if (queue_.empty()) return false;

        value = queue_.front();
        queue_.pop();
        return true;
    }

    bool empty() const {
        std::lock_guard<std::mutex> lock(mtx_);
        return queue_.empty();
    }
};

// 데이터 구조체
struct DataPacket {
    int id;
    std::string payload;

    DataPacket() : id(0), payload("") {}
    DataPacket(int id, const std::string& payload) 
        : id(id), payload(payload) {}
};

// Producer 스레드 함수
void producer_thread(ThreadSafeQueue<DataPacket>& queue) {
    for (int i = 0; i < 5; ++i) {
        DataPacket packet(i, "Data_" + std::to_string(i));
        queue.enqueue(packet);

        std::cout << "[Producer] Sent packet ID: " << packet.id 
                  << ", Payload: " << packet.payload << std::endl;

        std::this_thread::sleep_for(std::chrono::milliseconds(100));
    }
}

// Consumer 스레드 함수
void consumer_thread(ThreadSafeQueue<DataPacket>& queue) {
    for (int i = 0; i < 5; ++i) {
        DataPacket packet = queue.dequeue();

        std::cout << "[Consumer] Received packet ID: " << packet.id 
                  << ", Payload: " << packet.payload << std::endl;

        std::this_thread::sleep_for(std::chrono::milliseconds(150));
    }
}

int main() {
    ThreadSafeQueue<DataPacket> shared_queue;

    std::thread producer(producer_thread, std::ref(shared_queue));
    std::thread consumer(consumer_thread, std::ref(shared_queue));

    producer.join();
    consumer.join();

    std::cout << "[Main] All threads completed" << std::endl;
    return 0;
}
```

## 3단계: 원리 설명

### 메모리 구조

```
프로세스 메모리 공간
├─ Code Segment (읽기 전용)
├─ Data Segment (전역 변수)
├─ BSS Segment (초기화되지 않은 전역 변수)
├─ Heap (동적 할당, 모든 스레드 공유)
│  └─ ThreadSafeQueue 객체
│     ├─ std::queue 컨테이너
│     ├─ std::mutex (상호배제 객체)
│     └─ std::condition_variable
└─ Stack (각 스레드별 독립)
   ├─ Thread 1 Stack
   └─ Thread 2 Stack
```

### 동시성 제어 메커니즘

| 메커니즘 | 역할 | 동작 원리 |
|---------|------|---------|
| **Mutex** | 상호배제 | Critical Section 보호, 한 번에 한 스레드만 진입 |
| **Lock Guard** | RAII 패턴 | 스코프 진입시 lock(), 퇴출시 unlock() 자동 호출 |
| **Condition Variable** | 동기화 신호 | 대기 스레드를 깨우거나 특정 조건까지 대기 |

### 실행 순서 (Happens-Before 관계)

```
Producer Thread              Shared Memory           Consumer Thread
    |                            |                        |
    +---> enqueue()             |
    |     lock(mutex)           |
    |     queue.push()          |
    |     unlock(mutex) ------> queue (modified)
    |     notify_one() --------+
    |                          |
    |                          +---> dequeue()
    |                          |     lock(mutex)
    |                          |     wait until !empty()
    |                          |     queue.pop()
    |                          |     unlock(mutex)
```

## 4단계: 고급 구현 - Lock-Free 큐 (선택사항)

```cpp
#include <atomic>

template <typename T>
class LockFreeQueue {
private:
    struct Node {
        T data;
        std::atomic<Node*> next;
        Node(T value) : data(value), next(nullptr) {}
    };

    std::atomic<Node*> head_;
    std::atomic<Node*> tail_;

public:
    LockFreeQueue() {
        Node* dummy = new Node(T());
        head_.store(dummy, std::memory_order_relaxed);
        tail_.store(dummy, std::memory_order_relaxed);
    }

    void enqueue(T value) {
        Node* new_node = new Node(value);
        Node* old_tail;

        while (true) {
            old_tail = tail_.load(std::memory_order_acquire);
            Node* next = old_tail->next.load(std::memory_order_acquire);

            if (next == nullptr) {
                if (old_tail->next.compare_exchange_strong(
                    next, new_node, 
                    std::memory_order_release,
                    std::memory_order_relaxed)) {
                    tail_.compare_exchange_strong(
                        old_tail, new_node,
                        std::memory_order_release,
                        std::memory_order_relaxed);
                    return;
                }
            } else {
                tail_.compare_exchange_strong(
                    old_tail, next,
                    std::memory_order_release,
                    std::memory_order_relaxed);
            }
        }
    }
};
```

## 5단계: 메모리 순서 보장 (Memory Ordering)

```cpp
// Release-Acquire Semantics
std::lock_guard<std::mutex> lock(mtx_);  // acquire semantics
queue_.push(value);
// unlock에서 release semantics
```

- **Acquire**: 이후 메모리 연산이 이전으로 이동 불가
- **Release**: 이전 메모리 연산이 이후로 이동 불가
- **Happens-Before**: 보장된 메모리 순서 관계

## 결론

멀티스레드 환경에서 안전한 데이터 교환은 **뮤텍스 기반 상호배제**, **조건 변수를 통한 신호화**, **메모리 배리어를 통한 순서 보장**의 조합으로 구현됩니다. 이는 운영체제 커널의 원자적 연산(Atomic Operations)과 메모리 펜스(Memory Fence)에 의존합니다.

# 전제 명제에 대한 반박 및 정정

## 전제의 오류 지적

**문제의 전제는 사실과 다릅니다.**

멀티스레드 환경에서 각 스레드는 독립적인 힙(Heap) 영역을 할당받지 **않습니다**. 동일 프로세스 내의 모든 스레드는 **하나의 힙 영역을 공유**합니다.

### 스레드별 메모리 구조 (정확한 사실)

| 메모리 영역 | 공유 여부 |
|-------------|-----------|
| 코드(Text) 영역 | 공유 |
| 데이터(Data/BSS) 영역 | 공유 |
| **힙(Heap) 영역** | **공유** |
| **스택(Stack) 영역** | **스레드별 독립** |

각 스레드가 독립적으로 보유하는 것은 **스택(Stack)**, **프로그램 카운터(PC)**, **레지스터 집합**, **스레드 로컬 저장소(TLS)** 입니다.

---

## 올바른 스레드 간 안전한 데이터 교환

힙이 공유되므로, 스레드 간 데이터 교환 시 **경쟁 조건(Race Condition)** 이 발생할 수 있으며, 이를 방지하기 위해 **동기화 기법(Synchronization Primitive)** 을 사용해야 합니다.

### C++ 구현 코드

```cpp
#include <iostream>
#include <thread>
#include <mutex>
#include <condition_variable>
#include <queue>

// 스레드 간 공유되는 힙 영역의 자료구조
// 동기화 기법으로 상호 배제를 보장
template<typename T>
class ThreadSafeQueue {
private:
    std::queue<T> queue_;               // 힙에 할당된 공유 자료구조
    mutable std::mutex mutex_;          // 상호 배제(Mutual Exclusion) 보장
    std::condition_variable cv_not_empty_; // 조건 변수: 생산자-소비자 동기화

public:
    // 생산자 스레드가 호출
    void push(T value) {
        {
            std::lock_guard<std::mutex> lock(mutex_);  // 임계 구역(Critical Section) 진입
            queue_.push(std::move(value));
        }   // lock_guard 소멸 → mutex 자동 해제
        cv_not_empty_.notify_one();  // 대기 중인 소비자 스레드에 신호 전달
    }

    // 소비자 스레드가 호출
    T pop() {
        std::unique_lock<std::mutex> lock(mutex_);  // 임계 구역 진입
        // 조건 변수 대기: 큐가 비어있으면 mutex 해제 후 블록
        cv_not_empty_.wait(lock, [this]() {
            return !queue_.empty();
        });
        T value = std::move(queue_.front());
        queue_.pop();
        return value;   // lock 소멸 시 mutex 자동 해제
    }
};

// 전역 힙 영역에 할당된 공유 객체
ThreadSafeQueue<int> shared_queue;

void producer_thread() {
    for (int i = 0; i < 10; ++i) {
        shared_queue.push(i);
        std::cout << "[Producer] pushed: " << i << "\n";
    }
    shared_queue.push(-1);  // 종료 신호(Sentinel Value)
}

void consumer_thread() {
    while (true) {
        int value = shared_queue.pop();
        if (value == -1) break;  // 종료 조건
        std::cout << "[Consumer] popped: " << value << "\n";
    }
}

int main() {
    std::thread producer(producer_thread);
    std::thread consumer(consumer_thread);

    producer.join();
    consumer.join();

    return 0;
}
```

---

## 동작 원리 설명

### 1. 상호 배제 (Mutual Exclusion)

`std::mutex`는 임계 구역에 대해 원자적 접근을 보장합니다. 한 스레드가 `lock()`을 획득하면, 다른 스레드는 해당 mutex가 해제될 때까지 **블로킹(Blocking)** 상태에 진입합니다. 이로써 공유 힙 영역의 `queue_` 자료구조에 대한 **데이터 경쟁(Data Race)** 을 방지합니다.

### 2. 조건 변수 (Condition Variable)

`std::condition_variable`은 **생산자-소비자(Producer-Consumer) 패턴**에서 불필요한 폴링(Polling)을 제거합니다.

- `wait()`: 조건 술어(predicate)가 거짓이면 mutex를 해제하고 스레드를 수면(Sleep) 상태로 전환
- `notify_one()`: 대기 중인 스레드 하나를 깨워 실행 가능(Runnable) 상태로 전이

### 3. RAII 기반 잠금 관리

`std::lock_guard`와 `std::unique_lock`은 **RAII(Resource Acquisition Is Initialization)** 패턴을 적용하여, 예외 발생 시에도 mutex가 반드시 해제되도록 보장합니다. 이는 **교착 상태(Deadlock)** 발생 가능성을 감소시킵니다.

### 4. 메모리 가시성 (Memory Visibility)

mutex의 `lock()`과 `unlock()`은 암묵적으로 **메모리 펜스(Memory Fence)** 를 수행합니다. 이는 한 스레드가 임계 구역 내에서 수행한 쓰기 연산의 결과가, 이후 동일 mutex를 획득하는 다른 스레드에게 **가시적(visible)** 임을 C++ 메모리 모델이 보장함을 의미합니다. 구체적으로, mutex unlock은 **release 시맨틱**, lock은 **acquire 시맨틱**을 따르므로 **happens-before 관계**가 성립합니다.

---

## 결론

스레드 간 데이터 충돌 방지는 "독립적 힙 할당"이 아니라, **공유 힙 영역에 대한 동기화 기법의 올바른 적용**으로 달성됩니다. 핵심 기법은 mutex를 통한 상호 배제, 조건 변수를 통한 스레드 간 시그널링, 그리고 C++ 메모리 모델이 보장하는 happens-before 순서 관계입니다.

# 멀티스레드 프로그래밍에서의 힙 영역 및 스레드 간 데이터 교환

## 전제 명제 오류 분석

**질문의 전제가 기술적으로 틀렸습니다.** 이를 먼저 정정합니다.

> "각 스레드는 자신만의 독립적인 힙(Heap) 영역을 운영체제로부터 할당받는다"

이는 **사실이 아닙니다.**

---

## 실제 메모리 구조

### 프로세스 내 스레드의 메모리 레이아웃

```
프로세스 가상 주소 공간
┌─────────────────────────────┐
│         Kernel Space        │
├─────────────────────────────┤
│   Stack (Thread 1)          │ ← 스레드별 독립 영역
├─────────────────────────────┤
│   Stack (Thread 2)          │ ← 스레드별 독립 영역
├─────────────────────────────┤
│   Stack (Thread N)          │ ← 스레드별 독립 영역
├─────────────────────────────┤
│                             │
│   Heap                      │ ← 모든 스레드가 공유
│   (malloc/new)              │
│                             │
├─────────────────────────────┤
│   BSS Segment               │ ← 모든 스레드가 공유
├─────────────────────────────┤
│   Data Segment              │ ← 모든 스레드가 공유
├─────────────────────────────┤
│   Text Segment              │ ← 모든 스레드가 공유
└─────────────────────────────┘
```

### 스레드별 독립 영역 vs 공유 영역

| 메모리 영역 | 스레드 간 공유 여부 | 비고 |
|---|---|---|
| Stack | **독립** (스레드별 분리) | 지역 변수, 함수 호출 프레임, 반환 주소 |
| Heap | **공유** (프로세스 전체) | `new`, `malloc` 할당 메모리 |
| Data Segment | **공유** | 전역 변수, 정적 변수 |
| Text Segment | **공유** | 실행 코드 |
| Register Set | **독립** | PC, SP, 범용 레지스터 |
| TLS (Thread Local Storage) | **독립** | `thread_local` 키워드로 선언된 변수 |

> **핵심**: 동일 프로세스 내 모든 스레드는 **단일 힙을 공유**합니다. 힙은 스레드별로 분리되지 않으며, 이것이 바로 **Race Condition**과 **Data Race**가 발생하는 근본 원인입니다.

---

## 올바른 개념 기반 코드 작성

### 시나리오
- 공유 힙에 할당된 데이터를 두 스레드가 안전하게 교환
- **Mutex + Condition Variable**을 이용한 동기화

```cpp
#include <iostream>
#include <thread>
#include <mutex>
#include <condition_variable>
#include <queue>
#include <memory>
#include <vector>
#include <atomic>

// ============================================================
// Thread-Safe Queue: 공유 힙 영역에 대한 동기화된 접근 구조체
// ============================================================
template<typename T>
class ThreadSafeQueue {
private:
    std::queue<T>           queue_;          // 공유 힙에 위치
    mutable std::mutex      mutex_;          // Critical Section 보호
    std::condition_variable cv_not_empty_;   // 소비자 스레드 대기 조건
    std::condition_variable cv_not_full_;    // 생산자 스레드 대기 조건
    const size_t            max_size_;       // 최대 큐 크기 (Bounded Buffer)
    std::atomic<bool>       shutdown_{false};// 종료 신호

public:
    explicit ThreadSafeQueue(size_t max_size = 10)
        : max_size_(max_size) {}

    // --------------------------------------------------------
    // Enqueue: 생산자 스레드가 호출
    // - mutex_ 획득 후 큐에 데이터 삽입
    // - 큐가 가득 찬 경우 cv_not_full_에서 Block
    // --------------------------------------------------------
    bool enqueue(T item) {
        std::unique_lock<std::mutex> lock(mutex_);

        // Spurious Wakeup 방지를 위해 람다 조건 사용
        cv_not_full_.wait(lock, [this]() {
            return queue_.size() < max_size_ || shutdown_.load();
        });

        if (shutdown_.load()) return false;

        queue_.push(std::move(item));

        // 소비자 스레드의 Block 해제
        cv_not_empty_.notify_one();
        return true;
    }

    // --------------------------------------------------------
    // Dequeue: 소비자 스레드가 호출
    // - mutex_ 획득 후 큐에서 데이터 추출
    // - 큐가 비어있는 경우 cv_not_empty_에서 Block
    // --------------------------------------------------------
    bool dequeue(T& item) {
        std::unique_lock<std::mutex> lock(mutex_);

        cv_not_empty_.wait(lock, [this]() {
            return !queue_.empty() || shutdown_.load();
        });

        if (queue_.empty()) return false;

        item = std::move(queue_.front());
        queue_.pop();

        // 생산자 스레드의 Block 해제
        cv_not_full_.notify_one();
        return true;
    }

    void shutdown() {
        shutdown_.store(true);
        cv_not_empty_.notify_all();
        cv_not_full_.notify_all();
    }

    size_t size() const {
        std::lock_guard<std::mutex> lock(mutex_);
        return queue_.size();
    }
};

// ============================================================
// 데이터 구조체: 힙에 동적 할당될 페이로드
// ============================================================
struct Payload {
    int                 producer_id;
    int                 sequence_number;
    std::vector<double> data;           // 힙에 추가 할당

    Payload(int pid, int seq, std::vector<double> d)
        : producer_id(pid), sequence_number(seq), data(std::move(d)) {}
};

// ============================================================
// 생산자 스레드 함수
// - 힙에 Payload 객체 생성 후 공유 큐에 삽입
// ============================================================
void producer_thread(
    ThreadSafeQueue<std::shared_ptr<Payload>>& shared_queue,
    int producer_id,
    int item_count)
{
    for (int seq = 0; seq < item_count; ++seq) {
        // new 연산자: 공유 힙에 메모리 할당
        // shared_ptr: 소유권 이전 시 힙 메모리 수명 보장
        auto payload = std::make_shared<Payload>(
            producer_id,
            seq,
            std::vector<double>{
                static_cast<double>(seq),
                static_cast<double>(seq * 2),
                static_cast<double>(seq * 3)
            }
        );

        std::cout << "[Producer " << producer_id
                  << "] Enqueue seq=" << seq
                  << " | heap addr=" << payload.get()
                  << std::endl;

        if (!shared_queue.enqueue(std::move(payload))) {
            break; // shutdown 신호 수신
        }
    }
}

// ============================================================
// 소비자 스레드 함수
// - 공유 큐에서 Payload를 dequeue하여 처리
// ============================================================
void consumer_thread(
    ThreadSafeQueue<std::shared_ptr<Payload>>& shared_queue,
    int consumer_id,
    int expected_count,
    std::vector<std::shared_ptr<Payload>>& results,
    std::mutex& result_mutex)
{
    int received = 0;
    while (received < expected_count) {
        std::shared_ptr<Payload> payload;

        if (!shared_queue.dequeue(payload)) {
            break;
        }

        std::cout << "[Consumer " << consumer_id
                  << "] Dequeue from producer=" << payload->producer_id
                  << " seq=" << payload->sequence_number
                  << " | heap addr=" << payload.get()
                  << std::endl;

        // 결과 저장: result 벡터 자체도 공유 자원이므로 mutex 보호
        {
            std::lock_guard<std::mutex> lock(result_mutex);
            results.push_back(std::move(payload));
        }

        ++received;
    }
}

// ============================================================
// main: 스레드 생성 및 동기화 검증
// ============================================================
int main() {
    constexpr int ITEM_COUNT    = 5;
    constexpr int QUEUE_BOUND   = 3;  // Bounded Buffer 크기

    // 공유 힙에 할당되는 큐 객체
    ThreadSafeQueue<std::shared_ptr<Payload>> shared_queue(QUEUE_BOUND);

    // 소비자 결과 수집용 공유 자원
    std::vector<std::shared_ptr<Payload>> consumer_results;
    std::mutex result_mutex;

    std::cout << "=== Thread Start ===" << std::endl;

    // 스레드 생성: OS는 각 스레드에 독립적인 Stack 영역 할당
    // Heap은 여전히 프로세스 전체에서 공유됨
    std::thread producer(
        producer_thread,
        std::ref(shared_queue),
        1,
        ITEM_COUNT
    );

    std::thread consumer(
        consumer_thread,
        std::ref(shared_queue),
        1,
        ITEM_COUNT,
        std::ref(consumer_results),
        std::ref(result_mutex)
    );

    // Thread Join: 두 스레드의 실행 완료 대기
    producer.join();
    consumer.join();

    // --------------------------------------------------------
    // 검증: 수신된 데이터 무결성 확인
    // --------------------------------------------------------
    std::cout << "\n=== Verification ===" << std::endl;
    std::cout << "Total received: " << consumer_results.size() << std::endl;

    for (const auto& p : consumer_results) {
        std::cout << "  producer_id=" << p->producer_id
                  << " seq=" << p->sequence_number
                  << " data[0]=" << p->data[0]
                  << std::endl;
    }

    return 0;
}
```

