### 2. 사용자 정보 서비스 구현

```java
package com.example.security.service;

import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.userdetails.User;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.security.core.userdetails.UserDetailsService;
import org.springframework.security.core.userdetails.UsernameNotFoundException;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

import java.util.List;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

/**
 * UserDetailsService 구현체.
 * AuthenticationProvider가 인증 처리 시 이 서비스를 통해
 * UserDetails 객체를 조회한다.
 */
@Service
public class CustomUserDetailsService implements UserDetailsService {

    private final PasswordEncoder passwordEncoder;

    // 실제 운영 환경에서는 Repository를 통한 영속성 계층 조회로 대체
    private final Map<String, UserDetails> userStore = new ConcurrentHashMap<>();

    public CustomUserDetailsService(PasswordEncoder passwordEncoder) {
        this.passwordEncoder = passwordEncoder;
        initializeUsers();
    }

    /**
     * 애플리케이션 구동 시 인메모리 사용자 데이터 초기화.
     * ROLE_ADMIN: /api/admin/** 접근 권한 보유
     * ROLE_USER : 일반 인증 사용자 권한
     */
    private void initializeUsers() {
        UserDetails adminUser = User.builder()
                .username("admin")
                .password(passwordEncoder.encode("admin1234!"))
                .authorities(
                    new SimpleGrantedAuthority("ROLE_ADMIN"),
                    new SimpleGrantedAuthority("ROLE_USER")
                )
                .accountExpired(false)
                .accountLocked(false)
                .credentialsExpired(false)
                .disabled(false)
                .build();

        UserDetails normalUser = User.builder()
                .username("user")
                .password(passwordEncoder.encode("user1234!"))
                .authorities(
                    new SimpleGrantedAuthority("ROLE_USER")
                )
                .accountExpired(false)
                .accountLocked(false)
                .credentialsExpired(false)
                .disabled(false)
                .build();

        userStore.put("admin", adminUser);
        userStore.put("user", normalUser);
    }

    /**
     * @param username 클라이언트가 제출한 사용자 식별자
     * @return UserDetails - SecurityContext에 저장될 인증 주체 정보
     * @throws UsernameNotFoundException 식별자에 해당하는 레코드 부재 시
     */
    @Override
    public UserDetails loadUserByUsername(String username)
            throws UsernameNotFoundException {

        UserDetails userDetails = userStore.get(username);

        if (userDetails == null) {
            throw new UsernameNotFoundException(
                "사용자를 찾을 수 없습니다: " + username
            );
        }

        return userDetails;
    }
}
```

