### 3. 핵심 보안 설정 클래스

```java
package com.example.security.config;

import com.example.security.handler.CustomAccessDeniedHandler;
import com.example.security.handler.CustomAuthenticationEntryPoint;
import com.example.security.service.CustomUserDetailsService;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.http.HttpMethod;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.authentication.AuthenticationProvider;
import org.springframework.security.authentication.dao.DaoAuthenticationProvider;
import org.springframework.security.config.Customizer;
import org.springframework.security.config.annotation.authentication.configuration.AuthenticationConfiguration;
import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
import org.springframework.security.config.http.SessionCreationPolicy;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.access.intercept.AuthorizationFilter;

/**
 * Spring Security 6.x 표준 설정 클래스.
 *
 * WebSecurityConfigurerAdapter 제거에 따라
 * SecurityFilterChain을 Bean으로 직접 등록하는 컴포넌트 기반 설정 방식 적용.
 *
 * @EnableWebSecurity   : WebSecurityConfiguration, SpringWebMvcImportSelector,
 *                        OAuth2ImportSelector, HttpSecurityConfiguration 등을
 *                        자동 임포트하여 Spring Security 인프라를 활성화.
 * @EnableMethodSecurity: @PreAuthorize, @PostAuthorize 등 메서드 수준
 *                        인가 애노테이션 활성화 (prePostEnabled 기본값 true).
 */
@Configuration
@EnableWebSecurity
@EnableMethodSecurity(
    prePostEnabled = true,   // @PreAuthorize, @PostAuthorize 활성화
    securedEnabled = true,   // @Secured 활성화
    jsr250Enabled = true     // @RolesAllowed 활성화
)
public class SecurityConfig {

    private final CustomUserDetailsService userDetailsService;
    private final CustomAuthenticationEntryPoint authenticationEntryPoint;
    private final CustomAccessDeniedHandler accessDeniedHandler;

    public SecurityConfig(
            CustomUserDetailsService userDetailsService,
            CustomAuthenticationEntryPoint authenticationEntryPoint,
            CustomAccessDeniedHandler accessDeniedHandler) {
        this.userDetailsService = userDetailsService;
        this.authenticationEntryPoint = authenticationEntryPoint;
        this.accessDeniedHandler = accessDeniedHandler;
    }

    /**
     * BCryptPasswordEncoder Bean 등록.
     *
     * BCrypt: 적응형 단방향 해시 함수.
     * strength(cost factor) 기본값 10 → 2^10 = 1024회 반복 연산.
     * 무차별 대입 공격(Brute Force Attack) 및
     * 레인보우 테이블 공격(Rainbow Table Attack)에 대한 저항성 확보.
     */
    @Bean
    public PasswordEncoder passwordEncoder() {
        return new BCryptPasswordEncoder(12); // cost factor 12 적용
    }

    /**
     * DaoAuthenticationProvider Bean 등록.
     *
     * AuthenticationProvider 구현체로서,
     * UsernamePasswordAuthenticationToken을 처리하는 책임을 가진다.
     * UserDetailsService를 통해 UserDetails를 로드하고,
     * PasswordEncoder를 통해 자격증명(Credential) 검증을 수행한다.
     */
    @Bean
    public AuthenticationProvider authenticationProvider() {
        DaoAuthenticationProvider provider = new DaoAuthenticationProvider();
        provider.setUserDetailsService(userDetailsService);
        provider.setPasswordEncoder(passwordEncoder());

        // 사용자 미존재 시 UsernameNotFoundException 노출 여부 설정
        // true: BadCredentialsException으로 래핑하지 않고 원본 예외 전파
        provider.setHideUserNotFoundExceptions(false);

        return provider;
    }

    /**
     * AuthenticationManager Bean 등록.
     *
     * AuthenticationConfiguration으로부터 AuthenticationManager를 획득.
     * 복수의 AuthenticationProvider를 순회하며 인증 처리를 위임하는
     * ProviderManager 인스턴스가 반환된다.
     */
    @Bean
    public AuthenticationManager authenticationManager(
            AuthenticationConfiguration config) throws Exception {
        return config.getAuthenticationManager();
    }

    /**
     * SecurityFilterChain Bean 등록 - 핵심 보안 정책 정의.
     *
     * HttpSecurity 객체를 통해 필터 체인에 포함될 각 보안 모듈을 구성한다.
     * 최종적으로 build() 호출 시 DefaultSecurityFilterChain 인스턴스가 생성된다.
     *
     * @param http HttpSecurity - 보안 필터 체인 구성을 위한 빌더 객체
     * @return SecurityFilterChain - 구성된 필터 체인 인스턴스
     */
    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http)
            throws Exception {

        http
            /*
             * CSRF(Cross-Site Request Forgery) 보호 비활성화.
             *
             * REST API + HTTP Basic 인증 구조에서는
             * 세션 쿠키 기반 상태 유지가 없으므로 CSRF 공격 벡터가 성립하지 않는다.
             * Stateless 아키텍처에서 CSRF 토큰 검증은 불필요한 오버헤드이다.
             */
            .csrf(AbstractHttpConfigurer::disable)

            /*
             * 세션 관리 정책: STATELESS.
             *
             * SessionCreationPolicy.STATELESS:
             * SecurityContext를 HttpSession에 저장하지 않으며,
             * 요청마다 SecurityContext를 새로 생성하고 소멸시킨다.
             * HTTP Basic 인증은 매 요청마다 Authorization 헤더를 전송하므로
             * 세션 기반 상태 유지가 불필요하다.
             */
            .sessionManagement(session ->
                session.sessionCreationPolicy(SessionCreationPolicy.STATELESS)
            )

            /*
             * HTTP Basic 인증 활성화.
             *
             * BasicAuthenticationFilter가 필터 체인에 등록된다.
             * 클라이언트는 각 요청의 Authorization 헤더에
             * "Basic Base64(username:password)" 형식의 자격증명을 포함해야 한다.
             *
             * Customizer.withDefaults(): 기본 설정 적용
             * (realm name: "Realm")
             */
            .httpBasic(Customizer.withDefaults())

            /*
             * 인가(Authorization) 규칙 정의.
             *
             * requestMatchers의 평가 순서는 선언 순서를 따르며,
             * 첫 번째로 매칭되는 규칙이 적용된다 (First-Match Wins).
             */
            .authorizeHttpRequests(authz -> authz

                // 공개 엔드포인트: 인증 없이 접근 허용
                .requestMatchers(
                    "/api/public/**",
                    "/actuator/health",
                    "/actuator/info"
                ).permitAll()

                // HTTP OPTIONS 메서드: CORS Preflight 요청 허용
                .requestMatchers(HttpMethod.OPTIONS, "/**").permitAll()

                // 관리자 전용 엔드포인트: ROLE_ADMIN 권한 보유자만 접근 허용
                // hasRole("ADMIN") 내부적으로 "ROLE_ADMIN" GrantedAuthority와 비교
                .requestMatchers("/api/admin/**").hasRole("ADMIN")

                // 인증된 사용자 접근 엔드포인트
                .requestMatchers("/api/user/**").hasAnyRole("USER", "ADMIN")

                // 읽기 전용 엔드포인트: GET 메서드는 USER 이상 허용
                .requestMatchers(HttpMethod.GET, "/api/resources/**")
                    .hasAnyRole("USER", "ADMIN")

                // 쓰기 엔드포인트: ADMIN만 허용
                .requestMatchers(
                    HttpMethod.POST,
                    HttpMethod.PUT,
                    HttpMethod.DELETE
                    // varargs 미지원으로 개별 등록
                )
                // 아래와 같이 표현식(SpEL) 기반 접근 제어도 가능
                // .access(new WebExpressionAuthorizationManager("hasRole('ADMIN')"))

                // 위 규칙에 매칭되지 않는 모든 요청: 인증 필수
                .anyRequest().authenticated()
            )

            /*
             * 예외 처리 핸들러 등록.
             *
             * AuthenticationEntryPoint:
             *   미인증(Unauthenticated) 요청 접근 시 호출.
             *   ExceptionTranslationFilter가 AuthenticationException을 포착하여 위임.
             *
             * AccessDeniedHandler:
             *   인증은 완료되었으나 인가(Authorization) 실패 시 호출.
             *   ExceptionTranslationFilter가 AccessDeniedException을 포착하여 위임.
             */
            .exceptionHandling(exception -> exception
                .authenticationEntryPoint(authenticationEntryPoint)
                .accessDeniedHandler(accessDeniedHandler)
            )

            // 커스텀 AuthenticationProvider 등록
            .authenticationProvider(authenticationProvider());

        return http.build();
    }
}
```

