```java
import java.util.*;

public class PerformanceBenchmark {

    private static final int DATA_SIZE = 10_000_000;
    private static final int WARMUP_ITERATIONS = 3;
    private static final int TEST_ITERATIONS = 5;

    public static void main(String[] args) {
        benchmarkStrategies();
    }

    public static void benchmarkStrategies() {
        System.out.println("=== ArrayList 대규모 삽입 성능 비교 ===\n");

        // 전략 1: 사전 할당 (최적)
        long time1 = measurePerformance(() -> {
            ArrayList<Integer> list = new ArrayList<>(DATA_SIZE);
            for (int i = 0; i < DATA_SIZE; i++) {
                list.add(i);
            }
        });
        System.out.printf("전략 1 (사전 할당): %d ms%n", time1);

        // 전략 2: 기본 삽입 (비최적)
        long time2 = measurePerformance(() -> {
            ArrayList<Integer> list = new ArrayList<>();
            for (int i = 0; i < DATA_SIZE; i++) {
                list.add(i);
            }
        });
        System.out.printf("전략 2 (기본 삽입): %d ms%n", time2);

        // 전략 3: 배치 삽입
        long time3 = measurePerformance(() -> {
            ArrayList<Integer> list = new ArrayList<>();
            List<Integer> batch = new ArrayList<>(1000);
            for (int i = 0; i < DATA_SIZE; i++) {
                batch.add(i);
                if (batch.size() == 1000) {
                    list.addAll(batch);
                    batch.clear();
                }
            }
