## 3. 성능 최적화 구현

### 3.1 사전 용량 지정 (Pre-sizing)

```java
import java.util.ArrayList;
import java.util.List;

public class PreSizedArrayList {

    /**
     * 삽입할 데이터 크기를 사전에 알고 있는 경우
     * initialCapacity를 명시하여 grow() 호출 횟수를 0으로 감소
     */
    public static List<Integer> insertWithKnownSize(int targetSize) {
        // 생성자에서 elementData = new Object[initialCapacity] 단 1회 할당
        ArrayList<Integer> list = new ArrayList<>(targetSize);

        for (int i = 0; i < targetSize; i++) {
            list.add(i); // 용량 초과 없음 → grow() 미호출
        }

        return list;
    }

    public static void main(String[] args) {
        int targetSize = 10_000_000;

        // 비교 벤치마크
        long t1 = System.nanoTime();
        List<Integer> naive = new ArrayList<>();
        for (int i = 0; i < targetSize; i++) naive.add(i);
        long t2 = System.nanoTime();

        List<Integer> presized = insertWithKnownSize(targetSize);
        long t3 = System.nanoTime();

        System.out.printf("Default capacity : %.2f ms%n", (t2 - t1) / 1e6);
        System.out.printf("Pre-sized        : %.2f ms%n", (t3 - t2) / 1e6);
    }
}
```

### 3.2 ensureCapacity()를 활용한 배치 사전 확장

```java
import java.util.ArrayList;
import java.util.List;

public class EnsureCapacityDemo {

    /**
     * 데이터를 배치(Batch) 단위로 삽입하되,
     * 각 배치 시작 전 ensureCapacity()로 단일 grow() 호출을 보장
     */
    public static List<Integer> batchInsertWithEnsure(int totalSize, int batchSize) {
        ArrayList<Integer> list = new ArrayList<>();

        for (int batchStart = 0; batchStart < totalSize; batchStart += batchSize) {
            int batchEnd = Math.min(batchStart + batchSize, totalSize);

            // 현재 배치 삽입에 필요한 최소 용량을 사전 확보
            // 내부적으로: if (minCapacity > elementData.length) grow(minCapacity)
            list.ensureCapacity(batchEnd);

            for (int i = batchStart; i < batchEnd; i++) {
                list.add(i);
            }
        }

        return list;
    }
}
```

### 3.3 addAll()을 이용한 벌크 삽입 최적화

```java
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collection;
import java.util.List;

public class BulkInsertOptimization {

    /**
     * addAll(Collection c)의 내부 구현:
     * 1. c.toArray()로 소스 배열 획득
     * 2. 필요 시 단 1회 grow() 호출
     * 3. System.arraycopy()로 블록 복사 (단일 native 호출)
     *
     * 루프 기반 add()와 달리 arraycopy의 캐시 지역성(Cache Locality) 이점 활용
     */
    public static List<Integer> bulkInsert(Integer[] sourceData) {
        ArrayList<Integer> list = new ArrayList<>(sourceData.length);

        // 단일 System.arraycopy 호출로 전체 복사
        // JIT 컴파일러가 SIMD 벡터화 최적화 적용 가능
        list.addAll(Arrays.asList(sourceData));

        return list;
    }

    /**
     * 스트림 기반 대규모 데이터 생성 후 수집
     * Collectors.toList()는 내부적으로 ArrayList를 사용하며
     * 스트림 파이프라인의 병렬화(Parallelism) 적용 가능
     */
    public static List<Integer> parallelStreamInsert(int totalSize) {
        return java.util.stream.IntStream
            .range(0, totalSize)
            .parallel()                          // Fork/Join Pool 활용
            .boxed()
            .collect(java.util.stream.Collectors.toList());
    }
}
```

### 3.4 종합 벤치마크 코드

```java
import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;
import java.util.stream.Collectors;
import java.util.stream.IntStream;

public class ArrayListBenchmark {

    private static final int TARGET_SIZE = 10_000_000;
    private static final int WARMUP_ROUNDS = 3;
    private static final int MEASURE_ROUNDS = 5;

    public static void main(String[] args) {
        System.out.println("=== ArrayList 삽입 성능 벤치마크 ===");
        System.out.printf("대상 원소 수: %,d%n%n", TARGET_SIZE);

        // JIT 웜업 (JIT Compiler의 프로파일링 기반 최적화 안정화)
        for (int i = 0; i < WARMUP_ROUNDS; i++) {
            runAllStrategies();
        }

        // 실측
        double[] results = new double[4];
        for (int round = 0; round < MEASURE_ROUNDS; round++) {
            double[] r = runAllStrategies();
            for (int i = 0; i < r.length; i++) results[i] += r[i];
        }

        String[] labels = {
            "1. 기본 (초기 용량 10)",
            "2. 사전 용량 지정",
            "3. ensureCapacity 배치",
            "4. addAll 벌크 삽입"
        };

        System.out.println("--- 평균 실행 시간 (ms) ---");
        for (int i = 0; i < labels.length; i++) {
            System.out.printf("%-25s : %7.2f ms%n",
                labels[i], results[i] / MEASURE_ROUNDS);
        }
    }

    private static double[] runAllStrategies() {
        double[] times = new double[4];

        // 전략 1: 기본 삽입 (grow() 다중 호출)
        times[0] = measure(() -> {
            ArrayList<Integer> list = new ArrayList<>();
            for (int i = 0; i < TARGET_SIZE; i++) list.add(i);
        });

        // 전략 2: 사전 용량 지정 (grow() 0회)
        times[1] = measure(() -> {
            ArrayList<Integer> list = new ArrayList<>(TARGET_SIZE);
            for (int i = 0; i < TARGET_SIZE; i++) list.add(i);
        });

        // 전략 3: ensureCapacity 배치 삽입
        times[2] = measure(() -> {
            int batchSize = 100_000;
            ArrayList<Integer> list = new ArrayList<>();
            for (int s = 0; s < TARGET_SIZE; s += batchSize) {
                int end = Math.min(s + batchSize, TARGET_SIZE);
                list.ensureCapacity(end);
                for (int i = s; i < end; i++) list.add(i);
            }
        });

        // 전략 4: addAll 벌크 삽입 (단일 arraycopy)
        times[3] = measure(() -> {
            Integer[] src = new Integer[TARGET_SIZE];
            Arrays.fill(src, 42); // 데이터 초기화 시간 포함
            ArrayList<Integer> list = new ArrayList<>(TARGET_SIZE);
            list.addAll(Arrays.asList(src));
        });

        return times;
    }

    @FunctionalInterface
    interface Task { void run(); }

    private static double measure(Task task) {
        // GC 영향 최소화를 위한 명시적 GC 요청
        System.gc();
        long start = System.nanoTime();
        task.run();
        return (System.nanoTime() - start) / 1_000_000.0;
    }
}
```

