## 2. 대규모 데이터 삽입의 성능 최적화 전략

### 2.1 사전 용량 할당 (Capacity Pre-allocation)

```java
public class OptimizedInsertionStrategy {

    // 최적화되지 않은 방식: O(N) 시간복잡도 (평균)
    public static long naiveInsertion(int dataSize) {
        ArrayList<Integer> list = new ArrayList<>();
        long startTime = System.nanoTime();

        for (int i = 0; i < dataSize; i++) {
            list.add(i); // 용량 초과 시마다 재할당 발생
        }

        return System.nanoTime() - startTime;
    }

    // 최적화된 방식: O(N) 시간복잡도 (선형)
    public static long optimizedInsertion(int dataSize) {
        ArrayList<Integer> list = new ArrayList<>(dataSize);
        long startTime = System.nanoTime();

        for (int i = 0; i < dataSize; i++) {
            list.add(i); // 재할당 없음
        }

        return System.nanoTime() - startTime;
    }

    public static void main(String[] args) {
        int[] testSizes = {1_000_000, 5_000_000, 10_000_000};

        for (int size : testSizes) {
            long naiveTime = naiveInsertion(size);
            long optimizedTime = optimizedInsertion(size);

            System.out.printf("데이터 크기: %,d%n", size);
            System.out.printf("최적화 전: %,d ns%n", naiveTime);
            System.out.printf("최적화 후: %,d ns%n", optimizedTime);
            System.out.printf("성능 개선: %.2f배%n%n", 
                (double) naiveTime / optimizedTime);
        }
    }
}
```

