### 2.2 배치 삽입 및 메모리 지역성(Locality) 활용

```java
public class BatchInsertionOptimization {

    /**
     * 캐시 친화적 배치 삽입
     * - CPU 캐시 라인 활용 극대화
     * - 메모리 접근 패턴 최적화
     */
    public static long batchInsertionWithLocalityOptimization(
            int dataSize, 
            int batchSize) {

        ArrayList<Integer> list = new ArrayList<>(dataSize);
        long startTime = System.nanoTime();

        int[] buffer = new int[batchSize];

        for (int batch = 0; batch < dataSize; batch += batchSize) {
            int currentBatchSize = Math.min(batchSize, dataSize - batch);

            // 배치 데이터 준비 (메모리 지역성 향상)
            for (int i = 0; i < currentBatchSize; i++) {
                buffer[i] = batch + i;
            }

            // 배치 삽입
            for (int i = 0; i < currentBatchSize; i++) {
                list.add(buffer[i]);
            }
        }

        return System.nanoTime() - startTime;
    }

    /**
     * 병렬 스트림을 활용한 대규모 데이터 생성 및 수집
     */
    public static long parallelStreamInsertion(int dataSize) {
        long startTime = System.nanoTime();

        ArrayList<Integer> list = IntStream.range(0, dataSize)
                .parallel()
                .boxed()
                .collect(Collectors.toCollection(
                    () -> new ArrayList<>(dataSize)
                ));

        return System.nanoTime() - startTime;
    }
}
```

