### 2.3 메모리 재할당 오버헤드 분석

```java
public class ReallocationOverheadAnalysis {

    /**
     * 기하급수적 확장의 상환 분석(Amortized Analysis)
     */
    public static void demonstrateAmortizedComplexity() {
        System.out.println("=== 상환 시간 복잡도 분석 ===\n");

        ArrayList<Integer> list = new ArrayList<>();
        long totalCopyOperations = 0;

        for (int i = 1; i <= 1_000_000; i++) {
            list.add(i);

            // 재할당이 발생하는 순간 추적
            if ((i & (i - 1)) == 0 && i > 0) { // i가 2의 거듭제곱
                totalCopyOperations += i / 2;
                System.out.printf("크기 %,d 도달 시 누적 복사 연산: %,d%n", 
                    i, totalCopyOperations);
            }
        }

        System.out.printf("\n최종 누적 복사 연산: %,d%n", totalCopyOperations);
        System.out.printf("요소당 평균 복사: %.2f회%n", 
            (double) totalCopyOperations / 1_000_000);
        System.out.println("\n결론: O(1) 상환 시간복잡도");
    }

    /**
     * 메모리 단편화 분석
     */
    public static void analyzeMemoryFragmentation() {
        System.out.println("\n=== 메모리 단편화 분석 ===\n");

        ArrayList<Integer> list = new ArrayList<>(10_000_000);

        for (int i = 0; i < 10_000_000; i++) {
            list.add(i);
        }

        Runtime runtime = Runtime.getRuntime();
        long usedMemory = runtime.totalMemory() - runtime.freeMemory();

        System.out.printf("할당된 메모리: %,d bytes%n", 
            list.size() * Integer.BYTES);
        System.out.printf("실제 사용 메모리: %,d bytes%n", usedMemory);
        System.out.printf("메모리 오버헤드: %.2f%%%n", 
            ((double)(usedMemory - list.size() * Integer.BYTES) 
             / usedMemory) * 100);
    }
}
```

