}

class MemoryPressureMonitor {
    private static final double CRITICAL_THRESHOLD = 0.95;
    private static final double HIGH_THRESHOLD = 0.80;
    private static final double MODERATE_THRESHOLD = 0.60;

    public MemoryPressureLevel evaluatePressure() {
        Runtime runtime = Runtime.getRuntime();
        long max = runtime.maxMemory();
        long used = runtime.totalMemory() - runtime.freeMemory();
        double utilization = (double) used / max;

        if (utilization >= CRITICAL_THRESHOLD) {
            return MemoryPressureLevel.CRITICAL;
        } else if (utilization >= HIGH_THRESHOLD) {
            return MemoryPressureLevel.HIGH;
        } else if (utilization >= MODERATE_THRESHOLD) {
            return MemoryPressureLevel.MODERATE;
        } else {
            return MemoryPressureLevel.LOW;
        }
    }

    public double getCurrentUtilization() {
        Runtime runtime = Runtime.getRuntime();
        long max = runtime.maxMemory();
        long used = runtime.totalMemory() - runtime.freeMemory();
        return (double) used / max;
    }
}
