## 3. 핵심 구현 코드

### 3.1 ATE 코어 엔진

```java
package com.ate.core;

import sun.misc.Unsafe;
import java.lang.ref.PhantomReference;
import java.lang.ref.ReferenceQueue;
import java.lang.reflect.Field;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicLong;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.atomic.AtomicReferenceArray;

/**
 * Asynchronous Type Erasure Engine
 * 
 * GC의 Concurrent Marking Phase와 연동하여
 * 제네릭 인스턴스의 불필요한 타입 메타데이터를
 * 비동기적으로 소거하는 런타임 최적화 엔진.
 */
public final class ATEEngine {

    private static final Unsafe UNSAFE;
    private static final long OBJECT_HEADER_SIZE;
    private static final long MARK_WORD_OFFSET = 0L;
    private static final long KLASS_POINTER_OFFSET;

    // ATE 전용 비트 플래그: Mark Word의 unused bit 활용
    private static final long ATE_ELIGIBLE_BIT = 1L << 58;
    private static final long ATE_PROCESSED_BIT = 1L << 57;

    static {
        try {
            Field f = Unsafe.class.getDeclaredField("theUnsafe");
            f.setAccessible(true);
            UNSAFE = (Unsafe) f.get(null);

            // Compressed Oops 활성 여부에 따른 오프셋 결정
            boolean compressedOops = isCompressedOopsEnabled();
            KLASS_POINTER_OFFSET = compressedOops ? 4L : 8L;
            OBJECT_HEADER_SIZE = compressedOops ? 12L : 16L;
        } catch (Exception e) {
            throw new ExceptionInInitializerError(e);
        }
    }

    private final ErasureQueue erasureQueue;
    private final ATEDaemonThread daemonThread;
    private final MetadataStripper stripper;
    private final GCSafepointCoordinator safepointCoordinator;
    private final ATEStatistics statistics;

    private volatile boolean active = false;

    private static final ATEEngine INSTANCE = new ATEEngine();

    public static ATEEngine getInstance() {
        return INSTANCE;
    }

    private ATEEngine() {
        this.erasureQueue = new ErasureQueue(1 << 16); // 65536 slots
        this.stripper = new MetadataStripper();
        this.safepointCoordinator = new GCSafepointCoordinator();
        this.statistics = new ATEStatistics();
        this.daemonThread = new ATEDaemonThread();
    }

    public void activate() {
        if (!active) {
            active = true;
            daemonThread.start();
        }
    }

    public void deactivate() {
        active = false;
        daemonThread.interrupt();
    }

    /**
     * 제네릭 인스턴스를 ATE 대상으로 등록.
     * Object Header의 Mark Word에 ATE_ELIGIBLE_BIT를 CAS로 설정.
     */
    public <T> void registerForErasure(Object genericInstance, Class<T> typeToken) {
        if (!active || genericInstance == null) return;

        long markWord = UNSAFE.getLong(genericInstance, MARK_WORD_OFFSET);

        // 이미 처리되었거나 등록된 경우 스킵
        if ((markWord & ATE_ELIGIBLE_BIT) != 0 || (markWord & ATE_PROCESSED_BIT) != 0) {
            return;
        }

        // CAS를 통한 lock-free 등록
        long newMarkWord = markWord | ATE_ELIGIBLE_BIT;
        if (UNSAFE.compareAndSwapLong(genericInstance, MARK_WORD_OFFSET, markWord, newMarkWord)) {
            ErasureTask task = new ErasureTask(genericInstance, typeToken, System.nanoTime());
            erasureQueue.enqueue(task);
            statistics.incrementRegistered();
        }
    }

    /**
     * Bulk registration - 컬렉션 내부 요소 일괄 등록
     */
    public <T> void registerBulk(Object[] instances, Class<T> typeToken) {
        for (Object instance : instances) {
            if (instance != null) {
                registerForErasure(instance, typeToken);
            }
        }
    }

    private static boolean isCompressedOopsEnabled() {
        // -XX:+UseCompressedOops 여부 판정
        try {
            String value = System.getProperty("java.vm.compressedOopsMode");
            return value != null || Runtime.getRuntime().maxMemory() < 32L * 1024 * 1024 * 1024;
        } catch (Exception e) {
            return true; // 기본값: 활성
        }
    }

    // 내부 통계 접근
    public ATEStatistics getStatistics() {
        return statistics;
    }

    // ─────────────────────────────────────────────────────────────
    // Inner Classes
    // ─────────────────────────────────────────────────────────────

    /**
     * Lock-free MPSC (Multiple Producer Single Consumer) Queue
     * Application Thread(Producer) → ATE Daemon(Consumer)
     */
    static final class ErasureQueue {
        private final AtomicReferenceArray<ErasureTask> buffer;
        private final int capacity;
        private final int mask;
        private final AtomicLong producerIndex = new AtomicLong(0);
        private long consumerIndex = 0; // single consumer이므로 volatile 불필요

        ErasureQueue(int capacity) {
            // capacity는 2의 거듭제곱이어야 함
            this.capacity = Integer.highestOneBit(capacity - 1) << 1;
            this.mask = this.capacity - 1;
            this.buffer = new AtomicReferenceArray<>(this.capacity);
        }

        boolean enqueue(ErasureTask task) {
            long idx = producerIndex.getAndIncrement();
            int slot = (int) (idx & mask);

            // Slot이 비어있을 때까지 spin (backpressure)
            int spinCount = 0;
            while (buffer.get(slot) != null) {
                if (++spinCount > 1000) {
                    Thread.yield();
                    spinCount = 0;
                }
            }
            buffer.set(slot, task);
            return true;
        }

        ErasureTask dequeue() {
            int slot = (int) (consumerIndex & mask);
            ErasureTask task = buffer.get(slot);
            if (task != null) {
                buffer.set(slot, null);
                consumerIndex++;
            }
            return task;
        }

        int approximateSize() {
            return (int) (producerIndex.get() - consumerIndex);
        }
    }

    /**
     * 소거 작업 단위
     */
    static final class ErasureTask {
        final Object target;
        final Class<?> originalTypeToken;
        final long registrationTimeNanos;

        // Weak reference semantics: GC가 수거하면 소거 불필요
        volatile boolean cancelled = false;

        ErasureTask(Object target, Class<?> originalTypeToken, long registrationTimeNanos) {
            this.target = target;
            this.originalTypeToken = originalTypeToken;
            this.registrationTimeNanos = registrationTimeNanos;
        }
    }

    /**
     * ATE Daemon Thread
     * GC의 Concurrent Phase와 동기화하여 비동기 소거 수행.
     */
    final class ATEDaemonThread extends Thread {

        private static final long BATCH_PROCESS_THRESHOLD = 64;
        private static final long IDLE_PARK_NANOS = 1_000_000L; // 1ms

        ATEDaemonThread() {
            super("ATE-Daemon");
            setDaemon(true);
            setPriority(Thread.MIN_PRIORITY + 1); // GC thread보다 낮은 우선순위
        }

        @Override
        public void run() {
            while (active && !isInterrupted()) {
                try {
                    int processed = processBatch();

                    if (processed == 0) {
                        // 작업 없으면 park하여 CPU 절약
                        LockSupport.parkNanos(IDLE_PARK_NANOS);
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    break;
                } catch (Exception e) {
                    // 안정성: 예외 발생 시에도 daemon 유지
                    statistics.incrementErrors();
                }
            }
        }

        private int processBatch() throws InterruptedException {
            int count = 0;

            while (count < BATCH_PROCESS_THRESHOLD) {
                ErasureTask task = erasureQueue.dequeue();
                if (task == null) break;

                if (task.cancelled) {
                    count++;
                    continue;
                }

                // GC Safepoint 확인: Concurrent Phase에서만 소거 수행
                if (safepointCoordinator.isInConcurrentPhase()) {
                    processErasure(task);
                    count++;
                    statistics.incrementProcessed();
                } else {
                    // Safepoint 대기: STW 구간에서는 작업 보류
                    safepointCoordinator.waitForConcurrentPhase();
                    processErasure(task);
                    count++;
                    statistics.incrementProcessed();
                }
            }

            return count;
        }

        private void processErasure(ErasureTask task) {
            Object target = task.target;

            // 1단계: 대상 객체의 도달 가능성(Reachability) 검증
            if (!isReachable(target)) {
                task.cancelled = true;
                return;
            }

            // 2단계: Mark Word에서 ATE_ELIGIBLE 해제, ATE_PROCESSED 설정
            long markWord = UNSAFE.getLong(target, MARK_WORD_OFFSET);
            long newMarkWord = (markWord & ~ATE_ELIGIBLE_BIT) | ATE_PROCESSED_BIT;

            if (!UNSAFE.compareAndSwapLong(target, MARK_WORD_OFFSET, markWord, newMarkWord)) {
                // CAS 실패: GC가 Mark Word를 변경함 (forwarding pointer 등)
                // 재시도하지 않고 포기 (GC 우선)
                statistics.incrementCASFailures();
                return;
            }

            // 3단계: 메타데이터 스트리핑
            stripper.stripTypeMetadata(target, task.originalTypeToken);

            // 4단계: 힙 절약량 기록
            long saved = stripper.calculateSavedBytes(task.originalTypeToken);
            statistics.addBytesSaved(saved);
        }

        private boolean isReachable(Object obj) {
            // Mark Word의 GC bits 검사로 도달 가능성 근사 판정
            long markWord = UNSAFE.getLong(obj, MARK_WORD_OFFSET);
            // Biased locking pattern이나 forwarded 상태가 아닌지 확인
            long lockBits = markWord & 0x07L;
            return lockBits != 0x06L; // 0x06 = forwarded (이미 이동됨)
        }
    }

    /**
     * 메타데이터 스트리퍼
     * 객체 내부의 불필요한 타입 정보 필드를 null화하거나
     * 인라인 메타데이터를 제거.
     */
