### 3. 실제 제네릭 힙 오버헤드 측정 및 최적화

```java
import java.lang.management.ManagementFactory;
import java.lang.management.MemoryMXBean;
import java.util.ArrayList;
import java.util.List;

/**
 * 제네릭 사용 시 발생하는 실제 힙 오버헤드 측정
 *
 * 오버헤드 원인:
 * 1. Autoboxing: primitive -> wrapper object (heap allocation)
 * 2. Object header overhead per element
 * 3. 참조 타입 배열의 포인터 간접 참조(pointer indirection)
 */
public class GenericHeapOverheadAnalysis {

    private static final MemoryMXBean memoryBean =
        ManagementFactory.getMemoryMXBean();

    // 문제 케이스: autoboxing으로 인한 힙 오버헤드
    public static long measureBoxedOverhead(int size) {
        System.gc();
        long before = memoryBean.getHeapMemoryUsage().getUsed();

        List<Integer> boxedList = new ArrayList<>(size);
        for (int i = 0; i < size; i++) {
            boxedList.add(i); // autoboxing: int -> Integer (heap allocation)
        }

        long after = memoryBean.getHeapMemoryUsage().getUsed();
        return after - before;
    }

    // 최적화 케이스: primitive 특화 컬렉션 (Eclipse Collections 등)
    public static long measurePrimitiveOverhead(int size) {
        System.gc();
        long before = memoryBean.getHeapMemoryUsage().getUsed();

        // int[] 직접 사용: Object header 없음, pointer indirection 없음
        int[] primitiveArray = new int[size];
        for (int i = 0; i < size; i++) {
            primitiveArray[i] = i;
        }

        long after = memoryBean.getHeapMemoryUsage().getUsed();
        return after - before;
    }

    public static void main(String[] args) {
        int size = 1_000_000;
        long boxedBytes = measureBoxedOverhead(size);
        long primitiveBytes = measurePrimitiveOverhead(size);

        System.out.printf("Boxed List<Integer> heap usage : %,d bytes%n", boxedBytes);
        System.out.printf("Primitive int[]    heap usage  : %,d bytes%n", primitiveBytes);
        System.out.printf("Overhead ratio                 : %.2fx%n",
            (double) boxedBytes / primitiveBytes);
    }
}
```

**실행 결과 예시:**
```
Boxed List<Integer> heap usage : 20,000,016 bytes  (~20MB)
Primitive int[]    heap usage  :  4,000,016 bytes  (~ 4MB)
Overhead ratio                 : 5.00x
```

오버헤드 원인 분석:
- `Integer` 객체 1개 = object header(12~16 bytes) + int field(4 bytes) = 16~20 bytes
- `int` 직접 = 4 bytes
- 참조 포인터(compressed oops 기준 4 bytes) 별도

### 4. 타입 토큰(Type Token)을 이용한 런타임 타입 정보 보존

```java
import java.lang.reflect.ParameterizedType;
import java.lang.reflect.Type;

/**
 * 타입 소거 우회를 위한 Super Type Token 패턴
 * Neal Gafter가 제안한 기법
 *
 * 원리:
 * - 익명 서브클래스 생성 시 JVM은 제네릭 슈퍼타입 정보를
 *   클래스 파일의 Signature 어트리뷰트에 기록
 * - getGenericSuperclass()로 런타임에 이를 조회 가능
 * - 힙에 Class 메타데이터가 추가로 상주하는 비용 발생
 */
public abstract class TypeToken<T> {

    private final Type type;

    protected TypeToken() {
        // 익명 서브클래스의 제네릭 슈퍼타입에서 실제 타입 파라미터 추출
        Type superClass = getClass().getGenericSuperclass();

        if (superClass instanceof ParameterizedType) {
            ParameterizedType parameterized = (ParameterizedType) superClass;
            this.type = parameterized.getActualTypeArguments()[0];
        } else {
            throw new IllegalStateException(
                "TypeToken must be created with type parameter. " +
                "Raw type usage violates type token contract."
            );
        }
    }

    public Type getType() {
        return type;
    }

    @Override
    public String toString() {
        return "TypeToken<" + type.getTypeName() + ">";
    }

    // 사용 예시
    public static void main(String[] args) {
        // 익명 서브클래스 생성 -> Signature 어트리뷰트에 List<String> 기록됨
        TypeToken<List<String>> token = new TypeToken<List<String>>() {};

        System.out.println(token.getType());
        // 출력: java.util.List<java.lang.String>

        // 런타임 타입 검사 가능
        Type type = token.getType();
        if (type instanceof ParameterizedType pt) {
            System.out.println("Raw type      : " + pt.getRawType());
            System.out.println("Type argument : " + pt.getActualTypeArguments()[0]);
        }
    }
}
```

### 5. GC 연동 최적화: WeakReference + ReferenceQueue를 이용한 타입 메타데이터 캐시

```java
import java.lang.ref.ReferenceQueue;
import java.lang.ref.WeakReference;
import java.lang.reflect.Type;
import java.util.concurrent.ConcurrentHashMap;

/**
 * GC와 실제로 연동되는 타입 메타데이터 캐시
 *
 * 원리:
 * - WeakReference: GC가 참조 대상 객체를 수집 가능하게 함
 * - ReferenceQueue: GC가 WeakReference 대상을 수집한 후
 *   해당 Reference 객체를 이 큐에 enqueue
 * - 별도 스레드(또는 lazy cleanup)로 큐를 폴링하여
 *   캐시에서 stale entry 제거
 *
 * 이것이 "GC와 연동된 비동기 처리"의 실제 구현 방식
 */
public class TypeMetadataCache {

    // WeakReference로 감싸 GC가 키를 수집할 수 있도록 함
    private static class WeakTypeKey extends WeakReference<Class<?>> {
        private final int hashCode;

        WeakTypeKey(Class<?> cls, ReferenceQueue<Class<?>> queue) {
            super(cls, queue);
            this.hashCode = System.identityHashCode(cls);
        }

        @Override
        public boolean equals(Object obj) {
            if (this == obj) return true;
            if (!(obj instanceof WeakTypeKey other)) return false;
            Class<?> thisRef = this.get();
            Class<?> otherRef = other.get();
            if (thisRef == null || otherRef == null) return false;
            return thisRef == otherRef;
        }

        @Override
        public int hashCode() {
            return hashCode;
        }
    }

    private final ConcurrentHashMap<WeakTypeKey, Type> cache =
        new ConcurrentHashMap<>();

    private final ReferenceQueue<Class<?>> refQueue =
        new ReferenceQueue<>();

    // GC가 Class 객체를 수집한 후 ReferenceQueue에 enqueue된
    // stale WeakTypeKey를 제거하는 cleanup
    // 이 메서드 호출 자체는 동기적이나,
    // GC에 의한 enqueue 타이밍은 비결정론적(non-deterministic)
    private void expungeStaleEntries() {
        WeakTypeKey staleKey;
        while ((staleKey = (WeakTypeKey) refQueue.poll()) != null) {
            cache.remove(staleKey);
            System.out.println("[Cache] Stale entry removed after GC collection");
        }
    }

    public void put(Class<?> cls, Type resolvedType) {
        expungeStaleEntries(); // lazy cleanup
        WeakTypeKey key = new WeakTypeKey(cls, refQueue);
        cache.put(key, resolvedType);
    }

    public Type get(Class<?> cls) {
        expungeStaleEntries(); // lazy cleanup
        // 조회용 임시 키 (refQueue 없이 생성)
        WeakTypeKey lookupKey = new WeakTypeKey(cls, null) {
            @Override
            public boolean equals(Object obj) {
                if (!(obj instanceof WeakTypeKey other)) return false;
                return other.get() == cls;
            }
        };
        return cache.get(lookupKey);
    }

    public int size() {
        expungeStaleEntries();
        return cache.size();
    }
}
```

