## 2. ATE 구현 코드

### 2.1 핵심 컴포넌트: 제네릭 메타데이터 저장소

```java
import java.lang.ref.SoftReference;
import java.lang.reflect.ParameterizedType;
import java.lang.reflect.Type;
import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

/**
 * 비동기 타입 소거를 위한 제네릭 메타데이터 관리자
 * - WeakHashMap을 통한 자동 참조 해제
 * - SoftReference로 메모리 압박 시 자동 정제
 */
public class AsynchronousTypeErasureManager {

    // 타입 메타데이터 저장 구조
    private static class TypeMetadata {
        final Type[] typeArguments;
        final long creationTimestamp;
        final int generationId;
        volatile boolean markedForErasure;

        TypeMetadata(Type[] typeArguments, int generationId) {
            this.typeArguments = typeArguments;
            this.creationTimestamp = System.nanoTime();
            this.generationId = generationId;
            this.markedForErasure = false;
        }
    }

    // Young Generation 메타데이터 (빠른 접근)
    private final Map<Integer, SoftReference<TypeMetadata>> youngGenMetadata = 
        new ConcurrentHashMap<>();

    // Old Generation 메타데이터 (장기 보존)
    private final Map<Integer, TypeMetadata> oldGenMetadata = 
        Collections.synchronizedMap(new LinkedHashMap<Integer, TypeMetadata>() {
            protected boolean removeEldestEntry(Map.Entry eldest) {
                return size() > 10000; // 최대 10000개 항목 유지
            }
        });

    private final AtomicInteger metadataCounter = new AtomicInteger(0);
    private final AtomicInteger currentGeneration = new AtomicInteger(0);
    private final ExecutorService asyncErasureExecutor;
    private final BlockingQueue<Integer> erasureQueue;

    private static final int YOUNG_GEN_THRESHOLD = 1024;
    private static final int ERASURE_BATCH_SIZE = 128;

    public AsynchronousTypeErasureManager(int threadPoolSize) {
        this.asyncErasureExecutor = Executors.newFixedThreadPool(
            threadPoolSize,
            r -> {
                Thread t = new Thread(r, "ATE-Erasure-Worker");
                t.setDaemon(true);
                t.setPriority(Thread.MIN_PRIORITY);
                return t;
            }
        );
        this.erasureQueue = new LinkedBlockingQueue<>();
        initializeGCCallback();
        startAsyncErasureWorker();
    }

    /**
     * GC 콜백 등록 - Post-GC 이벤트 감지
     */
    private void initializeGCCallback() {
        NotificationEmitter emitter = 
            (NotificationEmitter) ManagementFactory.getMemoryMXBean();

        emitter.addNotificationListener((notification, handback) -> {
            if (notification.getType()
                .equals(MemoryNotificationInfo.MEMORY_COLLECTION_THRESHOLD_EXCEEDED)) {

                MemoryNotificationInfo info = 
                    MemoryNotificationInfo.from((CompositeData) 
                    notification.getUserData());

                if (info.getPoolName().contains("Old")) {
                    triggerMajorGCErasure();
                } else {
                    triggerMinorGCErasure();
                }
            }
        }, null, null);
    }

    /**
     * 제네릭 타입 메타데이터 등록
     * @param typeArguments 타입 인자 배열
     * @return 메타데이터 식별자
     */
    public int registerTypeMetadata(Type[] typeArguments) {
        int metadataId = metadataCounter.incrementAndGet();
        int generation = currentGeneration.get();

        TypeMetadata metadata = new TypeMetadata(typeArguments, generation);

        // Young Generation에 먼저 저장
        youngGenMetadata.put(metadataId, new SoftReference<>(metadata));

        // Young Generation 임계값 초과 시 Old Generation으로 승격
        if (youngGenMetadata.size() > YOUNG_GEN_THRESHOLD) {
            promoteToOldGeneration();
        }

        return metadataId;
    }

    /**
     * Young Generation → Old Generation 승격
     */
    private void promoteToOldGeneration() {
        List<Integer> keysToPromote = new ArrayList<>();

        for (Map.Entry<Integer, SoftReference<TypeMetadata>> entry : 
             youngGenMetadata.entrySet()) {

            SoftReference<TypeMetadata> ref = entry.getValue();
            TypeMetadata metadata = ref.get();

            if (metadata != null && !metadata.markedForErasure) {
                keysToPromote.add(entry.getKey());
            }
        }

        keysToPromote.stream()
            .limit(YOUNG_GEN_THRESHOLD / 2)
            .forEach(key -> {
                SoftReference<TypeMetadata> ref = youngGenMetadata.remove(key);
                if (ref != null) {
                    TypeMetadata metadata = ref.get();
                    if (metadata != null) {
                        oldGenMetadata.put(key, metadata);
                    }
                }
            });
    }

    /**
     * Minor GC 후 비동기 타입 소거 트리거
     */
    private void triggerMinorGCErasure() {
        asyncErasureExecutor.submit(this::performYoungGenErasure);
    }

    /**
     * Major GC 후 비동기 타입 소거 트리거
     */
    private void triggerMajorGCErasure() {
        asyncErasureExecutor.submit(this::performOldGenErasure);
        currentGeneration.incrementAndGet(); // 세대 증가
    }

    /**
     * Young Generation 타입 소거 수행
     * - SoftReference 자동 정제 활용
     * - 메모리 압박 시 자동 해제
     */
    private void performYoungGenErasure() {
        List<Integer> deadReferences = new ArrayList<>();

        for (Map.Entry<Integer, SoftReference<TypeMetadata>> entry : 
             youngGenMetadata.entrySet()) {

            if (entry.getValue().get() == null) {
                deadReferences.add(entry.getKey());
            }
        }

        deadReferences.forEach(youngGenMetadata::remove);
    }

    /**
     * Old Generation 타입 소거 수행
     * - 타입 소거 표시된 메타데이터 정제
     * - 장시간 미사용 메타데이터 제거
     */
    private void performOldGenErasure() {
        long currentTime = System.nanoTime();
        long erasureThreshold = TimeUnit.SECONDS.toNanos(300); // 300초

        List<Integer> keysToErase = new ArrayList<>();

        for (Map.Entry<Integer, TypeMetadata> entry : oldGenMetadata.entrySet()) {
            TypeMetadata metadata = entry.getValue();

            boolean isStale = (currentTime - metadata.creationTimestamp) 
                > erasureThreshold;
            boolean isMarked = metadata.markedForErasure;

            if (isStale || isMarked) {
                keysToErase.add(entry.getKey());
            }
        }

        // 배치 단위로 비동기 처리
        for (int i = 0; i < keysToErase.size(); i += ERASURE_BATCH_SIZE) {
            int endIdx = Math.min(i + ERASURE_BATCH_SIZE, keysToErase.size());
            List<Integer> batch = keysToErase.subList(i, endIdx);

            batch.forEach(key -> {
                TypeMetadata erased = oldGenMetadata.remove(key);
                if (erased != null) {
                    erased.typeArguments.clone(); // 명시적 소거
                }
            });
        }
    }

    /**
     * 비동기 타입 소거 워커 시작
     */
    private void startAsyncErasureWorker() {
        asyncErasureExecutor.submit(() -> {
            while (!Thread.currentThread().isInterrupted()) {
                try {
                    Integer metadataId = erasureQueue.poll(100, TimeUnit.MILLISECONDS);
                    if (metadataId != null) {
                        markForErasure(metadataId);
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    break;
                }
            }
        });
    }

    /**
     * 타입 메타데이터를 소거 대상으로 표시
     */
    public void markForErasure(int metadataId) {
        SoftReference<TypeMetadata> youngRef = youngGenMetadata.get(metadataId);
        if (youngRef != null) {
            TypeMetadata metadata = youngRef.get();
            if (metadata != null) {
                metadata.markedForErasure = true;
            }
            return;
        }

        TypeMetadata oldRef = oldGenMetadata.get(metadataId);
        if (oldRef != null) {
            oldRef.markedForErasure = true;
        }
    }

    /**
     * 타입 메타데이터 검색 (캐시 활용)
     */
    public Type[] retrieveTypeArguments(int metadataId) {
        SoftReference<TypeMetadata> youngRef = youngGenMetadata.get(metadataId);
        if (youngRef != null) {
            TypeMetadata metadata = youngRef.get();
            if (metadata != null) {
                return metadata.typeArguments;
            }
        }

        TypeMetadata oldRef = oldGenMetadata.get(metadataId);
        if (oldRef != null) {
            return oldRef.typeArguments;
        }

        return null;
    }

    /**
     * 통계 정보 조회
     */
    public TypeErasureStatistics getStatistics() {
        return new TypeErasureStatistics(
            youngGenMetadata.size(),
            oldGenMetadata.size(),
            currentGeneration.get(),
            metadataCounter.get()
        );
    }

    public void shutdown() {
        asyncErasureExecutor.shutdown();
        try {
            if (!asyncErasureExecutor.awaitTermination(10, TimeUnit.SECONDS)) {
                asyncErasureExecutor.shutdownNow();
            }
        } catch (InterruptedException e) {
            asyncErasureExecutor.shutdownNow();
            Thread.currentThread().interrupt();
        }
    }
}
```

