public class ATEOptimizer {

    // HotSpot JVM의 C2 컴파일러를 위한 최적화 힌트
    @HotSpotIntrinsicCandidate
    public static <T> T unsafeCast(Object obj, Class<T> type) {
        // 타입 메타데이터가 유효한 경우 검증 생략
        TypeMetadata metadata = typeCache.get(System.identityHashCode(obj));

        if (metadata != null && 
            metadata.runtimeType == type && 
            metadata.accessCount.get() > INLINE_THRESHOLD) {

            // JIT 컴파일러가 checkcast 바이트코드 제거 가능
            return (T) obj;
        }

        // 일반 경로
        return type.cast(obj);
    }

    private static final int INLINE_THRESHOLD = 1000;
}
