### 4.2 메모리 레이아웃 최적화
```java
public class CompressedTypeMetadata {

    // 64비트 JVM에서 압축 객체 포인터(Compressed OOPs) 활용
    // 일반 참조: 8바이트
    // 압축 참조: 4바이트

    // 타입 정보를 비트 필드로 압축
    private long compressedTypeInfo;

    // 상위 32비트: 클래스 ID
    // 하위 32비트: 접근 카운터

    public CompressedTypeMetadata(int classId, int accessCount) {
        this.compressedTypeInfo = 
            ((long) classId << 32) | (accessCount & 0xFFFFFFFFL);
    }

    public int getClassId() {
        return (int) (compressedTypeInfo >>> 32);
    }

    public int getAccessCount() {
        return (int) compressedTypeInfo;
    }

    public void incrementAccess() {
        // 원자적 증가 연산
        long current, updated;
        do {
            current = compressedTypeInfo;
            int newCount = ((int) current) + 1;
            updated = (current & 0xFFFFFFFF00000000L) | 
                     (newCount & 0xFFFFFFFFL);
        } while (!UNSAFE.compareAndSwapLong(
            this, OFFSET, current, updated));
    }

    private static final Unsafe UNSAFE = getUnsafe();
    private static final long OFFSET = getFieldOffset();

    private static Unsafe getUnsafe() {
        try {
            Field f = Unsafe.class.getDeclaredField("theUnsafe");
            f.setAccessible(true);
            return (Unsafe) f.get(null);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    private static long getFieldOffset() {
        try {
            return UNSAFE.objectFieldOffset(
                CompressedTypeMetadata.class
                    .getDeclaredField("compressedTypeInfo"));
        } catch (NoSuchFieldException e) {
            throw new RuntimeException(e);
        }
    }
}
