### 1.2 힙 오버헤드의 실제 발생 지점

```java
import java.lang.management.ManagementFactory;
import java.lang.management.MemoryMXBean;
import java.lang.management.MemoryUsage;
import java.util.ArrayList;
import java.util.List;

/**
 * Type Erasure로 인한 실제 힙 오버헤드 측정
 *
 * 오버헤드 발생 원인:
 * 1. Autoboxing: primitive → wrapper 객체 변환 시 heap allocation 발생
 *    - int(4 bytes) → Integer 객체(16 bytes object header + 4 bytes field = 20 bytes, 패딩 후 16bytes)
 *    - JVM Object Header: mark word(8 bytes) + class pointer(4 or 8 bytes)
 *
 * 2. Bridge Method 생성: 공변 반환 타입 처리를 위한 synthetic method 추가
 *
 * 3. Wildcard Capture: ? extends T 처리 시 추가 타입 체크 bytecode 삽입
 */
public class HeapOverheadMeasurement {

    private static final MemoryMXBean MEMORY_MX_BEAN =
        ManagementFactory.getMemoryMXBean();

    /**
     * primitive int 배열 vs Integer List 힙 사용량 비교
     * Type Erasure로 인해 List<Integer>는 List<Object>로 소거되어
     * primitive specialization 불가 → autoboxing 강제
     */
    public static void measureAutoboxingOverhead() {
        final int ELEMENT_COUNT = 1_000_000;

        // GC 수행 후 베이스라인 측정
        System.gc();
        System.runFinalization();
        long baselineHeap = getUsedHeapBytes();

        // Case 1: primitive int array (Type Erasure 영향 없음)
        int[] primitiveArray = new int[ELEMENT_COUNT];
        for (int i = 0; i < ELEMENT_COUNT; i++) {
            primitiveArray[i] = i;
        }
        long primitiveHeap = getUsedHeapBytes() - baselineHeap;

        // primitive array 해제
        primitiveArray = null;
        System.gc();
        System.runFinalization();
        baselineHeap = getUsedHeapBytes();

        // Case 2: List<Integer> - Type Erasure로 인해 autoboxing 발생
        // 내부적으로 Object[] 로 저장됨 (int[] 불가)
        List<Integer> genericList = new ArrayList<>(ELEMENT_COUNT);
        for (int i = 0; i < ELEMENT_COUNT; i++) {
            genericList.add(i); // autoboxing: int → Integer (heap allocation)
        }
        long genericHeap = getUsedHeapBytes() - baselineHeap;

        System.out.printf("primitive int[]: %,d bytes (%.2f MB)%n",
            primitiveHeap, primitiveHeap / 1024.0 / 1024.0);
        System.out.printf("List<Integer>:   %,d bytes (%.2f MB)%n",
            genericHeap, genericHeap / 1024.0 / 1024.0);
        System.out.printf("오버헤드 배율: %.1fx%n",
            (double) genericHeap / primitiveHeap);
    }

    private static long getUsedHeapBytes() {
        MemoryUsage heapUsage = MEMORY_MX_BEAN.getHeapMemoryUsage();
        return heapUsage.getUsed();
    }

    public static void main(String[] args) {
        measureAutoboxingOverhead();
    }
}
```

