## Unity C# 구현

```csharp
using UnityEngine;
using System.Collections.Generic;

namespace STC
{
    /// <summary>
    /// 타일 가시성 이력 및 확률 상태를 보유하는 구조체
    /// </summary>
    [System.Serializable]
    public struct TileVisibilityState
    {
        public SpriteRenderer Renderer;
        public Vector2Int GridPosition;
        public float VisibilityProbability;
        public int ConsecutiveInvisibleFrames;
        public bool LastKnownVisible;
    }

    /// <summary>
    /// 청크 단위 공간 분할 구조
    /// </summary>
    public class TileChunk
    {
        public Bounds AABB;
        public List<int> TileIndices; // TileVisibilityState 배열 내 인덱스 참조

        public TileChunk(Bounds bounds)
        {
            AABB = bounds;
            TileIndices = new List<int>(64);
        }
    }

    /// <summary>
    /// Stochastic Tilemap Culling 메인 컨트롤러
    /// </summary>
    public class StochasticTilemapCuller : MonoBehaviour
    {
        [Header("Spatial Partitioning")]
        [SerializeField] private Vector2Int chunkSize = new Vector2Int(8, 8);
        [SerializeField] private float tileUnit = 1.0f;

        [Header("Stochastic Parameters")]
        [SerializeField] [Range(0.0f, 1.0f)] private float activationThreshold = 0.3f;
        [SerializeField] [Range(0.01f, 0.99f)] private float probabilityDecayRate = 0.85f;
        [SerializeField] [Range(0.01f, 0.99f)] private float probabilityGrowthRate = 0.4f;
        [SerializeField] private int maxInvisibleFramesBeforeDisable = 3;

        [Header("Temporal Amortization")]
        [SerializeField] private int amortizationSubsets = 4;

        [Header("Velocity Prediction")]
        [SerializeField] private float predictionHorizon = 0.1f; // seconds

        // Internal State
        private TileVisibilityState[] _tileStates;
        private TileChunk[] _chunks;
        private Camera _camera;
        private Vector3 _previousCameraPosition;
        private Vector3 _cameraVelocity;
        private int _currentSubsetIndex;
        private int _totalTileCount;
        private Plane[] _frustumPlanes = new Plane[6];

        // Chunk spatial lookup
        private Dictionary<Vector2Int, TileChunk> _chunkLookup;

        private void Awake()
        {
            _camera = GetComponent<Camera>();
            if (_camera == null)
                _camera = Camera.main;

            _previousCameraPosition = transform.position;
            _currentSubsetIndex = 0;
        }

        private void Start()
        {
            InitializeTileRegistry();
            BuildChunks();
        }

        /// <summary>
        /// 씬 내 모든 대상 SpriteRenderer를 수집하여 상태 배열 초기화
        /// </summary>
        private void InitializeTileRegistry()
        {
            // 태그 또는 레이어 기반 필터링 (여기서는 "Tile" 태그 사용)
            GameObject[] tileObjects = GameObject.FindGameObjectsWithTag("Tile");
            _totalTileCount = tileObjects.Length;
            _tileStates = new TileVisibilityState[_totalTileCount];

            for (int i = 0; i < _totalTileCount; i++)
            {
                SpriteRenderer sr = tileObjects[i].GetComponent<SpriteRenderer>();
                Vector2Int gridPos = WorldToGrid(tileObjects[i].transform.position);

                _tileStates[i] = new TileVisibilityState
                {
                    Renderer = sr,
                    GridPosition = gridPos,
                    VisibilityProbability = 1.0f,
                    ConsecutiveInvisibleFrames = 0,
                    LastKnownVisible = true
                };
            }
        }

        /// <summary>
        /// 타일을 청크 단위로 공간 분할
        /// </summary>
        private void BuildChunks()
        {
            _chunkLookup = new Dictionary<Vector2Int, TileChunk>();

            for (int i = 0; i < _totalTileCount; i++)
            {
                Vector2Int chunkCoord = new Vector2Int(
                    Mathf.FloorToInt((float)_tileStates[i].GridPosition.x / chunkSize.x),
                    Mathf.FloorToInt((float)_tileStates[i].GridPosition.y / chunkSize.y)
                );

                if (!_chunkLookup.ContainsKey(chunkCoord))
                {
                    Vector3 chunkCenter = new Vector3(
                        (chunkCoord.x + 0.5f) * chunkSize.x * tileUnit,
                        (chunkCoord.y + 0.5f) * chunkSize.y * tileUnit,
                        0f
                    );
                    Vector3 chunkExtents = new Vector3(
                        chunkSize.x * tileUnit * 0.5f,
                        chunkSize.y * tileUnit * 0.5f,
                        0.5f
                    );
                    Bounds bounds = new Bounds(chunkCenter, chunkExtents * 2f);
                    _chunkLookup[chunkCoord] = new TileChunk(bounds);
                }

                _chunkLookup[chunkCoord].TileIndices.Add(i);
            }

            _chunks = new TileChunk[_chunkLookup.Count];
            _chunkLookup.Values.CopyTo(_chunks, 0);
        }

        private void LateUpdate()
        {
            ComputeCameraVelocity();
            ExtractFrustumPlanes();
            ExecuteSTC();
            _previousCameraPosition = transform.position;
        }

        private void ComputeCameraVelocity()
        {
            Vector3 delta = transform.position - _previousCameraPosition;
            float dt = Time.deltaTime;
            _cameraVelocity = (dt > 1e-6f) ? delta / dt : Vector3.zero;
        }

        private void ExtractFrustumPlanes()
        {
            // 직교 카메라의 프러스텀 6면 추출
            GeometryUtility.CalculateFrustumPlanes(_camera, _frustumPlanes);
        }

        /// <summary>
        /// STC 메인 루프: Temporal Amortization 적용
        /// </summary>
        private void ExecuteSTC()
        {
            // 예측된 프러스텀 확장 (velocity-based prediction)
            Bounds predictedFrustumBounds = ComputePredictedFrustumBounds();

            // Phase 1: 청크 레벨 컬링 (전체 청크 매 프레임 수행 - 청크 수는 소량)
            HashSet<int> visibleTileIndices = new HashSet<int>();
            for (int c = 0; c < _chunks.Length; c++)
            {
                // Frustum-AABB 교차 판정
                if (GeometryUtility.TestPlanesAABB(_frustumPlanes, _chunks[c].AABB))
                {
                    // 추가: 예측 범위 내 포함 여부
                    if (_chunks[c].AABB.Intersects(predictedFrustumBounds))
                    {
                        for (int t = 0; t < _chunks[c].TileIndices.Count; t++)
                        {
                            visibleTileIndices.Add(_chunks[c].TileIndices[t]);
                        }
                    }
                }
            }

            // Phase 2: 타일 레벨 확률적 컬링 (Amortized)
            int subsetSize = Mathf.CeilToInt((float)_totalTileCount / amortizationSubsets);
            int startIndex = _currentSubsetIndex * subsetSize;
            int endIndex = Mathf.Min(startIndex + subsetSize, _totalTileCount);

            for (int i = startIndex; i < endIndex; i++)
            {
                ref TileVisibilityState state = ref _tileStates[i];

                if (state.Renderer == null) continue;

                bool inFrustum = visibleTileIndices.Contains(i);

                // 확률 갱신 (Exponential Moving Average 기반)
                if (inFrustum)
                {
                    // 가시 영역 내: 확률 증가
                    state.VisibilityProbability = Mathf.Lerp(
                        state.VisibilityProbability, 1.0f, probabilityGrowthRate
                    );
                    state.ConsecutiveInvisibleFrames = 0;
                }
                else
                {
                    // 가시 영역 외: 확률 감쇠
                    state.VisibilityProbability *= probabilityDecayRate;
                    state.ConsecutiveInvisibleFrames++;
                }

                // 활성화/비활성화 결정
                bool shouldBeActive = DetermineActivation(ref state, inFrustum);

                if (state.Renderer.enabled != shouldBeActive)
                {
                    state.Renderer.enabled = shouldBeActive;
                }

                state.LastKnownVisible = shouldBeActive;
            }

            // Subset 순환
            _currentSubsetIndex = (_currentSubsetIndex + 1) % amortizationSubsets;
        }

        /// <summary>
        /// 확률적 활성화 결정 함수
        /// </summary>
        private bool DetermineActivation(ref TileVisibilityState state, bool inFrustum)
        {
            // Case 1: 프러스텀 내부이고 확률이 임계값 이상 → 활성
            if (inFrustum && state.VisibilityProbability >= activationThreshold)
                return true;

            // Case 2: 프러스텀 내부이지만 확률이 임계값 미만 (오클루전 추정) → 비활성
            if (inFrustum && state.VisibilityProbability < activationThreshold)
            {
                // 스토캐스틱 샘플링: 낮은 확률로 활성화하여 상태 갱신 기회 부여
