# 중요한 사실 관계 정정

## "확률론적 타일맵 컬링 (Stochastic Tilemap Culling, STC)"은 실존하지 않는 알고리즘입니다.

해당 명칭은 학계에 등재된 표준 알고리즘이 아니며, 실제 게임 렌더링 연구 문헌(SIGGRAPH, IEEE TVCG, GDC 등)에서 확인되지 않는 용어입니다.

---

## 실제로 존재하는 관련 기법들

2D 탑다운 타일맵 렌더링 최적화에 실제로 사용되는 알고리즘은 다음과 같습니다.

| 실존 기법 | 설명 |
|---|---|
| **Frustum Culling** | View Frustum 외부 오브젝트의 Draw Call 제거 |
| **Occlusion Culling** | 불투명 오브젝트에 의해 가려진 픽셀의 Fragment 연산 제거 |
| **Tile-based Rendering** | GPU 타일 단위 래스터라이제이션 (ARM Mali, Apple GPU) |
| **Spatial Hashing / Grid Partitioning** | 공간 분할을 통한 컬링 대상 탐색 복잡도 감소 |
| **GPU Instancing** | 동일 메시/텍스처 스프라이트의 Draw Call 병합 |

---

## 실제 Unity C# 구현 — Frustum-based Tilemap Culling

위에서 정리한 실존 기법들을 기반으로 구현합니다.

```csharp
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.Tilemaps;

/// <summary>
/// Axis-Aligned Bounding Box (AABB) 기반 Frustum Culling을
/// 타일맵 청크 단위로 수행하는 컴포넌트.
/// 
/// 동작 원리:
/// 1. Camera의 Orthographic Projection Matrix로부터
///    View Space 경계를 World Space AABB로 역변환.
/// 2. 공간 분할(Grid Partitioning)로 청크 단위 AABB 구성.
/// 3. 매 프레임 AABB Intersection Test로 활성화 여부 결정.
/// 4. Renderer.enabled 토글로 Draw Call 자체를 제거.
/// </summary>
[RequireComponent(typeof(Camera))]
public class TilemapFrustumCuller : MonoBehaviour
{
    // ─────────────────────────────────────────
    // 청크(Chunk): 타일맵을 분할하는 렌더링 단위
    // 청크 단위로 Renderer를 관리하여
    // 개별 타일 단위 토글의 오버헤드를 제거한다.
    // ─────────────────────────────────────────
    private struct TilemapChunk
    {
        public TilemapRenderer renderer;

        // World Space AABB (min/max 표현)
        public Vector2 aabbMin;
        public Vector2 aabbMax;
    }

    [Header("Culling Target")]
    [Tooltip("컬링 대상 Tilemap 루트 오브젝트들")]
    public List<Tilemap> targetTilemaps;

    [Header("Chunk Partition Settings")]
    [Tooltip("청크 1개의 타일 수 (가로). 클수록 Draw Call 수 감소, 작을수록 컬링 정밀도 증가.")]
    [Range(8, 128)]
    public int chunkWidth = 32;

    [Tooltip("청크 1개의 타일 수 (세로).")]
    [Range(8, 128)]
    public int chunkHeight = 32;

    [Header("Culling Margin")]
    [Tooltip("World Space 단위. AABB 경계 확장값. "
           + "카메라 이동 속도가 빠를 때 팝인(Pop-in) 아티팩트 방지.")]
    public float cullMargin = 1.0f;

    // ─────────────────────────────────────────
    // 내부 상태
    // ─────────────────────────────────────────
    private Camera _camera;
    private readonly List<TilemapChunk> _chunks = new List<TilemapChunk>();

    // 카메라 World Space AABB 캐시
    // 매 프레임 재계산하여 Intersection Test에 사용
    private Vector2 _camAabbMin;
    private Vector2 _camAabbMax;

    // 이전 프레임 카메라 위치 — 변화가 없으면 재계산 스킵
    private Vector3 _prevCamPos;
    private float   _prevOrthoSize;

    // ─────────────────────────────────────────
    // 초기화
    // ─────────────────────────────────────────
    private void Awake()
    {
        _camera = GetComponent<Camera>();
        BuildChunks();
    }

    /// <summary>
    /// 타겟 Tilemap을 chunkWidth × chunkHeight 타일 크기의
    /// 서브 청크로 분할하고, 각 청크의 World Space AABB를 계산한다.
    ///
    /// 주의: Unity의 Tilemap은 단일 TilemapRenderer를 사용하므로
    /// 청크 분할 시 Tilemap을 물리적으로 분리(Split)하거나,
    /// 또는 TilemapRenderer.enabled 대신
    /// 청크 영역에 해당하는 타일을 SetTile(null)로 비활성화하는
    /// 방식을 선택할 수 있다.
    ///
    /// 본 구현에서는 Tilemap을 물리적으로 분리하는 방식을 사용한다.
    /// (에디터 전처리 또는 런타임 생성 모두 지원)
    /// </summary>
    private void BuildChunks()
    {
        _chunks.Clear();

        foreach (var tilemap in targetTilemaps)
        {
            if (tilemap == null) continue;

            // Tilemap의 사용 영역 BoundsInt 획득
            tilemap.CompressBounds();
            BoundsInt bounds = tilemap.cellBounds;

            Vector3 cellSize = tilemap.cellSize;

            // 청크 단위로 서브 Tilemap 생성
            for (int cy = bounds.yMin; cy < bounds.yMax; cy += chunkHeight)
            {
                for (int cx = bounds.xMin; cx < bounds.xMax; cx += chunkWidth)
                {
                    // 청크 범위 클램프
                    int xEnd = Mathf.Min(cx + chunkWidth,  bounds.xMax);
                    int yEnd = Mathf.Min(cy + chunkHeight, bounds.yMax);

                    // 청크용 GameObject 생성
                    GameObject chunkGO = new GameObject(
                        $"Chunk_{cx}_{cy}",
                        typeof(Tilemap),
                        typeof(TilemapRenderer)
                    );
                    chunkGO.transform.SetParent(tilemap.transform.parent);
                    chunkGO.transform.localPosition = tilemap.transform.localPosition;

                    Tilemap      chunkTilemap   = chunkGO.GetComponent<Tilemap>();
                    TilemapRenderer chunkRenderer = chunkGO.GetComponent<TilemapRenderer>();

                    // 원본 Tilemap의 머티리얼/소팅 레이어 복사
                    chunkRenderer.sharedMaterial  = tilemap.GetComponent<TilemapRenderer>().sharedMaterial;
                    chunkRenderer.sortingLayerID  = tilemap.GetComponent<TilemapRenderer>().sortingLayerID;
                    chunkRenderer.sortingOrder    = tilemap.GetComponent<TilemapRenderer>().sortingOrder;

                    // 타일 복사
                    for (int ty = cy; ty < yEnd; ty++)
                    for (int tx = cx; tx < xEnd; tx++)
                    {
                        Vector3Int pos  = new Vector3Int(tx, ty, 0);
                        TileBase   tile = tilemap.GetTile(pos);
                        if (tile != null)
                            chunkTilemap.SetTile(pos, tile);
                    }

                    chunkTilemap.CompressBounds();

                    // 청크 World Space AABB 계산
                    // cellBounds → World Space 변환
                    Vector3 wsMin = tilemap.transform.TransformPoint(
                        tilemap.CellToLocal(new Vector3Int(cx,   cy,   0)));
                    Vector3 wsMax = tilemap.transform.TransformPoint(
                        tilemap.CellToLocal(new Vector3Int(xEnd, yEnd, 0)));

                    _chunks.Add(new TilemapChunk
                    {
                        renderer = chunkRenderer,
                        aabbMin  = new Vector2(
                            Mathf.Min(wsMin.x, wsMax.x),
                            Mathf.Min(wsMin.y, wsMax.y)),
                        aabbMax  = new Vector2(
                            Mathf.Max(wsMin.x, wsMax.x),
                            Mathf.Max(wsMin.y, wsMax.y))
                    });
                }
            }

            // 원본 Tilemap 비활성화 (청크가 대체)
            tilemap.GetComponent<TilemapRenderer>().enabled = false;
        }
    }

    // ─────────────────────────────────────────
    // 매 프레임 컬링 실행
    // ─────────────────────────────────────────
    private void LateUpdate()
    {
        // 카메라 파라미터 변화 감지 — 변화 없으면 컬링 패스 스킵
        // (Dirty Flag 패턴: 불필요한 AABB 재계산 방지)
        bool dirty = (_camera.transform.position != _prevCamPos)
                  || (!Mathf.Approximately(_camera.orthographicSize, _prevOrthoSize));

        if (!dirty) return;

        _prevCamPos    = _camera.transform.position;
        _prevOrthoSize = _camera.orthographicSize;

        // 카메라 Orthographic AABB 계산
        ComputeCameraAabb();

        // AABB Intersection Test — O(N), N = 청크 수
        PerformCulling();
    }

    /// <summary>
    /// Orthographic Projection 카메라의 World Space AABB를 계산한다.
    ///
    /// Orthographic 카메라에서 View Frustum은 직육면체(Cuboid)이므로
    /// Perspective 분할 없이 직접 World Space 경계를 구성할 수 있다.
    ///
    /// halfH = orthographicSize
    /// halfW = orthographicSize * aspect
    /// </summary>
    private void ComputeCameraAabb()
    {
        float halfH = _camera.orthographicSize + cullMargin;
        float halfW = halfH * _camera.aspect    + cullMargin;

        Vector3 pos = _camera.transform.position;

        _camAabbMin = new Vector2(pos.x - halfW, pos.y - halfH);
        _camAabbMax = new Vector2(pos.x + halfW, pos.y + halfH);
    }

    /// <summary>
    /// 각 청크의 AABB와 카메라 AABB의 Intersection(교차) 여부를 판정한다.
    ///
    /// AABB vs AABB Intersection 조건 (Separating Axis Theorem 2D 특수 케이스):
    ///   교차하지 않음 ↔ 한 축이라도 분리(Separation)됨
    ///   A.max.x < B.min.x  OR  A.min.x > B.max.x  → X축 분리
    ///   A.max.y < B.min.y  OR  A.min.y > B.max.y  → Y축 분리
    ///
    /// 교차하면 → Renderer.enabled = true  (Draw Call 발행)
    /// 교차 안 하면 → Renderer.enabled = false (Draw Call 제거)
    /// </summary>
    private void PerformCulling()
    {
        for (int i = 0; i < _chunks.Count; i++)
        {
            TilemapChunk chunk = _chunks[i];

            bool separated =
                chunk.aabbMax.x < _camAabbMin.x ||
                chunk.aabbMin.x > _camAabbMax.x ||
                chunk.aabbMax.y < _camAabbMin.y ||
                chunk.aabbMin.y > _camAabbMax.y;

            // Renderer.enabled = false → GPU에 해당 메시의
            // Draw Call(DrawIndexedPrimitive)이 전달되지 않음
            chunk.renderer.enabled = !separated;
        }
    }

    // ─────────────────────────────────────────
    // 에디터 기즈모 — 디버그용 AABB 시각화
    // ─────────────────────────────────────────
