# 2D 탑다운 게임의 확률론적 타일맵 컬링(STC) 구현

먼저 명확히 할 점: **"확률론적 타일맵 컬링"은 학계에 정식으로 제안된 알고리즘이 아닙니다.** 실제 산업 표준은 **Frustum Culling**, **Occlusion Culling**, **Spatial Partitioning** 기반 기법들입니다. 아래는 이들을 통합한 실용적 구현입니다.

---

## 1. 핵심 개념: 확률론적 접근의 문제점

확률론적 방식으로 렌더링 대상을 "비활성화"하는 것은:
- **프레임 일관성 붕괴** (Temporal Coherence Breakdown)
- **시각적 팝인/팝아웃** (Pop-in artifacts)
- **렌더링 결과 비결정성** 초래

따라서 **결정론적 공간 분할 기반 컬링**을 구현합니다.

---

## 2. 최적화된 구현: Spatial Hashing + Frustum Culling

```csharp
using UnityEngine;
using System.Collections.Generic;

/// <summary>
/// 확률론적이 아닌 결정론적 타일맵 컬링 시스템
/// Spatial Hash Grid + Frustum Culling 기반
/// </summary>
public class OptimizedTilemapCulling : MonoBehaviour
{
    [SerializeField] private Camera mainCamera;
    [SerializeField] private int gridCellSize = 32; // 타일 크기
    [SerializeField] private int gridResolutionX = 100;
    [SerializeField] private int gridResolutionY = 100;

    // Spatial Hashing 구조
    private Dictionary<int, List<TileData>> spatialHashGrid;
    private TileData[] allTiles;

    // Frustum 경계 캐시
    private Plane[] frustumPlanes;
    private Vector3 frustumMin, frustumMax;

    // 성능 메트릭
    private int visibleTileCount;
    private int culledTileCount;

    private struct TileData
    {
        public Vector3 position;
        public Bounds bounds;
        public Renderer renderer;
        public int gridHash;
        public bool wasVisibleLastFrame;
    }

    private void Start()
    {
        InitializeSpatialGrid();
        frustumPlanes = new Plane[6];
    }

    /// <summary>
    /// 공간 해싱 그리드 초기화
    /// O(n) 전처리 비용
    /// </summary>
    private void InitializeSpatialGrid()
    {
        spatialHashGrid = new Dictionary<int, List<TileData>>();

        // 씬의 모든 Tile Renderer 수집
        Renderer[] allRenderers = FindObjectsOfType<Renderer>();
        allTiles = new TileData[allRenderers.Length];

        for (int i = 0; i < allRenderers.Length; i++)
        {
            TileData tile = new TileData
            {
                position = allRenderers[i].transform.position,
                bounds = allRenderers[i].bounds,
                renderer = allRenderers[i],
                wasVisibleLastFrame = true
            };

            // 공간 해시 계산
            tile.gridHash = ComputeSpatialHash(tile.position);

            if (!spatialHashGrid.ContainsKey(tile.gridHash))
                spatialHashGrid[tile.gridHash] = new List<TileData>();

            spatialHashGrid[tile.gridHash].Add(tile);
            allTiles[i] = tile;
        }
    }

    /// <summary>
    /// 3D 위치를 1D 공간 해시로 변환
    /// Morton Code(Z-order curve) 사용
    /// </summary>
    private int ComputeSpatialHash(Vector3 worldPos)
    {
        int gridX = Mathf.FloorToInt(worldPos.x / gridCellSize);
        int gridY = Mathf.FloorToInt(worldPos.y / gridCellSize);

        // Morton 인코딩으로 캐시 지역성 향상
        return MortonEncode(gridX, gridY);
    }

    /// <summary>
    /// Morton Code 인코딩 (Z-order curve)
    /// 공간적 인접성을 선형 인접성으로 변환
    /// </summary>
    private int MortonEncode(int x, int y)
    {
        int result = 0;
        for (int i = 0; i < 16; i++)
        {
            result |= ((x & (1 << i)) << i) | ((y & (1 << i)) << (i + 1));
        }
        return result;
    }

    /// <summary>
    /// 프레임별 컬링 업데이트
    /// 카메라 Frustum 기반 가시성 판정
    /// </summary>
    private void Update()
    {
        // Frustum 평면 추출 (카메라 절두체)
        ExtractFrustumPlanes();

        // 카메라 시야 AABB 계산
        CalculateFrustumBounds();

        // 공간 해시 쿼리: 카메라 시야 관련 그리드 셀만 순회
        QueryVisibleTiles();

        // 프레임 통계
        Debug.Log($"Visible: {visibleTileCount} | Culled: {culledTileCount} | " +
                  $"Culling Rate: {(culledTileCount * 100f / (visibleTileCount + culledTileCount)):F1}%");
    }

    /// <summary>
    /// 카메라 Frustum 평면 추출
    /// 6개 평면: Near, Far, Left, Right, Top, Bottom
    /// </summary>
    private void ExtractFrustumPlanes()
    {
        Matrix4x4 vpMatrix = mainCamera.projectionMatrix * mainCamera.worldToCameraMatrix;

        // Near plane
        frustumPlanes[0] = new Plane(
            vpMatrix.GetRow(2) + vpMatrix.GetRow(3),
            -vpMatrix.m23 - vpMatrix.m33
        );

        // Far plane
        frustumPlanes[1] = new Plane(
            -vpMatrix.GetRow(2) + vpMatrix.GetRow(3),
            vpMatrix.m23 - vpMatrix.m33
        );

        // Left plane
        frustumPlanes[2] = new Plane(
            vpMatrix.GetRow(0) + vpMatrix.GetRow(3),
            -vpMatrix.m03 - vpMatrix.m33
        );

        // Right plane
        frustumPlanes[3] = new Plane(
            -vpMatrix.GetRow(0) + vpMatrix.GetRow(3),
            vpMatrix.m03 - vpMatrix.m33
        );

        // Top plane
        frustumPlanes[4] = new Plane(
            -vpMatrix.GetRow(1) + vpMatrix.GetRow(3),
            vpMatrix.m13 - vpMatrix.m33
        );

        // Bottom plane
        frustumPlanes[5] = new Plane(
            vpMatrix.GetRow(1) + vpMatrix.GetRow(3),
            -vpMatrix.m13 - vpMatrix.m33
        );
    }

    /// <summary>
    /// Frustum을 포함하는 AABB 계산
    /// 공간 해시 쿼리 범위 결정
    /// </summary>
    private void CalculateFrustumBounds()
    {
        Vector3 camPos = mainCamera.transform.position;
        float orthoHeight = mainCamera.orthographicSize;
        float orthoWidth = orthoHeight * mainCamera.aspect;

        frustumMin = camPos - new Vector3(orthoWidth, orthoHeight, 0);
        frustumMax = camPos + new Vector3(orthoWidth, orthoHeight, 0);
    }

    /// <summary>
    /// 공간 해시 그리드 쿼리
    /// Frustum 교차 셀의 타일만 검사 (조기 종료 최적화)
    /// </summary>
    private void QueryVisibleTiles()
    {
        visibleTileCount = 0;
        culledTileCount = 0;

        // Frustum 범위의 그리드 셀 범위 계산
        int minGridX = Mathf.FloorToInt(frustumMin.x / gridCellSize);
        int maxGridX = Mathf.CeilToInt(frustumMax.x / gridCellSize);
        int minGridY = Mathf.FloorToInt(frustumMin.y / gridCellSize);
        int maxGridY = Mathf.CeilToInt(frustumMax.y / gridCellSize);

        HashSet<int> queriedHashes = new HashSet<int>();

        // 범위 내 그리드 셀 순회
        for (int gx = minGridX; gx <= maxGridX; gx++)
        {
            for (int gy = minGridY; gy <= maxGridY; gy++)
            {
                int hash = MortonEncode(gx, gy);

                if (spatialHashGrid.TryGetValue(hash, out List<TileData> cellTiles))
                {
                    queriedHashes.Add(hash);

                    // 셀 내 타일 검사
                    foreach (TileData tile in cellTiles)
                    {
                        if (IsBoundsInFrustum(tile.bounds))
                        {
                            tile.renderer.enabled = true;
                            visibleTileCount++;
                        }
                        else
                        {
                            tile.renderer.enabled = false;
                            culledTileCount++;
                        }
                    }
                }
            }
        }
    }

    /// <summary>
    /// AABB와 Frustum 교차 검사
    /// 6개 평면 모두와의 교차 판정
    /// </summary>
    private bool IsBoundsInFrustum(Bounds bounds)
    {
        Vector3 extents = bounds.extents;
        Vector3 center = bounds.center;

        for (int i = 0; i < 6; i++)
        {
            // 평면의 법선 방향 최대 거리
            float maxDist = Mathf.Abs(frustumPlanes[i].normal.x * extents.x) +
                           Mathf.Abs(frustumPlanes[i].normal.y * extents.y) +
                           Mathf.Abs(frustumPlanes[i].normal.z * extents.z);

            // 중심에서 평면까지의 거리
            float dist = Vector3.Dot(frustumPlanes[i].normal, center) + frustumPlanes[i].distance;

            // AABB가 평면 뒤에 완전히 위치하면 Frustum 외부
            if (dist < -maxDist)
                return false;
        }

        return true;
    }

    /// <summary>
    /// 동적 업데이트 지원 (타일 추가/제거 시)
    /// </summary>
    public void InvalidateSpatialGrid()
    {
        spatialHashGrid.Clear();
        InitializeSpatialGrid();
    }
}
```

