## 2. Unity C# 구현

```csharp
using System.Collections.Generic;
using UnityEngine;

[RequireComponent(typeof(Camera))]
public class StochasticTilemapCulling : MonoBehaviour
{
    [SerializeField] private SpriteRenderer[] tileSprites;
    [SerializeField] private float cullingMargin = 1.0f;       // AABB 확장 마진
    [SerializeField] private float probabilityThreshold = 0.6f;
    [SerializeField] private int cellSize = 8;                 // 공간 해싱 셀 크기
    [SerializeField] private float velocityLookahead = 0.25f;  // 예측 프레임 시간(s)

    private Camera cam;
    private readonly Plane[] frustumPlanes = new Plane[6];
    private Dictionary<Vector2Int, List<SpriteRenderer>> spatialHash;
    private Vector3 previousCameraPos;

    void Awake()
    {
        cam = GetComponent<Camera>();
        BuildSpatialHash();
        previousCameraPos = cam.transform.position;
    }

    private void BuildSpatialHash()
    {
        spatialHash = new Dictionary<Vector2Int, List<SpriteRenderer>>();
        foreach (var sr in tileSprites)
        {
            if (sr == null) continue;
            Vector2Int key = ToCellKey(sr.transform.position);
            if (!spatialHash.TryGetValue(key, out var bucket))
            {
                bucket = new List<SpriteRenderer>();
                spatialHash[key] = bucket;
            }
            bucket.Add(sr);
        }
    }

    private Vector2Int ToCellKey(Vector3 worldPos)
    {
        return new Vector2Int(
            Mathf.FloorToInt(worldPos.x / cellSize),
            Mathf.FloorToInt(worldPos.y / cellSize));
    }

    void LateUpdate()
    {
        GeometryUtility.CalculateFrustumPlanes(cam, frustumPlanes);

        Vector3 camPos = cam.transform.position;
        Vector3 camVelocity = (camPos - previousCameraPos) / Mathf.Max(Time.deltaTime, 1e-5f);
        previousCameraPos = camPos;

        Vector3 predictedPos = camPos + camVelocity * velocityLookahead;
        float orthoH = cam.orthographicSize;
        float orthoW = orthoH * cam.aspect;
        float maxDist = Mathf.Sqrt(orthoW * orthoW + orthoH * orthoH) + cellSize;

        foreach (var kv in spatialHash)
        {
            Vector3 center = new Vector3(
                (kv.Key.x + 0.5f) * cellSize,
                (kv.Key.y + 0.5f) * cellSize, 0f);

            Bounds cellAABB = new Bounds(center, new Vector3(cellSize, cellSize, 1f));
            cellAABB.Expand(cullingMargin);

            // 1) 결정론적 프러스텀-AABB 교차 테스트
            bool intersectsFrustum = GeometryUtility.TestPlanesAABB(frustumPlanes, cellAABB);

            // 2) 카메라 속도 벡터 기반 진입 확률 P(visible | t+Δt)
            float dist = Vector3.Distance(predictedPos, cellAABB.center);
            float enterProbability = Mathf.Clamp01(1f - dist / maxDist);

            bool render = intersectsFrustum || (enterProbability >= probabilityThreshold);

            var bucket = kv.Value;
            for (int i = 0; i < bucket.Count; ++i)
            {
                var sr = bucket[i];
                if (sr != null && sr.enabled != render)
                    sr.enabled = render;
            }
        }
    }
}
```

