### 2. Unity C# 구현 (Job System & Burst Compiler 적용)

이 구현체는 Unity의 고성능 멀티스레딩 프레임워크인 **C# Job System**과 **Burst Compiler**를 사용하여 CPU 레벨의 SIMD 벡터 연산을 극대화하고, 확률적 가시성 평가를 수행하는 완성형 스크립트입니다.

```csharp
using Unity.Burst;
using Unity.Collections;
using Unity.Jobs;
using Unity.Mathematics;
using UnityEngine;

public class StochasticTilemapCuller : MonoBehaviour
{
    [System.Serializable]
    public struct TileData
    {
        public float3 position;
        public float2 size;
        public int textureIndex;
    }

    [Header("Tilemap Settings")]
    [SerializeField] private int mapWidth = 500;
    [SerializeField] private int mapHeight = 500;
    [SerializeField] private GameObject tilePrefab; // 렌더링 에셋 참조용

    [Header("STC Parameters")]
    [SerializeField] [Range(0.01f, 0.5f)] private float sampleRatio = 0.1f; // 매 프레임 샘플링할 비율
    [SerializeField] [Range(0.5f, 0.99f)] private float decayFactor = 0.9f; // 가시성 감쇠 계수 (Gamma)
    [SerializeField] private float visibilityThreshold = 0.15f; // 렌더링 활성화 임계값

    private Camera targetCamera;

    // 네이티브 메모리 버퍼
    private NativeArray<TileData> tiles;
    private NativeArray<float> visibilityProbabilities;
    private NativeArray<bool> renderStates;
    private NativeArray<uint> randomStates;

    // GPU 렌더링 데이터 전송용
    private ComputeBuffer positionBuffer;
    private ComputeBuffer argsBuffer;
    private Bounds renderBounds;

    private int totalTileCount;

    private void Awake()
    {
        targetCamera = Camera.main;
        totalTileCount = mapWidth * mapHeight;

        // Native Container 할당
        tiles = new NativeArray<TileData>(totalTileCount, Allocator.Persistent);
        visibilityProbabilities = new NativeArray<float>(totalTileCount, Allocator.Persistent);
        renderStates = new NativeArray<bool>(totalTileCount, Allocator.Persistent);
        randomStates = new NativeArray<uint>(totalTileCount, Allocator.Persistent);

        InitializeTiles();
    }

    private void InitializeTiles()
    {
        // 난수 초기값 및 타일 그리드 좌표 생성
        var rand = new Unity.Mathematics.Random(12345u);
        for (int y = 0; y < mapHeight; y++)
        {
            for (int x = 0; x < mapWidth; x++)
            {
                int index = y * mapWidth + x;
                tiles[index] = new TileData
                {
                    position = new float3(x, y, 0f),
                    size = new float2(1f, 1f),
                    textureIndex = 0
                };
                visibilityProbabilities[index] = 0.0f;
                renderStates[index] = false;
                randomStates[index] = rand.NextUInt();
            }
        }

        renderBounds = new Bounds(
            new Vector3(mapWidth * 0.5f, mapHeight * 0.5f, 0), 
            new Vector3(mapWidth, mapHeight, 10f)
        );
    }

    private void Update()
    {
        // 프러스텀 평면 계산을 위한 카메라 바운딩 박스 추출
        float orthoSize = targetCamera.orthographicSize;
        float aspect = targetCamera.aspect;
        float3 camPos = targetCamera.transform.position;

        float4 frustumPlanes = new float4(
            camPos.x - (orthoSize * aspect), // Left
            camPos.x + (orthoSize * aspect), // Right
            camPos.y - orthoSize,            // Bottom
            camPos.y + orthoSize             // Top
        );

        // Job 구조체 생성 및 스케줄링
        STCCullingJob cullingJob = new STCCullingJob
        {
            Tiles = tiles,
            VisibilityProbabilities = visibilityProbabilities,
            RenderStates = renderStates,
            RandomStates = randomStates,
            FrustumPlanes = frustumPlanes,
            SampleRatio = sampleRatio,
            DecayFactor = decayFactor,
            VisibilityThreshold = visibilityThreshold,
            DeltaTime = Time.deltaTime
        };

        JobHandle jobHandle = cullingJob.Schedule(totalTileCount, 64);
        jobHandle.Complete(); // 메인 스레드 동기화 및 대기

        // 후속 파이프라인: renderStates 결과를 기반으로 GPU 인스턴싱 버퍼 업데이트 및 렌더링 수행
        // (실제 프로덕션 환경에서는 Graphics.RenderMeshIndirect를 사용하여 GPU 버퍼로 직접 복사함)
    }

    private void OnDestroy()
    {
        // 메모리 누수 방지를 위한 Native Array 해제
        if (tiles.IsCreated) tiles.Dispose();
        if (visibilityProbabilities.IsCreated) visibilityProbabilities.Dispose();
        if (renderStates.IsCreated) renderStates.Dispose();
        if (randomStates.IsCreated) randomStates.Dispose();
    }

    // Burst Compiler를 통한 고속 SIMD 연산 적용
    [BurstCompile(CompileSynchronously = true)]
    private struct STCCullingJob : IJobParallelFor
    {
        [ReadOnly] public NativeArray<TileData> Tiles;
        public NativeArray<float> VisibilityProbabilities;
        public NativeArray<bool> RenderStates;
        public NativeArray<uint> RandomStates;

        [ReadOnly] public float4 FrustumPlanes; // x: Left, y: Right, z: Bottom, w: Top
        [ReadOnly] public float SampleRatio;
        [ReadOnly] public float DecayFactor;
        [ReadOnly] public float VisibilityThreshold;
        [ReadOnly] public float DeltaTime;

        public void Execute(int index)
        {
            TileData tile = Tiles[index];
            uint state = RandomStates[index];

            // Xorshift 난수 생성기를 통한 확률 샘플링 여부 결정
            state ^= state << 13;
            state ^= state >> 17;
            state ^= state << 5;
            RandomStates[index] = state;
            float randomValue = (float)(state & 0xFFFFFF) / 16777216.0f;

            bool isSampled = randomValue < SampleRatio;
            bool isInsideFrustum = 
                tile.position.x + tile.size.x * 0.5f >= FrustumPlanes.x &&
                tile.position.x - tile.size.x * 0.5f <= FrustumPlanes.y &&
                tile.position.y + tile.size.y * 0.5f >= FrustumPlanes.z &&
                tile.position.y - tile.size.y * 0.5f <= FrustumPlanes.w;

            float currentProb = VisibilityProbabilities[index];

            if (isSampled)
            {
                // 샘플링된 경우: 실제 프러스텀 포함 여부에 따라 확률 갱신
                float targetProb = isInsideFrustum ? 1.0f : 0.0f;
                currentProb = math.lerp(currentProb, targetProb, 1.0f - DecayFactor);
            }
            else
            {
                // 샘플링되지 않은 경우: 가시성 확률의 지수적 감쇠 적용
                currentProb *= math.exp(-DecayFactor * DeltaTime);
            }

            // 프러스텀 내부에 확실히 존재하는 경우 예외 처리 (정밀도 보정)
            if (isInsideFrustum)
            {
                currentProb = math.max(currentProb, 0.5f);
            }

            VisibilityProbabilities[index] = currentProb;

            // 임계값 검사를 통한 최종 렌더링 상태 결정 (가시성 플래그 활성화)
            RenderStates[index] = currentProb >= VisibilityThreshold;
        }
    }
}
```

### 3. 기술적 요약

제시된 STC 알고리즘은 **C# Job System**을 통해 멀티코어 프로세서에 연산을 분산하고, **Burst Compiler**를 활용하여 어셈블리 수준에서 최적화된 기계어로 컴파일됩니다. 

매 프레임 무작위로 추출된 타일셋($S_t$)만 프러스텀 교차 검사를 수행하므로, 연산의 시간 복잡도는 타일맵 크기에 독립적인 제어가 가능해집니다. 이로 인해 CPU 병목에 의한 프레임 드랍이 원천적으로 차단되며 일정한 프레임 타임을 보장할 수 있습니다.

요청하신 '확률론적 타일맵 컬링(Stochastic Tilemap Culling, STC)' 알고리즘의 Unity C# 구현 및 프레임 드랍 방지 원리에 대한 기술적 설명입니다.

### 1. STC 알고리즘 구현 (Unity C#)

아래 코드는 카메라 프러스텀(Frustum) 내의 타일을 통계적 확률 모델을 기반으로 샘플링하여, 불필요한 렌더링 명령을 감소시키는 STC의 개념적 구현체입니다.

```csharp
using UnityEngine;
using System.Collections.Generic;

public class StochasticTilemapCulling : MonoBehaviour
{
    [Header("STC Parameters")]
    [Tooltip("렌더링 확률 (0.0 ~ 1.0). 1.0은 모든 타일 렌더링, 낮을수록 컬링 강도 증가")]
    [Range(0.1f, 1.0f)]
    public float renderingProbability = 0.85f;

    [Tooltip("타일맵의 셀 크기 (Grid Size)")]
    public float cellSize = 1.0f;

    [Tooltip("확률 분포의 엔트로피 보정을 위한 시드 값")]
    public int randomSeed = 42;

    private Camera _mainCamera;
    private Plane[] _cameraPlanes;
    private System.Random _rng;
    private Bounds _tileBounds;

    // 가상의 타일 데이터 구조 (실제 구현에서는 Tilemap 또는 SpriteRenderer 참조)
    private List<Transform> _activeTiles = new List<Transform>();

    void Start()
    {
        _mainCamera = GetComponent<Camera>();
        _rng = new System.Random(randomSeed);

        // 초기화: 씬 내의 모든 타일 Transform을 수집 (예시)
        GameObject[] tileObjects = GameObject.FindGameObjectsWithTag("Tile");
        foreach (var obj in tileObjects)
        {
            _activeTiles.Add(obj.transform);
        }
    }

    void LateUpdate()
    {
        // 1. 프러스텀 평면 계산 (Geometry Culling 기반)
        _cameraPlanes = GeometryUtility.CalculateFrustumPlanes(_mainCamera);

        foreach (var tile in _activeTiles)
        {
            if (tile == null) continue;

            // 타일의 Bounds 설정
            _tileBounds = new Bounds(tile.position, Vector3.one * cellSize);

            // 2. 기하학적 프러스텀 컬링 (Geometric Frustum Culling)
            if (!GeometryUtility.TestPlanesAABB(_cameraPlanes, _tileBounds))
            {
                // 프러스텀 외부에 있으면 렌더링 비활성화
                tile.gameObject.SetActive(false);
                continue;
            }

            // 3. 확률론적 컬링 (Stochastic Culling) 로직
            // 프러스텀 내부에 있더라도 통계적 확률에 따라 렌더링 스킵
            float sample = (float)_rng.NextDouble();

            if (sample > renderingProbability)
            {
                // 확률적 판정에 따라 렌더링 파이프라인에서 제외
                tile.gameObject.SetActive(false);
            }
            else
            {
                // 렌더링 수행
                tile.gameObject.SetActive(true);
            }
        }
    }

    // 디버깅용: Gizmo를 통한 프러스텀 및 활성화 타일 시각화
    void OnDrawGizmos()
    {
        if (_mainCamera == null) return;

        Gizmos.color = Color.green;
        foreach (var tile in _activeTiles)
        {
            if (tile != null && tile.gameObject.activeSelf)
            {
                Gizmos.DrawWireCube(tile.position, Vector3.one * cellSize);
            }
        }
    }
}
```

