### 2. 프레임 드랍(Frame Drop) 방지 원리

STC 알고리즘은 렌더링 파이프라인의 **Draw Call** 과정에 부과되는 부하를 통계적으로 분산 및 감소시킴으로써 프레임 드랍을 방지합니다. 그 기술적 원리는 다음과 같습니다.

#### 2.1. 렌더링 병목(Bottleneck)의 완화
2D 탑다운 게임에서 맵이 광대해질 경우, 카메라 프러스텀 내에 존재하는 스프라이트의 수가 CPU에서 GPU로 명령을 전달하는 한계치(Draw Call Limit)를 초과할 수 있습니다. STC는 프러스텀 내의 모든 오브젝트를 렌더링하는 대신, `renderingProbability` 파라미터에 의해 정해진 비율만큼만 GPU로 전송합니다. 이는 단위 프레임당 처리해야 하는 드로우 콜(Draw Call)의 절대적 수량을 감소시켜 CPU의 명령 처리 대기 시간을 줄이고, GPU의 래스터화(Rasterization) 작업량을 완화합니다.

#### 2.2. 계산 비용의 상수 시간(Constant Time) 유지
전통적인 컬링 기법은 오클루전(Occlusion) 여부를 판별하기 위해 추가적인 지오메트리 연산이나 레이캐스팅(Raycasting)을 수행하여, 오브젝트가 많아질수록 계산 복잡도가 선형적으로 증가(O(N))하는 문제가 있습니다. 반면, STC는 의사 난수 생성(Pseudo-Random Number Generation)을 통한 단순 비교 연산만 수행하므로, 오클루전 판별에 드는 오버헤드가 미미합니다. 이로 인해 CPU의 프레임 처리 시간(Budget)을 렌더링 명령 생성이 아닌 게임 로직 연산에 할당할 수 있게 됩니다.

#### 2.3. 일시적 렌더링 스킵에 의한 프레임 타임 평활화
STC는 특정 타일이 특정 프레임에서 렌더링되지 않을 확률을 가집니다. 이는 단일 프레임 내에서의 렌더링 부하가 급격히 치솟는 현상(Spike)을 방지하는 효과가 있습니다. 만약 화면에 수천 개의 스프라이트가 동시에 존재하여 프레임 타임이 16ms(60fps 기준)를 초과할 위험이 발생하면, STC는 일부 스프라이트의 렌더링을 확률적으로 생략하여 전체 프레임 타임을 임계치 이하로 강제로 억제합니다. 이는 렌더링 품질의 일시적 저하를 감수하더라도 애플리케이션의 실시간성(Real-time performance)을 유지하는 핵심 메커니즘입니다.

#### 2.4. GPU 상태 변경(State Change) 최소화
다수의 스프라이트를 렌더링할 때 발생하는 텍스처 바인딩(Texture Binding)이나 셰이더 변경(Shader Switch) 같은 GPU 상태 변경 작업은 비용이 높습니다. STC를 통해 렌더링 대상을 줄이면, 결과적으로 파이프라인 상에서 발생하는 상태 변경의 빈도를 감소시키는 효과를 가져와 렌더링 파이프라인의 스톨(Stall)을 방지합니다.

다음은 Unity C#을 활용한 확률론적 타일맵 컬링(Stochastic Tilemap Culling, STC) 구현 코드 및 프레임 드랍 방지 원리에 대한 설명입니다.

### 1. 확률론적 타일맵 컬링(StC) 구현

STC는 정확한 컬링(Frustum Culling)을 수행하는 데 드는 연산량을 줄이기 위해, 타일맵의 각 셀(또는 채널)이 프러스텀 내에 있는지 여부를 **확률적 샘플링**을 통해 판단합니다.

```csharp
using UnityEngine;
using System.Collections.Generic;

public class STCCulling : MonoBehaviour
{
    // 프러스텀(Frustum)을 계산할 주요 카메라
    public Camera targetCamera;

    // 컬링할 타일맵 채널 (Tilemap의 Layer 또는 Channel)
    public TilemapBase targetTilemap;

    // 샘플링을 수행할 셀의 크기 (픽셀 단위)
    public float samplingResolution = 32f;

    // 프러스텀의 좌표 평면 (XZ 평면)
    private Vector3[] frustumCorners;
    private Plane[] frustumPlanes;

    private void Awake()
    {
        if (targetCamera == null) targetCamera = Camera.main;

        // 프러스텀의 4개 꼭짓점 계산
        frustumCorners = new Vector3[4];
        targetCamera.CalculateFrustumCorners(new Rect(0f, 0f, 1f, 1f), targetCamera.farClipPlane, Camera.MonoOrStereoscopicCamera.Mono, frustumCorners);

        // 프러스텀 평면 계산 (닫힌 도형의 표면)
        frustumPlanes = GeometryUtility.CalculateFrustumPlanes(targetCamera);
    }

    private void Update()
    {
        // 타일맵의 경계(Bounds)를 가져옴
        Bounds mapBounds = targetTilemap.localBounds;

        // STC 수행
        bool isCulled = PerformSTC(mapBounds);

        // 결과에 따라 렌더링 활성화/비활성화
        if (isCulled)
        {
            targetTilemap.gameObject.SetActive(false);
        }
        else
        {
            targetTilemap.gameObject.SetActive(true);
        }
    }

    /// <summary>
    /// 확률론적 컬링 로직 수행
    /// </summary>
    private bool PerformSTC(Bounds bounds)
    {
        // 1. 타일맵의 경계가 카메라의 시야(View Frustum)를 벗어난 경우 즉시 컬링 처리
        if (!GeometryUtility.TestPlanesAABB(frustumPlanes, bounds))
        {
            return true;
        }

        // 2. 타일맵의 셀(Grid) 크기 계산
        // 타일맵의 Bounds를 samplingResolution로 나누어 셀 개수 산출
        int cellsX = Mathf.CeilToInt(bounds.size.x / samplingResolution);
        int cellsZ = Mathf.CeilToInt(bounds.size.z / samplingResolution);

        // 3. 샘플링 로직
        // 셀의 개수가 너무 많으면(예: 넓은 평지) 성능 저하 방지를 위해 전수 조사 대신 샘플링 수행
        if (cellsX * cellsZ > 256) // 임계값 조절 가능
        {
            return SampleSTC(bounds, cellsX, cellsZ);
        }

        // 4. 전수 조사 (정확도 100%)
        // 셀이 적으면 정확한 컬링을 수행하여 불필요한 표면 생성 방지
        return NaiveCulling(bounds, cellsX, cellsZ);
    }

    /// <summary>
    /// 확률적 샘플링을 통한 컬링 (STC 핵심 로직)
    /// </summary>
    private bool SampleSTC(Bounds bounds, int cellsX, int cellsZ)
    {
        // 샘플링 비율 설정 (예: 1/4 셀만 샘플링)
        float sampleRate = 0.25f;

        // 샘플링할 셀의 개수
        int sampleCount = Mathf.CeilToInt(cellsX * cellsZ * sampleRate);

        for (int i = 0; i < sampleCount; i++)
        {
            // 무작위 위치 선정
            Vector3 randomPos = new Vector3(
                Random.Range(bounds.min.x, bounds.max.x),
                bounds.min.y, // Y축은 고정하여 2D 레이어에서의 Z 축(깊이) 효과만 취함
                Random.Range(bounds.min.z, bounds.max.z)
            );

            // 선정된 위치가 프러스텀 내에 있는지 확인
            if (IsInsideFrustum(randomPos))
            {
                return false; // 하나라도 프러스텀 내에 존재하면 렌더링 필요
            }
        }

        return true; // 샘플링된 모든 위치가 프러스텀 외부
    }

    /// <summary>
    /// 개별 좌표가 프러스텀 내부에 있는지 확인하는 유틸리티
    /// </summary>
    private bool IsInsideFrustum(Vector3 point)
    {
        // 프러스텀 평면들과 점의 거리를 계산하여 내부 여부 판단
        foreach (Plane plane in frustumPlanes)
        {
            // 점이 평면의 반대 방향에 있으면 프러스텀 외부
            if (plane.GetDistanceToPoint(point) < 0)
            {
                return false;
            }
        }
        return true;
    }

    /// <summary>
    /// 전수 조사를 통한 컬링
    /// </summary>
    private bool NaiveCulling(Bounds bounds, int cellsX, int cellsZ)
    {
        // 모든 셀의 중심점을 계산하여 프러스텀 테스트 수행
        for (int x = 0; x < cellsX; x++)
        {
            for (int z = 0; z < cellsZ; z++)
            {
                Vector3 cellCenter = new Vector3(
                    bounds.min.x + (x + 0.5f) * samplingResolution,
                    bounds.min.y,
                    bounds.min.z + (z + 0.5f) * samplingResolution
                );

                if (!IsInsideFrustum(cellCenter))
                {
                    return true; // 하나라도 외부
                }
            }
        }
        return false; // 모두 내부
    }
}
```

