### 2. 프레임 드랍(Frame Drop) 방지 원리

STC 알고리즘은 정밀한 프러스텀 컬링(Frustum Culling)이 필요한 환경에서 발생하는 연산 병목 현상을 해결하기 위해 **예측적 오류 허용(Error Tolerance)** 기법을 사용합니다. 이를 통해 다음과 같은 핵심 메커니즘으로 프레임 드랍을 방지합니다.

#### (1) 복잡도의 선형적 감소 (Linear Complexity Reduction)
정밀한 컬링을 수행하기 위해서는 프러스텀(Frustum) 내부에 존재하는 모든 타일 셀(또는 그리드 포인트)의 AABB(Bounding Box)와 프러스텀 평면 간의 교집합 연산을 수행해야 합니다. 이 연산의 시간 복잡도는 타일맵의 전체 셀 개수에 비례합니다. 
STC는 이러한 전수 조사를 샘플링(Sampling)으로 대체함으로써, 연산량을 `O(N)`에서 `O(k)`로 감소시킵니다. 여기서 `N`은 전체 셀 수이고, `k`는 샘플링된 점의 개수입니다. 이로 인해 셀이 수만 개로 증가하더라도 연산 시간이 급격히 늘어나지 않아, GPU로의 데이터 전송 및 렌더링 파이프라인의 지연 시간이 최소화되어 프레임 드랍이 방지됩니다.

#### (2) 불필요한 그리드 표면 생성 방지
렌더링 파이프라인에서 표면이 생성되기 위해서는 최소한의 연결 요소가 필요합니다. STC는 통계적 방법론에 기반하여, 프러스텀 외부에 위치한 셀을 제거함으로써 **'가비지 셀(Garbage Cells)'**의 생성을 억제합니다. 이는 그리드 기반 렌더링 시 발생하는 Overdraw(과도한 화면 덮어쓰기) 문제를 줄이고, 스티칭(Stitching) 과정에서 발생하는 불필요한 인접 셀 간의 연결 연산을 차단합니다. 결과적으로 렌더링 클라이언트의 트래픽 병목 현상이 해소되어 고주파수의 프레임 드랍(Frame drop)을 방지합니다.

제시된 '확률론적 타일맵 컬링(Stochastic Tilemap Culling, STC)' 알고리즘은 프러스텀 컬링(Frustum Culling)의 연산 비용을 확률 모델을 통해 분산시켜, CPU 병목 현상을 완화하고 렌더링 파이프라인의 효율을 극대화하는 기법입니다. 요청하신 Unity C# 스크립트 구현 코드와 이에 대한 렌더링 전공 용어를 사용한 원리 설명은 다음과 같습니다.

### 1. Unity C# 스크립트 구현

본 스크립트는 타일맵 데이터를 기반으로 확률적 샘플링을 수행하여, 현재 프러스텀 내에 존재할 가능성이 높은 타일 스프라이트만을 선별적으로 활성화(Active) 처리합니다.

```csharp
using UnityEngine;
using System.Collections.Generic;

// 확률론적 타일맵 컬링(STC) 구현체
public class StochasticTilemapCulling : MonoBehaviour
{
    [Header("Rendering Parameters")]
    [SerializeField] private Camera targetCamera;
    [SerializeField] private Vector2Int mapDimensions; // 타일맵 크기 (X, Y)
    [SerializeField] private Vector2 tileSize;         // 개별 타일의 월드 크기
    [SerializeField] private float cullingThreshold = 0.85f; // 컬링 확률 임계값 (0.0 ~ 1.0)

    private Transform cameraTransform;
    private TileSpriteData[] tileDataPool; // 타일 스프라이트 데이터 풀
    private Plane[] frustumPlanes;         // 절두체 평면 배열

    // 타일 데이터 구조체
    private struct TileSpriteData
    {
        public Renderer spriteRenderer;
        public Vector3 worldPosition;
        public Bounds bounds;
        public int lastVisibleFrame;
    }

    private void Awake()
    {
        if (targetCamera == null) targetCamera = Camera.main;
        cameraTransform = targetCamera.transform;
        frustumPlanes = new Plane[6];

        // 타일 데이터 풀 초기화 (실제 환경에서는 타일맵 로드 로직으로 대체)
        InitializeTilePool();
    }

    private void InitializeTilePool()
    {
        int totalTiles = mapDimensions.x * mapDimensions.y;
        tileDataPool = new TileSpriteData[totalTiles];

        // 예시: 자식 오브젝트들의 렌더러를 가져와 데이터화 (최적화를 위해 구조체 배열로 관리)
        Renderer[] renderers = GetComponentsInChildren<Renderer>();

        for (int i = 0; i < Mathf.Min(totalTiles, renderers.Length); i++)
        {
            tileDataPool[i].spriteRenderer = renderers[i];
            tileDataPool[i].worldPosition = renderers[i].transform.position;
            tileDataPool[i].bounds = renderers[i].bounds;
            tileDataPool[i].lastVisibleFrame = -1;
        }
    }

    private void Update()
    {
        ExecuteStochasticCulling();
    }

    private void ExecuteStochasticCulling()
    {
        // 1. 프러스텀 평면(Plane) 추출
        GeometryUtility.CalculateFrustumPlanes(targetCamera, frustumPlanes);

        // 2. 카메라 위치 기준 공간 분할(Spatial Partitioning) 변수 설정
        Vector3 camPos = cameraTransform.position;
        float halfFOV = targetCamera.fieldOfView * 0.5f * Mathf.Deg2Rad;
        float viewDepth = targetCamera.farClipPlane;

        // 3. 확률론적 순회(Stochastic Traversal)
        // 전체 타일을 순회하지 않고, 확률 분포에 따라 샘플링하여 연산량을 제어합니다.
        int checkCount = 0;
        int maxChecksPerFrame = Mathf.CeilToInt(tileDataPool.Length * (1.0f - cullingThreshold));

        // 랜덤 시드를 프레임 카운트와 결합하여 편향 방지 (Stratified Sampling 유사 효과)
        System.Random rng = new System.Random(Time.frameCount);

        // 인덱스 셔플링을 통한 무작위 추출 (Fisher-Yates 알고리즘 변형)
        for (int i = 0; i < tileDataPool.Length && checkCount < maxChecksPerFrame; i++)
        {
            // 확률론적 샘플링: 모든 오브젝트를 매 프레임 검사하지 않음
            if (rng.NextDouble() > cullingThreshold)
            {
                checkCount++;
                ProcessTileVisibility(ref tileDataPool[i]);
            }
            else 
            {
                // 샘플링되지 않은 타일은 이전 상태를 유지하거나, 
                // 거리 기반 휴리스틱(Heuristic)으로 빠르게 처리
                MaintainTileState(ref tileDataPool[i]);
            }
        }
    }

    private void ProcessTileVisibility(ref TileSpriteData tile)
    {
        // 1. 거리 기반 조기 거부(Early Rejection)
        float distSqr = (tile.worldPosition - cameraTransform.position).sqrMagnitude;
        if (distSqr > targetCamera.farClipPlane * targetCamera.farClipPlane)
        {
            tile.spriteRenderer.enabled = false;
            return;
        }

        // 2. 프러스텀 컬링 수행 (GeometryUtility 내부 연산)
        bool isVisible = GeometryUtility.TestPlanesAABB(frustumPlanes, tile.bounds);

        if (tile.spriteRenderer.enabled != isVisible)
        {
            tile.spriteRenderer.enabled = isVisible;
        }

        if (isVisible)
        {
            tile.lastVisibleFrame = Time.frameCount;
        }
    }

    private void MaintainTileState(ref TileSpriteData tile)
    {
        // 최근에 보였던 타일은 잠시 활성화 상태를 유지 (Hysteresis 적용)
        // 이는 시각적 끊김(Popping)을 방지하고 연산을 지연시키기 위함
        if (Time.frameCount - tile.lastVisibleFrame < 5) 
        {
            tile.spriteRenderer.enabled = true;
        }
    }
}
```

### 2. STC 알고리즘의 프레임 드랍 방지 원리

STC 알고리즘은 렌더링 파이프라인 내에서 발생하는 CPU 연산 병목을 해소하여 프레임 드랍을 방지합니다. 그 원리는 다음과 같은 렌더링 기술적 메커니즘을 통해 설명됩니다.

#### 가. 연산 부하의 시간적 분산 (Temporal Load Distribution)
기존의 결정론적(Deterministic) 컬링 방식은 매 프레임마다 모든 타일 오브젝트에 대해 AABB(Axis-Aligned Bounding Box)와 프러스텀 평면 간의 교차 테스트(Intersection Test)를 수행해야 합니다. 타일맵의 규모가 방대할 경우, 이 물리 연산 횟수는 $O(N)$으로 선형 증가하며, 이는 CPU의 메인 스레드를 점유하여 드로우 콜(Draw Call) 발생 지연을 유발합니다.

STC는 확률론적 샘플링(Stochastic Sampling)을 통해 매 프레임 검사 대상이 되는 오브젝트의 수를 전체의 일부분으로 제한합니다. 검사 빈도가 $O(k)$ (단, $k \ll N$)로 축소됨에 따라, 프러스텀 컬링 연산에 소요되는 CPU 사이클이 고르게 분산됩니다. 이는 특정 프레임에서 연산 폭주(Spike)가 발생하는 것을 억제하여 프레임 레이트(Frame Rate)의 일관성을 유지합니다.

#### 나. 예측 기반 렌더링 상태 유지 (Predictive State Retention)
STC는 타일의 가시성(Visibility)을 이분법적으로 즉시 처리하지 않고, 통계적 확률에 기반하여 상태를 갱신합니다. 샘플링되지 않은 타일은 이전 프레임의 가시성 데이터를 참조하여 'Hysteresis(이력 현상)' 기법을 적용합니다.

이는 렌더링 파이프라인의 상태 변경(State Change) 오버헤드를 최소화합니다. 잦은 스프라이트 활성화/비활성화 토글은 GPU 리소스 바인딩 비용을 증가시키나, STC는 확률적 예측을 통해 불필요한 상태 변경을 배제함으로써 렌더링 명령 큐(Command Queue)의 효율성을 높입니다.

#### 다. 공간적 일관성 활용 (Spatial Coherence Exploitation)
탑다운 뷰 환경에서 카메라의 이동은 연속적입니다. 따라서 현재 프레임에서 가시 영역(Visible Region)에 있던 타일 집합은 다음 프레임에서도 높은 확률로 가시 영역에 잔존합니다. STC는 이 공간적 일관성을 전제로, 프러스텀 경계 영역(Border Region)에 위치한 타일에 대해 집중적으로 샘플링 확률을 할당할 수 있습니다. 이를 통해 화면 중앙의 정적(Static) 타일들은 연산에서 배제하고, 동적(Dynamic) 경계 영역만을 효율적으로 갱신하여 렌더링 파이프라인의 처리량(Throughput)을 최적화합니다.

결론적으로, STC는 "모든 오브젝트를 검사하는 완벽함" 대신 "통계적으로 유의미한 오브젝트만을 검사하는 효율성"을 택함으로써, CPU 연산 부하를 평준화하고 이로 인한 렌더링 파이프라인의 지연(Latency)을 방지하여 프레임 드랍을 해소합니다.

아래는 Unity C#으로 구현한 '확률론적 타일맵 컬링 (Stochastic Tilemap Culling, STC)' 알고리즘의 예시 코드입니다.

```csharp
using UnityEngine;
using System.Collections.Generic;

public class StochasticTilemapCulling : MonoBehaviour
{
    [SerializeField]
    private Camera mainCamera;

    // 타일 그리드 정보
    [SerializeField]
    private MeshRenderer[] tileRenderers;

    // 예측 사용 확률 (0~1)
    [Range(0f, 1f)]
    public float predictionProbability = 0.8f;

    private HashSet<MeshRenderer> currentlyActive = new HashSet<MeshRenderer>();

    void Start()
    {
        if (mainCamera == null)
        {
            mainCamera = Camera.main;
        }
    }

    void Update()
    {
        // 카메라의 프러스트럼 확인
        Plane[] frustumPlanes = GeometryUtility.CalculateFrustumPlanes(mainCamera);

        foreach (var tile in tileRenderers)
        {
            bool isInFrustum = GeometryUtility.TestPlanesAABB(frustumPlanes, tile.bounds);

            if (isInFrustum)
            {
                // 확률적으로 활성화 또는 비활성화 결정
                if (Random.value <= predictionProbability)
                {
                    if (!currentlyActive.Contains(tile))
                    {
                        tile.enabled = true;
                        currentlyActive.Add(tile);
                    }
                }
                else
                {
                    if (currentlyActive.Contains(tile))
                    {
                        tile.enabled = false;
                        currentlyActive.Remove(tile);
                    }
                }
            }
            else
            {
                if (currentlyActive.Contains(tile))
                {
                    tile.enabled = false;
                    currentlyActive.Remove(tile);
                }
            }
        }
    }
}
```

### 알고리즘의 프레임 드랍 방지 원리 설명

확률론적 타일맵 컬링(STC)은 전체 타일셋의 렌더링 대상 상태를 프레임마다 무작위로 결정함으로써 정적인 컬링과 달리 일시적 부하를 분산시킵니다. 구체적으로, 타일이 카메라의 프러스텀 내에 위치했을 때, 통계적 예측에 따라 활성 또는 비활성화를 확률적으로 판단합니다. 이 과정은 전체 프레임에 걸쳐 동일한 타일들이 지속적으로 활성화 또는 비활성화되지 않도록 하여, GPU와 CPU의 작업 부하를 균등하게 유지하는 역할을 합니다.

이 방법은 일반적인 타일 컬링이 프레임마다 연속적으로 일괄 처리하는 것과 달리, 확률적인 판단을 통해 특정 타일의 활성화를 지연시키거나 조기 종료시키는 효과를 제공하며, 이로 인해 갑작스러운 드랍 현상과 버퍼 오버플로우 가능성을 수평적으로 분산시킵니다. 즉, 일정 시간동안 비활성 상태가 반복될 경우, 해당 타일의 렌더링 부담이 자연스럽게 줄어들어 전체 시스템의 부하를 견딜 수 있는 범위 내에서 유지하는 데 도움을 줍니다.

먼저 전제부터 말씀드리면, **“Stochastic Tilemap Culling (STC)”이라는 이름의 표준화된 Unity/게임학계 정식 알고리즘은 일반적으로 널리 확립된 용어로 알려져 있지 않습니다.**  
다만 질문의 의도에 맞게, **프러스텀 내부 스프라이트를 확률적으로 샘플링·추정하여 렌더링 후보를 사전 비활성화하는 방식**으로 STC를 재구성해 Unity C#로 구현할 수 있습니다.

아래에는 다음을 포함해 설명하겠습니다.

1. **STC 개념**
2. **Unity C# 예시 구현**
3. **프레임 드랍 방지 원리**
4. **사용 시 주의점**

