## 1) STC 개념

일반적인 타일맵/스프라이트 컬링은 보통 다음 방식입니다.

- 카메라 프러스텀과 타일/스프라이트의 Bounds를 매 프레임 정확히 교차 검사
- 교차하지 않으면 비활성화
- 교차하면 렌더링 유지

이 방식은 정확하지만, 오브젝트 수가 많거나 동적 객체가 많을 때:

- 개별 Bounds 검사 비용 증가
- Renderer 활성/비활성 전환 비용 증가
- 트랜스폼/렌더러 상태 갱신에 따른 CPU 스파이크
- 결과적으로 프레임 타임 변동 증가

**STC는 이를 완전 결정론적 검사 대신 확률적 추정으로 완화**하는 접근입니다.  
핵심은 다음입니다.

- 프러스텀 안쪽의 모든 객체를 매 프레임 정확하게 검사하지 않음
- 샘플링을 통해 “이번 프레임에 실제로 화면 기여가 낮을 가능성”이 높은 객체를 추정
- 추정 결과를 기반으로 일부 렌더러를 미리 비활성화하거나, 낮은 우선순위 그룹으로 전환
- 검사는 모든 객체에 매 프레임 수행하지 않고, **분산된 시간 슬롯**으로 처리

즉, STC는 **정확도 일부를 비용 절감으로 교환**해서 CPU 피크를 줄이는 방식입니다.

---

## 2) Unity C# 구현 예시

아래 예시는 다음을 가정합니다.

- 2D 탑다운
- 타일맵 또는 다수 스프라이트 렌더러 존재
- 카메라 기준으로 일정 거리 밖, 혹은 확률적으로 낮은 우선순위 객체를 비활성화
- 매 프레임 전체를 다 검사하지 않고, 프레임 단위로 일부만 샘플링

### 2-1. STC 매니저 스크립트

```csharp
using System.Collections.Generic;
using UnityEngine;

public class StochasticTilemapCulling : MonoBehaviour
{
    [Header("References")]
    [SerializeField] private Camera targetCamera;

    [Header("Sampling")]
    [Range(1, 512)]
    [SerializeField] private int sampleBudgetPerFrame = 64;

    [Range(0f, 1f)]
    [SerializeField] private float conservativeKeepProbability = 0.15f;

    [Header("Cull Settings")]
    [SerializeField] private float extraMargin = 1.5f;
    [SerializeField] private float nearDistanceKeep = 12f;
    [SerializeField] private float farDistanceCull = 28f;

    [Header("Runtime")]
    [SerializeField] private bool useBoundsIntersection = true;

    private readonly List<SpriteRenderer> renderers = new List<SpriteRenderer>();
    private int cursor = 0;

    private Plane[] frustumPlanes = new Plane[6];

    private void Awake()
    {
        if (targetCamera == null)
            targetCamera = Camera.main;

        CacheRenderers();
    }

    private void OnEnable()
    {
        CacheRenderers();
    }

    private void CacheRenderers()
    {
        renderers.Clear();
        renderers.AddRange(FindObjectsOfType<SpriteRenderer>(true));
    }

    private void LateUpdate()
    {
        if (targetCamera == null || renderers.Count == 0)
            return;

        GeometryUtility.CalculateFrustumPlanes(targetCamera, frustumPlanes);

        int processed = 0;
        int count = renderers.Count;

        while (processed < sampleBudgetPerFrame && count > 0)
        {
            if (cursor >= count)
                cursor = 0;

            SpriteRenderer sr = renderers[cursor++];
            processed++;

            if (sr == null)
                continue;

            EvaluateRenderer(sr);
        }
    }

    private void EvaluateRenderer(SpriteRenderer sr)
    {
        Bounds bounds = sr.bounds;

        // 카메라 중심점과의 거리 기반 1차 필터
        Vector3 camPos = targetCamera.transform.position;
        Vector3 closest = bounds.ClosestPoint(camPos);
        float dist = Vector3.Distance(camPos, closest);

        // 근거리 객체는 유지
        if (dist <= nearDistanceKeep)
        {
            SetVisible(sr, true);
            return;
        }

        // 원거리 객체는 더 공격적으로 컬링
        if (dist >= farDistanceCull)
        {
            if (Random.value > conservativeKeepProbability)
            {
                SetVisible(sr, false);
                return;
            }
            SetVisible(sr, true);
            return;
        }

        // 프러스텀 교차 검사
        bool inFrustum = useBoundsIntersection
            ? GeometryUtility.TestPlanesAABB(frustumPlanes, bounds)
            : IsInsideExpandedViewport(bounds);

        if (!inFrustum)
        {
            // 확률론적 비활성화
            // 경계 근처 객체를 일정 확률로 남겨서 과도한 토글을 완화
            if (Random.value > conservativeKeepProbability)
                SetVisible(sr, false);
            else
                SetVisible(sr, true);
        }
        else
        {
            SetVisible(sr, true);
        }
    }

    private void SetVisible(SpriteRenderer sr, bool visible)
    {
        if (sr.enabled != visible)
            sr.enabled = visible;
    }

    private bool IsInsideExpandedViewport(Bounds bounds)
    {
        Vector3 min = targetCamera.WorldToViewportPoint(bounds.min);
        Vector3 max = targetCamera.WorldToViewportPoint(bounds.max);

        float xMin = Mathf.Min(min.x, max.x) - extraMargin;
        float xMax = Mathf.Max(min.x, max.x) + extraMargin;
        float yMin = Mathf.Min(min.y, max.y) - extraMargin;
        float yMax = Mathf.Max(min.y, max.y) + extraMargin;

        return xMax >= 0f && xMin <= 1f && yMax >= 0f && yMin <= 1f;
    }
}
```

