### 2-2. 타일 단위로 적용하는 버전

타일맵의 각 셀을 별도 SpriteRenderer로 관리하는 경우 다음처럼 별도 구조를 두는 것이 좋습니다.  
Unity의 `TilemapRenderer` 자체는 개별 셀 단위 비활성화가 제한적이므로, **커스텀 타일 인스턴싱 또는 Chunk 단위 관리**가 성능상 더 적합합니다.

아래는 간단히 “청크 단위” 컬링 구조입니다.

```csharp
using System.Collections.Generic;
using UnityEngine;

public class STCChunk : MonoBehaviour
{
    public Renderer[] renderers;
    [HideInInspector] public Bounds chunkBounds;
}
```

```csharp
using System.Collections.Generic;
using UnityEngine;

public class STCChunkCulling : MonoBehaviour
{
    [SerializeField] private Camera targetCamera;
    [SerializeField] private int chunkSampleBudget = 8;
    [SerializeField] private float cullPadding = 2f;

    private readonly List<STCChunk> chunks = new List<STCChunk>();
    private Plane[] planes = new Plane[6];
    private int index = 0;

    private void Awake()
    {
        if (targetCamera == null)
            targetCamera = Camera.main;

        chunks.AddRange(FindObjectsOfType<STCChunk>(true));
    }

    private void LateUpdate()
    {
        if (targetCamera == null || chunks.Count == 0)
            return;

        GeometryUtility.CalculateFrustumPlanes(targetCamera, planes);

        for (int i = 0; i < chunkSampleBudget; i++)
        {
            if (index >= chunks.Count)
                index = 0;

            STCChunk chunk = chunks[index++];
            if (chunk == null) continue;

            ProcessChunk(chunk);
        }
    }

    private void ProcessChunk(STCChunk chunk)
    {
        Bounds expanded = chunk.chunkBounds;
        expanded.Expand(cullPadding);

        bool visible = GeometryUtility.TestPlanesAABB(planes, expanded);

        // 확률적 유지: 경계 부근 토글을 완화
        if (!visible)
        {
            float keepProbability = 0.1f;
            visible = Random.value < keepProbability;
        }

        if (chunk.renderers == null) return;

        for (int i = 0; i < chunk.renderers.Length; i++)
        {
            if (chunk.renderers[i] != null)
                chunk.renderers[i].enabled = visible;
        }
    }
}
```

