public class DataCollectionPipeline {

    public static void main(String[] args) throws InterruptedException {
        ThreadSafeQueue<DataPacket> queue = new ThreadSafeQueue<>(100);

        // 생산자 스레드 그룹
        Thread[] producers = new Thread[3];
        for (int i = 0; i < 3; i++) {
            final int producerId = i;
            producers[i] = new Thread(() -> {
                try {
                    for (int j = 0; j < 50; j++) {
                        DataPacket packet = new DataPacket(
                            producerId, 
                            j, 
                            "Data_" + producerId + "_" + j
                        );
                        queue.enqueue(packet);
                        System.out.println(
                            "[Producer-" + producerId + "] Enqueued: " + 
                            packet + " | Queue Size: " + queue.size()
                        );
                        Thread.sleep(10);
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                }
            });
        }

        // 소비자 스레드 그룹
        Thread[] consumers = new Thread[2];
        for (int i = 0; i < 2; i++) {
            final int consumerId = i;
            consumers[i] = new Thread(() -> {
                try {
                    for (int j = 0; j < 75; j++) {
                        DataPacket packet = queue.dequeue();
                        System.out.println(
                            "[Consumer-" + consumerId + "] Dequeued: " + 
                            packet + " | Queue Size: " + queue.size()
                        );
                        Thread.sleep(15);
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                }
            });
        }

        // 모든 스레드 시작
        for (Thread producer : producers) producer.start();
        for (Thread consumer : consumers) consumer.start();

        // 모든 스레드 종료 대기
        for (Thread producer : producers) producer.join();
        for (Thread consumer : consumers) consumer.join();

        System.out.println("파이프라인 처리 완료");
    }
}

