```java
/**
 * Monitor(모니터) 패턴 구현 분석
 */
public class MonitorPatternAnalysis {

    /**
     * Vector 내부 상태 관리 구조
     */
    public static class VectorMonitorState {
        /*
         * [Lock State Machine]
         * 
         * UNLOCKED ─── Thread A 도착 ──→ LOCKED (owned by Thread A)
         *                                    ↓
         *                            Thread B 도착 (대기)
         *                            Thread C 도착 (대기)
         *                                    ↓
         *                    Thread A 작업 완료 ──→ UNLOCKED
         *                                    ↓
         *                            Thread B Lock 획득
         *                            (FIFO 또는 우선순위)
         */
    }

    /**
     * Synchronized 메서드의 바이트코드 레벨 동작
     */
    public static class BytecodeAnalysis {
        /*
         * synchronized void add(Object element) {
         *     // 메서드 진입 시:
         *     MONITORENTER  // intrinsic lock 획득 시도
         *     
         *     // 메서드 본체
         *     ALOAD_0       // this 로드
         *     ...
         *     
         *     // 메서드 종료 시:
         *     MONITOREXIT   // intrinsic lock 해제
         *     RETURN
         * }
         * 
         * 예외 발생 시에도 MONITOREXIT 실행 보장 (implicit finally)
         */
    }
}
