## 2. 구현 코드

```java
import java.util.Vector;
import java.util.NoSuchElementException;

/**
 * Vector를 내부 저장소로 활용한 스레드 안전 큐 구현.
 * FIFO(First-In-First-Out) 정책을 준수하며,
 * 모든 공개 연산에 대해 상호 배제를 보장한다.
 *
 * @param <E> 큐에 적재되는 원소의 타입 매개변수
 */
public class VectorThreadSafeQueue<E> {

    private final Vector<E> internalStore;
    private final int capacity;
    private final Object lock;

    /**
     * 무한 용량 큐 생성자
     */
    public VectorThreadSafeQueue() {
        this(Integer.MAX_VALUE);
    }

    /**
     * 유한 용량 큐 생성자 (Bounded Queue)
     * 
     * @param capacity 큐의 최대 수용 가능 원소 수
     * @throws IllegalArgumentException capacity가 0 이하일 경우
     */
    public VectorThreadSafeQueue(int capacity) {
        if (capacity <= 0) {
            throw new IllegalArgumentException(
                "Capacity must be a positive integer. Provided: " + capacity);
        }
        this.capacity = capacity;
        this.internalStore = new Vector<>(Math.min(capacity, 16));
        this.lock = new Object();
    }

    /**
     * 큐의 후미(tail)에 원소를 적재한다.
     * 큐가 포화 상태(full)일 경우, 공간이 확보될 때까지 호출 스레드를 대기시킨다.
     *
     * @param element 적재할 원소 (null 허용하지 않음)
     * @throws InterruptedException 대기 중 스레드가 인터럽트된 경우
     * @throws NullPointerException element가 null인 경우
     */
    public void enqueue(E element) throws InterruptedException {
        if (element == null) {
            throw new NullPointerException("Null element insertion is prohibited.");
        }
        synchronized (lock) {
            while (internalStore.size() >= capacity) {
                lock.wait();  // 포화 상태: 조건 대기(Condition Wait)
            }
            internalStore.addElement(element);
            lock.notifyAll();  // 대기 중인 소비자 스레드 각성(Signal)
        }
    }

    /**
     * 큐의 선두(head)에서 원소를 제거하고 반환한다.
     * 큐가 공백 상태(empty)일 경우, 원소가 적재될 때까지 호출 스레드를 대기시킨다.
     *
     * @return 큐 선두의 원소
     * @throws InterruptedException 대기 중 스레드가 인터럽트된 경우
     */
    public E dequeue() throws InterruptedException {
        synchronized (lock) {
            while (internalStore.isEmpty()) {
                lock.wait();  // 공백 상태: 조건 대기
            }
            E element = internalStore.elementAt(0);
            internalStore.removeElementAt(0);
            lock.notifyAll();  // 대기 중인 생산자 스레드 각성
            return element;
        }
    }

    /**
     * 큐의 선두 원소를 제거하지 않고 조회한다.
     * 큐가 공백 상태일 경우 예외를 발생시킨다.
     *
     * @return 큐 선두의 원소
     * @throws NoSuchElementException 큐가 공백 상태인 경우
     */
    public E peek() {
        synchronized (lock) {
            if (internalStore.isEmpty()) {
                throw new NoSuchElementException("Queue is empty.");
            }
            return internalStore.elementAt(0);
        }
    }

    /**
     * 비차단(non-blocking) 적재 시도.
     * 큐가 포화 상태이면 즉시 false를 반환한다.
     *
     * @param element 적재할 원소
     * @return 적재 성공 시 true, 포화 상태 시 false
     */
    public boolean offer(E element) {
        if (element == null) {
            throw new NullPointerException("Null element insertion is prohibited.");
        }
        synchronized (lock) {
            if (internalStore.size() >= capacity) {
                return false;
            }
            internalStore.addElement(element);
            lock.notifyAll();
            return true;
        }
    }

    /**
     * 비차단 반출 시도.
     * 큐가 공백 상태이면 null을 반환한다.
     *
     * @return 큐 선두의 원소, 공백 상태 시 null
     */
    public E poll() {
        synchronized (lock) {
            if (internalStore.isEmpty()) {
                return null;
            }
            E element = internalStore.elementAt(0);
            internalStore.removeElementAt(0);
            lock.notifyAll();
            return element;
        }
    }

    /**
     * 현재 큐에 적재된 원소의 수를 반환한다.
     *
     * @return 원소 수
     */
    public int size() {
        synchronized (lock) {
            return internalStore.size();
        }
    }

    /**
     * 큐의 공백 여부를 반환한다.
     *
     * @return 공백 상태이면 true
     */
    public boolean isEmpty() {
        synchronized (lock) {
            return internalStore.isEmpty();
        }
    }

    /**
     * 큐의 포화 여부를 반환한다.
     *
     * @return 포화 상태이면 true
     */
    public boolean isFull() {
        synchronized (lock) {
            return internalStore.size() >= capacity;
        }
    }

    /**
     * 큐의 모든 원소를 제거한다.
     */
    public void clear() {
        synchronized (lock) {
            internalStore.removeAllElements();
            lock.notifyAll();
        }
    }
}
```

