## 3. 멀티스레드 파이프라인 검증 코드

```java
import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.CountDownLatch;

public class PipelineVerification {

    private static final int PRODUCER_COUNT = 4;
    private static final int CONSUMER_COUNT = 4;
    private static final int ITEMS_PER_PRODUCER = 10000;
    private static final AtomicInteger producedCount = new AtomicInteger(0);
    private static final AtomicInteger consumedCount = new AtomicInteger(0);

    public static void main(String[] args) throws InterruptedException {

        VectorThreadSafeQueue<Integer> queue = new VectorThreadSafeQueue<>(256);
        CountDownLatch producerLatch = new CountDownLatch(PRODUCER_COUNT);
        CountDownLatch consumerLatch = new CountDownLatch(CONSUMER_COUNT);

        // 생산자 스레드 집합 생성
        for (int i = 0; i < PRODUCER_COUNT; i++) {
            final int producerId = i;
            Thread producer = new Thread(() -> {
                try {
                    for (int j = 0; j < ITEMS_PER_PRODUCER; j++) {
                        int item = producerId * ITEMS_PER_PRODUCER + j;
                        queue.enqueue(item);
                        producedCount.incrementAndGet();
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    producerLatch.countDown();
                }
            }, "Producer-" + producerId);
            producer.start();
        }

        // 소비자 스레드 집합 생성
        for (int i = 0; i < CONSUMER_COUNT; i++) {
            Thread consumer = new Thread(() -> {
                try {
                    while (true) {
                        // 모든 생산자가 종료되고 큐가 공백이면 소비자도 종료
                        if (producerLatch.getCount() == 0 && queue.isEmpty()) {
                            break;
                        }
                        Integer item = queue.poll();
                        if (item != null) {
                            consumedCount.incrementAndGet();
                            // 데이터 처리 로직 위치
                        } else {
                            Thread.sleep(1);  // 스핀 대기 방지
                        }
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    consumerLatch.countDown();
                }
            }, "Consumer-" + i);
            consumer.start();
        }

        producerLatch.await();
        consumerLatch.await();

        // 잔여 원소 처리
        while (!queue.isEmpty()) {
            queue.poll();
            consumedCount.incrementAndGet();
        }

        System.out.println("Total Produced: " + producedCount.get());
        System.out.println("Total Consumed: " + consumedCount.get());
        System.out.println("Queue Residual Size: " + queue.size());
        System.out.println("Data Integrity: " + 
            (producedCount.get() == consumedCount.get() ? "VERIFIED" : "VIOLATION"));
    }
}
```

