## 1. 아키텍처 설계 및 구현

### 1.1 핵심 인터페이스 정의

```java
package pipeline.queue;

/**
 * 스레드 안전 큐의 계약을 정의하는 제네릭 인터페이스
 * FIFO(First-In-First-Out) 순서 보장을 명세
 *
 * @param <T> 큐에 저장될 데이터 타입 파라미터
 */
public interface ThreadSafeQueue<T> {

    /**
     * 큐의 후미(tail)에 요소를 삽입
     * @param item 삽입할 요소 (null 비허용)
     * @throws IllegalArgumentException null 요소 삽입 시도 시
     */
    void enqueue(T item);

    /**
     * 큐의 전단(head)에서 요소를 추출 및 제거
     * @return 추출된 요소
     * @throws java.util.NoSuchElementException 큐가 공백 상태일 때
     */
    T dequeue();

    /**
     * 큐의 전단 요소를 제거 없이 조회(peek)
     * @return 전단 요소
     * @throws java.util.NoSuchElementException 큐가 공백 상태일 때
     */
    T peek();

    /**
     * 현재 큐에 적재된 요소의 카디널리티(cardinality) 반환
     */
    int size();

    /**
     * 큐의 공백 상태 여부 판별
     */
    boolean isEmpty();

    /**
     * 큐 내 모든 요소를 원자적으로 제거
     */
    void clear();
}
```

