### 1.2 Vector 기반 스레드 안전 큐 구현체

```java
package pipeline.queue;

import java.util.Vector;
import java.util.NoSuchElementException;
import java.util.List;
import java.util.ArrayList;
import java.util.concurrent.atomic.AtomicLong;
import java.util.logging.Logger;
import java.util.logging.Level;

/**
 * java.util.Vector를 내부 저장소로 활용하는 스레드 안전 FIFO 큐 구현체
 *
 * <p>동기화 전략:
 * <ul>
 *   <li>Vector의 인스턴스 레벨 모니터 락(monitor lock)을 활용한 메서드 단위 상호 배제(mutual exclusion)</li>
 *   <li>복합 연산(compound action)에 대한 명시적 synchronized 블록 적용</li>
 *   <li>원자적 카운터(AtomicLong)를 통한 락-프리(lock-free) 통계 수집</li>
 * </ul>
 *
 * @param <T> 큐에 저장될 데이터 타입 파라미터
 */
public class VectorBackedQueue<T> implements ThreadSafeQueue<T> {

    private static final Logger LOGGER =
        Logger.getLogger(VectorBackedQueue.class.getName());

    /**
     * 내부 저장소: java.util.Vector
     * - 모든 public 메서드에 synchronized 키워드가 선언되어
     *   인스턴스 레벨 모니터 락 기반 상호 배제 보장
     * - 동적 배열(dynamic array) 구조로 인덱스 기반 O(1) 접근 지원
     */
    private final Vector<T> storage;

    /** 큐의 최대 수용 용량 (0 이하 = 무제한) */
    private final int capacity;

    /** 누적 enqueue 연산 횟수 - CAS(Compare-And-Swap) 기반 원자적 갱신 */
    private final AtomicLong enqueueCount = new AtomicLong(0);

    /** 누적 dequeue 연산 횟수 */
    private final AtomicLong dequeueCount = new AtomicLong(0);

    /** 큐 식별자 - 다중 큐 인스턴스 구분용 */
    private final String queueId;

    // =========================================================
    // 생성자 오버로딩 (Constructor Overloading)
    // =========================================================

    /**
     * 무제한 용량의 큐 인스턴스 생성
     * Vector 초기 용량(initial capacity)을 16으로 설정하여
     * 초기 메모리 할당 오버헤드 최소화
     */
    public VectorBackedQueue() {
        this("default-queue", 0, 16);
    }

    /**
     * 식별자 지정 무제한 큐 생성
     * @param queueId 큐 인스턴스 식별자
     */
    public VectorBackedQueue(String queueId) {
        this(queueId, 0, 16);
    }

    /**
     * 완전 매개변수화 생성자
     *
     * @param queueId         큐 식별자
     * @param capacity        최대 수용 용량 (0 = 무제한)
     * @param initialCapacity Vector 초기 내부 배열 크기
     */
    public VectorBackedQueue(String queueId, int capacity, int initialCapacity) {
        if (queueId == null || queueId.isBlank()) {
            throw new IllegalArgumentException(
                "queueId는 공백이 아닌 문자열이어야 합니다."
            );
        }
        if (initialCapacity < 1) {
            throw new IllegalArgumentException(
                "initialCapacity는 1 이상이어야 합니다: " + initialCapacity
            );
        }
        this.queueId  = queueId;
        this.capacity = capacity;
        // Vector 생성 시 초기 용량 및 증분(increment) 지정
        // increment = 0 → 용량 부족 시 현재 크기의 2배로 자동 확장
        this.storage  = new Vector<>(initialCapacity, 0);

        LOGGER.log(Level.INFO,
            "[{0}] VectorBackedQueue 초기화 완료 | capacity={1}, initialCapacity={2}",
            new Object[]{queueId, capacity, initialCapacity}
        );
    }

    // =========================================================
    // ThreadSafeQueue 인터페이스 구현
    // =========================================================

    /**
     * 큐의 후미(tail)에 요소를 원자적으로 삽입
     *
     * <p>동기화 분석:
     * storage(Vector)의 모니터 락을 획득한 후 용량 검증과 삽입을
     * 단일 임계 구역(critical section) 내에서 수행하여
     * TOCTOU(Time-of-Check-Time-of-Use) 경쟁 조건을 방지
     *
     * @param item 삽입할 요소
     * @throws IllegalArgumentException null 요소 삽입 시도 시
     * @throws IllegalStateException    유한 용량 큐가 포화 상태일 때
     */
    @Override
    public void enqueue(T item) {
        if (item == null) {
            throw new IllegalArgumentException(
                "null 요소는 삽입 불가합니다. queueId=" + queueId
            );
        }

        // Vector 인스턴스의 내재적 락(intrinsic lock)을 명시적으로 획득
        // → 용량 검증(check)과 삽입(use)을 원자적 복합 연산으로 묶음
        synchronized (storage) {
            if (capacity > 0 && storage.size() >= capacity) {
                throw new IllegalStateException(
                    String.format("[%s] 큐 포화 상태: 현재 크기=%d, 최대 용량=%d",
                        queueId, storage.size(), capacity)
                );
            }
            // Vector.addElement() → synchronized 메서드
            // 현재 블록이 이미 storage의 모니터 락을 보유하므로
            // 재진입 락(reentrant lock) 메커니즘에 의해 데드락 없이 진입 가능
            storage.addElement(item);
        }

        enqueueCount.incrementAndGet();

        LOGGER.log(Level.FINE,
            "[{0}] enqueue 완료 | item={1}, 현재 크기={2}",
            new Object[]{queueId, item, storage.size()}
        );
    }

    /**
     * 큐의 전단(head)에서 요소를 원자적으로 추출 및 제거
     *
     * <p>동기화 분석:
     * 공백 검증(isEmpty), 인덱스 0 조회(elementAt), 인덱스 0 제거(removeElementAt)의
     * 세 연산을 단일 임계 구역으로 묶어 원자성(atomicity) 보장.
     * 임계 구역 외부에서는 다른 스레드의 dequeue 연산이 개입하여
     * IndexOutOfBoundsException이 발생할 수 있음.
     *
     * @return 전단 요소
     * @throws NoSuchElementException 큐가 공백 상태일 때
     */
    @Override
    public T dequeue() {
        T item;

        synchronized (storage) {
            if (storage.isEmpty()) {
                throw new NoSuchElementException(
                    "[" + queueId + "] 공백 큐에서 dequeue 시도"
                );
            }
            // 인덱스 0 = FIFO 전단(head)
            item = storage.elementAt(0);
            storage.removeElementAt(0);
        }

        dequeueCount.incrementAndGet();

        LOGGER.log(Level.FINE,
            "[{0}] dequeue 완료 | item={1}, 잔여 크기={2}",
            new Object[]{queueId, item, storage.size()}
        );

        return item;
    }

    /**
     * 전단 요소를 제거 없이 조회(non-destructive read)
     *
     * @return 전단 요소
     * @throws NoSuchElementException 큐가 공백 상태일 때
     */
    @Override
    public T peek() {
        synchronized (storage) {
            if (storage.isEmpty()) {
                throw new NoSuchElementException(
                    "[" + queueId + "] 공백 큐에서 peek 시도"
                );
            }
            return storage.elementAt(0);
        }
    }

    /**
     * 현재 큐의 카디널리티(cardinality) 반환
     * Vector.size()는 synchronized 메서드이므로 단독 호출 시 스레드 안전
     */
    @Override
    public int size() {
        return storage.size();
    }

    /**
     * 공백 상태 판별
     * Vector.isEmpty()는 synchronized 메서드
     */
    @Override
    public boolean isEmpty() {
        return storage.isEmpty();
    }

    /**
     * 큐 내 모든 요소를 원자적으로 제거
     * Vector.clear()는 synchronized 메서드
     */
    @Override
    public void clear() {
        synchronized (storage) {
            storage.clear();
        }
        LOGGER.log(Level.INFO, "[{0}] 큐 초기화(clear) 완료", queueId);
    }

    // =========================================================
    // 확장 기능 메서드
    // =========================================================

    /**
     * 큐의 현재 상태를 스냅샷(snapshot)으로 반환
     *
     * <p>스냅샷 일관성(snapshot consistency) 보장:
     * storage의 모니터 락을 보유한 상태에서 전체 요소를 복사하므로
     * 반환된 리스트는 특정 시점의 일관된 상태를 반영.
     * 반환 후 원본 큐의 변경은 스냅샷에 영향을 미치지 않음(독립성).
     *
     * @return 현재 큐 상태의 불변 스냅샷
     */
    public List<T> snapshot() {
        synchronized (storage) {
            return new ArrayList<>(storage);
        }
    }

    /**
     * 조건부 일괄 enqueue - 트랜잭션적 원자성(transactional atomicity) 제공
     *
     * <p>모든 요소를 단일 임계 구역 내에서 삽입하거나
