# 멀티스레드 안전 큐 시스템 구현 및 동기화 원리 분석

## 1. Vector 기반 스레드 안전 큐 구현

```java
import java.util.Vector;
import java.util.NoSuchElementException;

/**
 * Vector를 내부 저장소로 활용한 스레드 안전 큐 구현
 * FIFO(First-In-First-Out) 의미론을 준수
 */
public class ThreadSafeVectorQueue<E> {

    private final Vector<E> elements;
    private static final int DEFAULT_CAPACITY = 10;

    public ThreadSafeVectorQueue() {
        this.elements = new Vector<>(DEFAULT_CAPACITY);
    }

    /**
     * Enqueue 연산: 요소를 큐의 후단(rear)에 삽입
     * @param element 삽입할 요소
     * @throws IllegalArgumentException null 요소 삽입 시도
     */
    public void enqueue(E element) {
        if (element == null) {
            throw new IllegalArgumentException("null 요소는 허용되지 않습니다.");
        }
        synchronized (elements) {
            elements.add(element);
        }
    }

    /**
     * Dequeue 연산: 큐의 전단(front)에서 요소를 제거 및 반환
     * @return 제거된 요소
     * @throws NoSuchElementException 큐가 공상태일 때 호출
     */
    public E dequeue() {
        synchronized (elements) {
            if (isEmpty()) {
                throw new NoSuchElementException("큐가 공상태입니다.");
            }
            return elements.remove(0);
        }
    }

    /**
     * Peek 연산: 큐의 전단 요소를 제거 없이 조회
     * @return 전단 요소
     * @throws NoSuchElementException 큐가 공상태일 때 호출
     */
    public E peek() {
        synchronized (elements) {
            if (isEmpty()) {
                throw new NoSuchElementException("큐가 공상태입니다.");
            }
            return elements.get(0);
        }
    }

    /**
     * 큐의 공상태 판정
     * @return 공상태 여부
     */
    public boolean isEmpty() {
        synchronized (elements) {
            return elements.isEmpty();
        }
    }

    /**
     * 큐의 현재 요소 개수 반환
     * @return 크기
     */
    public int size() {
        synchronized (elements) {
            return elements.size();
        }
    }

    /**
     * 큐 전체 초기화
     */
    public void clear() {
        synchronized (elements) {
            elements.clear();
        }
    }
}
```

## 2. 생산자-소비자 패턴 적용 예제

```java
/**
 * 데이터 수집 파이프라인: 생산자 스레드
 */
public class DataProducer implements Runnable {

    private final ThreadSafeVectorQueue<DataPacket> queue;
    private final String producerId;
    private final int dataCount;

    public DataProducer(ThreadSafeVectorQueue<DataPacket> queue, 
                       String producerId, int dataCount) {
        this.queue = queue;
        this.producerId = producerId;
        this.dataCount = dataCount;
    }

    @Override
    public void run() {
        try {
            for (int i = 0; i < dataCount; i++) {
                DataPacket packet = new DataPacket(
                    producerId,
                    "Data_" + i,
                    System.currentTimeMillis()
                );
                queue.enqueue(packet);
                System.out.printf("[%s] 데이터 삽입: %s%n", 
                    producerId, packet);
                Thread.sleep(100);
            }
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }
}

/**
 * 데이터 수집 파이프라인: 소비자 스레드
 */
public class DataConsumer implements Runnable {

    private final ThreadSafeVectorQueue<DataPacket> queue;
    private final String consumerId;

    public DataConsumer(ThreadSafeVectorQueue<DataPacket> queue, 
                       String consumerId) {
        this.queue = queue;
        this.consumerId = consumerId;
    }

    @Override
    public void run() {
        try {
            while (!Thread.currentThread().isInterrupted()) {
                if (!queue.isEmpty()) {
                    DataPacket packet = queue.dequeue();
                    System.out.printf("[%s] 데이터 추출: %s%n", 
                        consumerId, packet);
                    processData(packet);
                } else {
                    Thread.sleep(50);
                }
            }
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }

    private void processData(DataPacket packet) {
        // 데이터 처리 로직
        try {
            Thread.sleep(150);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }
}

/**
 * 데이터 패킷 모델
 */
public class DataPacket {
    private final String sourceId;
    private final String payload;
    private final long timestamp;

    public DataPacket(String sourceId, String payload, long timestamp) {
        this.sourceId = sourceId;
        this.payload = payload;
        this.timestamp = timestamp;
    }

    @Override
    public String toString() {
        return String.format("DataPacket{source='%s', payload='%s', ts=%d}", 
            sourceId, payload, timestamp);
    }
}
