# 스레드 안전 큐 시스템 구현 (java.util.Vector 기반)

## 1. 구현 코드

```java
import java.util.Vector;
import java.util.NoSuchElementException;

public class ThreadSafeVectorQueue<E> {

    private final Vector<E> storage;

    public ThreadSafeVectorQueue() {
        this.storage = new Vector<>();
    }

    public ThreadSafeVectorQueue(int initialCapacity) {
        this.storage = new Vector<>(initialCapacity);
    }

    /**
     * FIFO 정책에 따라 큐의 후단(tail)에 원소를 적재한다.
     * Vector.add(E)는 내부적으로 synchronized 메서드로 정의되어
     * 모니터 락(monitor lock)을 획득한 후 원소를 삽입한다.
     */
    public void enqueue(E element) {
        if (element == null) {
            throw new NullPointerException("null 원소는 허용되지 않는다.");
        }
        storage.add(element);
    }

    /**
     * FIFO 정책에 따라 큐의 전단(head)에서 원소를 제거 후 반환한다.
     * 복합 연산(check-then-act)이므로 메서드 단위의 동기화가 필요하다.
     */
    public synchronized E dequeue() {
        if (storage.isEmpty()) {
            throw new NoSuchElementException("큐가 비어 있다.");
        }
        return storage.remove(0);
    }

    /**
     * 전단 원소를 제거하지 않고 조회한다.
     * 단일 원자 연산이 아닌 isEmpty + get 의 복합 연산이므로
     * 인스턴스 단위 동기화로 원자성을 확보한다.
     */
    public synchronized E peek() {
        if (storage.isEmpty()) {
            return null;
        }
        return storage.firstElement();
    }

    public int size() {
        return storage.size();
    }

    public boolean isEmpty() {
        return storage.isEmpty();
    }
}
```

