### 1. Vector 기반 Thread-safe Queue 구현

아래의 `VectorQueue` 클래스는 `java.util.Vector`를 내부 물리 구조로 채택하고, FIFO(First-In-First-Out) 연산을 수행하도록 설계되었습니다. `Vector` 자체의 메서드 동기화 외에도, 복합 연산(Check-Then-Act) 시 발생할 수 있는 경쟁 상태(Race Condition)를 방지하기 위해 상호 배제(Mutual Exclusion)를 명시적으로 강화하였습니다.

```java
import java.util.Vector;
import java.util.NoSuchElementException;

/**
 * java.util.Vector를 내부 저장소로 사용하는 스레드 안전한 큐 구현체
 * @param <E> 큐에 저장될 요소의 타입
 */
public class VectorQueue<E> {

    // 내부 저장소로 Vector 활용 (초기 용량 설정)
    private final Vector<E> storage;

    /**
     * 기본 생성자
     */
    public VectorQueue() {
        this.storage = new Vector<>();
    }

    /**
     * 큐의 끝(Tail)에 요소를 추가합니다.
     * Vector의 add() 메서드는 자체적으로 synchronized로 선언되어 있어 스레드 안전합니다.
     *
     * @param element 추가할 요소
     * @throws NullPointerException 요소가 null인 경우
     */
    public void enqueue(E element) {
        if (element == null) {
            throw new NullPointerException("Null elements are not allowed in this queue.");
        }
        storage.add(element);
    }

    /**
     * 큐의 시작(Head)에서 요소를 제거하고 반환합니다.
     * 원자적(Atomic) 복합 연산을 보장하기 위해 내부 Vector 인스턴스에 대해 동기화 블록을 설정합니다.
     *
     * @return 제거된 요소
     * @throws NoSuchElementException 큐가 비어있을 경우
     */
    public E dequeue() {
        // 복합 연산(isEmpty 검사 후 remove 연산)의 원자성을 보장하기 위해 
        // storage 객체의 모니터 락(Monitor Lock)을 획득
        synchronized (storage) {
            if (storage.isEmpty()) {
                throw new NoSuchElementException("Queue is empty.");
            }
            // FIFO 구조를 위해 인덱스 0번의 요소를 제거하며 반환
            return storage.remove(0);
        }
    }

    /**
     * 큐의 시작(Head)에 있는 요소를 제거하지 않고 반환합니다.
     *
     * @return 참조된 요소
     * @throws NoSuchElementException 큐가 비어있을 경우
     */
    public E peek() {
        synchronized (storage) {
            if (storage.isEmpty()) {
                throw new NoSuchElementException("Queue is empty.");
            }
            return storage.get(0);
        }
    }

    /**
     * 현재 큐에 적재된 요소의 개수를 반환합니다.
     *
     * @return 큐의 크기
     */
    public int size() {
        // Vector.size()는 내부적으로 synchronized 처리되어 있음
        return storage.size();
    }

    /**
     * 큐가 비어있는지 여부를 확인합니다.
     *
     * @return 비어있으면 true, 그렇지 않으면 false
     */
    public boolean isEmpty() {
        // Vector.isEmpty()는 내부적으로 synchronized 처리되어 있음
        return storage.isEmpty();
    }
}
```

