## 활용 예시: 데이터 수집 파이프라인

```java
public class DataCollectionPipeline {

    private final SynchronizedVectorQueue<DataPacket> queue;
    private final ExecutorService producerPool;
    private final ExecutorService consumerPool;

    public DataCollectionPipeline(int queueCapacity, int producerCount, int consumerCount) {
        this.queue = new SynchronizedVectorQueue<>(queueCapacity);
        this.producerPool = Executors.newFixedThreadPool(producerCount);
        this.consumerPool = Executors.newFixedThreadPool(consumerCount);
    }

    public void start() {
        // 생산자 스레드 시작
        for (int i = 0; i < ((ThreadPoolExecutor) producerPool).getCorePoolSize(); i++) {
            producerPool.submit(new DataProducer(queue, i));
        }

        // 소비자 스레드 시작
        for (int i = 0; i < ((ThreadPoolExecutor) consumerPool).getCorePoolSize(); i++) {
            consumerPool.submit(new DataConsumer(queue, i));
        }
    }

    // 생산자 구현
    private static class DataProducer implements Runnable {
        private final SynchronizedVectorQueue<DataPacket> queue;
        private final int id;

        @Override
        public void run() {
            while (!Thread.currentThread().isInterrupted()) {
                DataPacket packet = acquireFromExternalSource();
                try {
                    queue.enqueue(packet); // Blocking 삽입
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    break;
                }
            }
        }
    }

    // 소비자 구현
    private static class DataConsumer implements Runnable {
        private final SynchronizedVectorQueue<DataPacket> queue;
        private final int id;

        @Override
        public void run() {
            while (!Thread.currentThread().isInterrupted()) {
                try {
                    DataPacket packet = queue.dequeue(); // Blocking 추출
                    process(packet);
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    break;
                }
            }
        }
    }
}
```

