## **1. 스레드 안전한 큐 시스템 구현**

아래 예제는 `Vector`를 기반으로 한 스레드 안전한 큐 인터페이스를 구현한 클래스입니다. `Queue` 인터페이스의 주요 메서드인 `offer`, `poll`, `peek`를 오버라이드하여 구현하였습니다.

```java
import java.util.Collections;
import java.util.Vector;
import java.util.Queue;
import java.util.NoSuchElementException;

public class ThreadSafeVectorQueue<E> implements Queue<E> {

    // 스레드 안전성을 위해 Vector 사용
    private final Vector<E> vector;

    // 생성자
    public ThreadSafeVectorQueue() {
        this.vector = new Vector<>();
    }

    /**
     * 큐에 요소를 추가합니다. 스레드 안전성 보장.
     *
     * @param e 추가할 요소 (null 허용)
     * @return 추가 성공 여부 (true)
     * @throws IllegalStateException 큐가 전체 크기 제한에 도달했을 경우
     */
    @Override
    public boolean offer(E e) {
        vector.addElement(e);  // Vector의 addElement는 synchronized로 동기화됨
        return true;
    }

    /**
     * 큐에서 요소를 제거하고 반환합니다. 요소가 없으면 null을 반환합니다.
     *
     * @return 제거된 요소 또는 null
     */
    @Override
    public E poll() {
        if (vector.isEmpty()) {
            return null;
        }
        return vector.remove(0);  // Vector의 remove(int index)는 synchronized로 동기화됨
    }

    /**
     * 큐에서 요소를 반환하지만 제거하지 않습니다. 요소가 없으면 null을 반환합니다.
     *
     * @return 최전단 요소 또는 null
     */
    @Override
    public E peek() {
        if (vector.isEmpty()) {
            return null;
        }
        return vector.elementAt(0);  // Vector의 elementAt(int index)는 synchronized로 동기화됨
    }

    /**
     * 큐를 비웁니다.
     */
    @Override
    public void clear() {
        vector.removeAllElements();  // Vector의 removeAllElements는 synchronized로 동기화됨
    }

    /**
     * 큐에 요소가 존재하는지 확인합니다.
     *
     * @return 큐가 비어 있지 않으면 true
     */
    @Override
    public boolean isEmpty() {
        return vector.isEmpty();  // Vector의 isEmpty는 synchronized로 동기화됨
    }

    /**
     * 큐의 현재 크기를 반환합니다.
     *
     * @return 큐의 요소 개수
     */
    @Override
    public int size() {
        return vector.size();  // Vector의 size는 synchronized로 동기화됨
    }

    /**
     * 큐에 모든 요소를 포함하는 배열을 반환합니다.
     *
     * @return 요소들을 포함하는 배열
     */
    @Override
    public E[] toArray() {
        return vector.toArray((E[]) new Object[0]);
    }

    /**
     * 큐에 모든 요소를 포함하는 지정된 배열에 복사하여 반환합니다.
     *
     * @param a 복사 대상 배열
     * @return 입력된 배열 또는 새로 생성된 배열
     */
    @Override
    public <T> T[] toArray(T[] a) {
        return vector.toArray(a);
    }

    /**
     * 큐에 요소가 존재하는지 확인합니다.
     *
     * @param o 존재 여부를 확인할 객체
     * @return 객체가 큐에 존재하면 true
     */
    @Override
    public boolean contains(Object o) {
        return vector.contains(o);  // Vector의 contains는 synchronized로 동기화됨
    }

    /**
     * 큐에서 지정된 요소를 제거합니다.
     *
     * @param o 제거할 요소
     * @return 제거에 성공하면 true
     */
    @Override
    public boolean remove(Object o) {
        return vector.remove(o);  // Vector의 remove(Object o)는 synchronized로 동기화됨
    }

    /**
     * 큐에 지정된 모든 요소를 추가합니다.
     *
     * @param c 추가할 요소들을 포함한 컬렉션
     * @return 추가에 성공하면 true
     */
    @Override
    public boolean addAll(java.util.Collection<? extends E> c) {
        return vector.addAll(c);  // Vector의 addAll은 synchronized로 동기화됨
    }

    /**
     * 큐에서 모든 요소를 제거합니다.
     */
    @Override
    public boolean removeAll(java.util.Collection<?> c) {
        return vector.removeAll(c);  // Vector의 removeAll은 synchronized로 동기화됨
    }

    /**
     * 큐에서 지정된 요소들을 보유하고 있는지 확인합니다.
     *
     * @param c 확인할 컬렉션
     * @return 모든 요소가 보유되면 true
     */
    @Override
    public boolean retainsAll(java.util.Collection<?> c) {
        return vector.retainAll(c);  // Vector의 retainAll은 synchronized로 동기화됨
    }

    /**
     * 이 큐에 대한 이터레이터를 반환합니다. 이터레이터는 동기화되지 않았으므로,
     * 외부에서 별도로 동기화 처리가 필요할 수 있습니다.
     *
     * @return 이터레이터
     */
    @Override
    public java.util.Iterator<E> iterator() {
        return vector.iterator();  // Vector의 iterator는 동기화되지 않음. 외부에서 synchronized 처리 필요
    }

    /**
     * 이 큐에 포함된 모든 요소를 포함하는 배열을 생성하여 반환합니다.
     *
     * @return 요소들을 포함하는 배열
     */
    @Override
    public Object[] toArray(Object[] a) {
        return vector.toArray(a);
    }

    /**
     * 큐에 요소를 추가합니다.
     *
     * @param e 추가할 요소
     * @return 추가에 성공하면 true
     */
    @Override
    public boolean add(E e) {
        return offer(e);
    }

    /**
     * 큐에서 요소를 제거하고 반환합니다. 요소가 없으면 예외를 발생시킵니다.
     *
     * @return 제거된 요소
     * @throws NoSuchElementException 큐가 비어 있음
     */
    @Override
    public E remove() {
        E e = poll();
        if (e == null) {
            throw new NoSuchElementException("Queue is empty");
        }
        return e;
    }

    /**
     * 큐에서 요소를 반환하지만 제거하지 않습니다. 요소가 없으면 예외를 발생시킵니다.
     *
     * @return 최전단 요소
     * @throws NoSuchElementException 큐가 비어 있음
     */
    @Override
    public E element() {
        E e = peek();
        if (e == null) {
            throw new NoSuchElementException("Queue is empty");
        }
        return e;
    }

    /**
     * 큐에 요소가 존재하는지 확인합니다.
     *
     * @param o 존재 여부를 확인할 객체
     * @return 객체가 큐에 존재하면 true
     */
    @Override
    public boolean containsAll(java.util.Collection<?> c) {
        return vector.containsAll(c);  // Vector의 containsAll은 synchronized로 동기화됨
    }
}
```

