### 2.2 메인 리소스 매니저 클래스

```csharp
using System;
using System.Collections.Generic;
using System.Diagnostics;
using UnityEngine;
using UnityEngine.Tilemaps;
using Debug = UnityEngine.Debug;

namespace TopDownGame.ResourceManagement
{
    /// <summary>
    /// Resources.Load API를 활용한 동기적 에셋 관리 시스템.
    ///
    /// [메모리 모델]
    /// - _assetRegistry: Managed Heap에 할당된 Dictionary
    ///   Key   → string (interned string pool 또는 managed heap)
    ///   Value → AssetEntry struct (managed heap 내 값 타입 저장)
    ///   AssetEntry.AssetReference → Native Heap의 UnityEngine.Object 네이티브 인스턴스 참조
    ///
    /// [동기적 로딩의 실행 흐름]
    /// 1. Resources.Load 호출 → Unity 네이티브 레이어로 P/Invoke 전환
    /// 2. 직렬화된 에셋 바이너리를 디스크 I/O (또는 AssetBundle 캐시)에서 읽기
    /// 3. 역직렬화(deserialization) 수행 → Native Heap에 객체 인스턴스 생성
    /// 4. 관리형 래퍼(managed wrapper) 객체를 Managed Heap에 생성
    /// 5. 네이티브 인스턴스 포인터를 관리형 래퍼에 바인딩
    /// 6. 관리형 래퍼 참조를 호출 스택으로 반환
    /// </summary>
    public sealed class TileAssetResourceManager : IDisposable
    {
        // ─────────────────────────────────────────────────────────────
        // 싱글턴 인스턴스 관리 (스레드 안전 초기화)
        // ─────────────────────────────────────────────────────────────

        private static volatile TileAssetResourceManager _instance;
        private static readonly object _instanceLock = new object();

        public static TileAssetResourceManager Instance
        {
            get
            {
                if (_instance == null)
                {
                    lock (_instanceLock)
                    {
                        if (_instance == null)
                            _instance = new TileAssetResourceManager();
                    }
                }
                return _instance;
            }
        }

        // ─────────────────────────────────────────────────────────────
        // 내부 상태 필드
        // ─────────────────────────────────────────────────────────────

        /// <summary>
        /// 로드된 에셋의 중앙 레지스트리.
        /// Key: Resources/ 상대 경로 (예: "Tiles/Terrain/GrassTile")
        /// Value: AssetEntry 구조체 (관리형 참조 + 메타데이터 포함)
        ///
        /// Dictionary 내부 구조:
        /// - 버킷 배열(bucket array): Managed Heap에 연속 할당
        /// - 각 버킷: 해시 충돌 시 연결 리스트(chaining) 방식으로 엔트리 연결
        /// - 초기 용량을 명시하여 rehashing 빈도 최소화
        /// </summary>
        private readonly Dictionary<string, AssetEntry> _assetRegistry;

        /// <summary>
        /// 타입별 로드된 에셋 경로 인덱스.
        /// 특정 타입의 전체 에셋 조회 시 O(n) 전체 탐색을 회피하기 위한
        /// 역방향 인덱스(inverted index) 구조.
        /// </summary>
        private readonly Dictionary<Type, HashSet<string>> _typeIndex;

        /// <summary>
        /// 에셋 로드/언로드 이벤트 구독자 목록.
        /// 옵저버 패턴(Observer Pattern) 구현.
        /// </summary>
        public event Action<AssetEventArgs> OnAssetStateChanged;

        /// <summary>
        /// 성능 측정용 스톱워치: 동기 로딩의 메인 스레드 블로킹 시간 추적
        /// </summary>
        private readonly Stopwatch _loadStopwatch;

        /// <summary>
        /// 누적 로딩 통계
        /// </summary>
        private int _totalLoadCount;
        private int _totalUnloadCount;
        private long _totalLoadTimeMs;

        private bool _isDisposed;

        // ─────────────────────────────────────────────────────────────
        // 생성자 (private: 싱글턴 패턴 강제)
        // ─────────────────────────────────────────────────────────────

        private TileAssetResourceManager()
        {
            // 초기 용량 지정: 수천 개 에셋 예상 시 해시 테이블 초기 버킷 수 설정.
            // 로드 팩터(load factor) 0.72 기준으로 rehashing 없이
            // 약 3600개 엔트리 수용 가능.
            const int initialCapacity = 4096;

            _assetRegistry = new Dictionary<string, AssetEntry>(
                initialCapacity,
                StringComparer.Ordinal); // 서수 비교: 해시 충돌 최소화 및 성능 최적화

            _typeIndex    = new Dictionary<Type, HashSet<string>>(16);
            _loadStopwatch = new Stopwatch();

            Debug.Log(
                $"[TileAssetResourceManager] 초기화 완료. " +
                $"초기 버킷 용량: {initialCapacity}");
        }

        // ─────────────────────────────────────────────────────────────
        // 핵심 API: 동기적 에셋 로드
        // ─────────────────────────────────────────────────────────────

        /// <summary>
        /// Resources.Load를 통한 동기적 에셋 로드 및 레지스트리 등록.
        ///
        /// [실행 시 메모리 할당 순서]
        /// 1. _assetRegistry에서 경로 키 해시 연산 및 버킷 탐색 (O(1) 평균)
        /// 2. 캐시 히트 시: 기존 AssetEntry의 ReferenceCount 증가 후 반환
        /// 3. 캐시 미스 시:
        ///    a. Resources.Load → 네이티브 레이어에서 에셋 역직렬화
        ///    b. Native Heap에 UnityEngine.Object 네이티브 인스턴스 할당
        ///    c. Managed Heap에 관리형 래퍼 객체 할당
        ///    d. AssetEntry 구조체 생성 (Managed Heap, 값 타입이나 Dictionary 내부에서 박싱 없이 저장)
        ///    e. _assetRegistry에 새 엔트리 삽입
        ///    f. _typeIndex 역방향 인덱스 갱신
        ///
        /// </summary>
        /// <typeparam name="T">로드할 에셋의 UnityEngine.Object 파생 타입</typeparam>
        /// <param name="resourcePath">Resources/ 폴더 기준 상대 경로 (확장자 제외)</param>
        /// <returns>로드된 에셋의 관리형 참조. 로드 실패 시 null.</returns>
        public T Load<T>(string resourcePath) where T : UnityEngine.Object
        {
            if (_isDisposed)
                throw new ObjectDisposedException(nameof(TileAssetResourceManager));

            if (string.IsNullOrEmpty(resourcePath))
            {
                Debug.LogError("[TileAssetResourceManager] resourcePath가 null 또는 빈 문자열입니다.");
                return null;
            }

            // ── 캐시 히트 경로 (O(1) 해시 테이블 조회) ──────────────────
            if (_assetRegistry.TryGetValue(resourcePath, out AssetEntry existingEntry))
            {
                // 네이티브 객체 유효성 재검증:
                // Unity fake-null 패턴으로 인해 관리형 참조 존재 ≠ 네이티브 객체 유효
                if (existingEntry.IsNativeObjectAlive)
                {
                    // 구조체는 값 타입이므로 ref 키워드로 직접 수정
                    ref AssetEntry entryRef = ref System.Runtime.InteropServices
                        .CollectionsMarshal.GetValueRefOrNullRef(
                            _assetRegistry, resourcePath);

                    if (!System.Runtime.CompilerServices.Unsafe.IsNullRef(ref entryRef))
                        entryRef.ReferenceCount++;

                    return existingEntry.AssetReference as T;
                }
                else
                {
                    // 네이티브 객체가 외부에서 소멸됨 (예: Resources.UnloadAsset 직접 호출)
                    // 레지스트리에서 무효 엔트리 제거 후 재로드 진행
                    Debug.LogWarning(
                        $"[TileAssetResourceManager] 경로 '{resourcePath}'의 " +
                        $"네이티브 에셋 객체가 소멸 상태입니다. 재로드를 수행합니다.");
                    RemoveFromIndex(resourcePath, existingEntry.AssetType);
                    _assetRegistry.Remove(resourcePath);
                }
            }

