# Unity 2D 탑뷰 게임의 동적 에셋 로딩 및 메모리 관리 시스템

## 1. 아키텍처 설계 및 구현

```csharp
using UnityEngine;
using System.Collections.Generic;
using System;

/// <summary>
/// Resources.Load 기반 동기식 에셋 로딩 매니저
/// 타일맵 및 스프라이트 에셋의 메모리 할당 및 생명주기 관리
/// </summary>
public class AssetLoadingManager : MonoBehaviour
{
    private static AssetLoadingManager _instance;

    // 로드된 에셋의 참조를 유지하는 캐시 구조
    private Dictionary<string, Sprite> _spriteCache;
    private Dictionary<string, Texture2D> _textureCache;
    private Dictionary<string, TileData[]> _tileDataCache;

    // 에셋 로드 상태 추적
    private Dictionary<string, AssetLoadState> _loadStateMap;

    // 메모리 통계
    private AssetMemoryStatistics _memoryStats;

    public static AssetLoadingManager Instance
    {
        get
        {
            if (_instance == null)
            {
                _instance = FindObjectOfType<AssetLoadingManager>();
                if (_instance == null)
                {
                    GameObject managerObject = new GameObject("AssetLoadingManager");
                    _instance = managerObject.AddComponent<AssetLoadingManager>();
                }
            }
            return _instance;
        }
    }

    private void Awake()
    {
        if (_instance != null && _instance != this)
        {
            Destroy(gameObject);
            return;
        }

        _instance = this;
        InitializeCache();
        DontDestroyOnLoad(gameObject);
    }

    /// <summary>
    /// 캐시 메모리 구조 초기화
    /// </summary>
    private void InitializeCache()
    {
        _spriteCache = new Dictionary<string, Sprite>(capacity: 2048);
        _textureCache = new Dictionary<string, Texture2D>(capacity: 512);
        _tileDataCache = new Dictionary<string, TileData[]>(capacity: 256);
        _loadStateMap = new Dictionary<string, AssetLoadState>(capacity: 2816);
        _memoryStats = new AssetMemoryStatistics();
    }

    /// <summary>
    /// 동기식 스프라이트 에셋 로드
    /// Resources.Load API를 통한 메인 스레드 블로킹 호출
    /// </summary>
    /// <param name="resourcePath">Resources 폴더 상대 경로</param>
    /// <param name="spriteIndex">스프라이트 시트 내 인덱스 (선택적)</param>
    /// <returns>로드된 스프라이트 또는 null</returns>
    public Sprite LoadSprite(string resourcePath, int spriteIndex = -1)
    {
        // 1. 캐시 조회 - O(1) 해시 테이블 탐색
        string cacheKey = GenerateCacheKey(resourcePath, spriteIndex);

        if (_spriteCache.TryGetValue(cacheKey, out Sprite cachedSprite))
        {
            _memoryStats.RecordCacheHit();
            return cachedSprite;
        }

        // 2. 동기식 로드 수행 - 메인 스레드 블로킹
        Sprite loadedSprite = null;

        try
        {
            if (spriteIndex >= 0)
            {
                // 스프라이트 시트에서 특정 인덱스의 스프라이트 로드
                Sprite[] spriteArray = Resources.LoadAll<Sprite>(resourcePath);

                if (spriteArray != null && spriteIndex < spriteArray.Length)
                {
                    loadedSprite = spriteArray[spriteIndex];
                }
            }
            else
            {
                // 단일 스프라이트 로드
                loadedSprite = Resources.Load<Sprite>(resourcePath);
            }

            if (loadedSprite != null)
            {
                // 3. 메모리 할당 및 캐시 저장
                _spriteCache[cacheKey] = loadedSprite;
                _loadStateMap[cacheKey] = new AssetLoadState
                {
                    ResourcePath = resourcePath,
                    LoadTimestamp = DateTime.UtcNow,
                    AssetType = AssetType.Sprite,
                    MemorySize = CalculateSpriteMemory(loadedSprite),
                    ReferenceCount = 1
                };

                _memoryStats.RecordAssetLoad(loadedSprite.texture.width * loadedSprite.texture.height * 4);
            }
        }
        catch (Exception ex)
        {
            Debug.LogError($"스프라이트 로드 실패: {resourcePath}, 예외: {ex.Message}");
            _loadStateMap[cacheKey] = new AssetLoadState 
            { 
                LoadState = LoadState.Failed 
            };
        }

        return loadedSprite;
    }

    /// <summary>
    /// 타일맵 데이터 일괄 로드
    /// 대량의 타일 정보를 단일 호출로 로드하여 메모리 단편화 감소
    /// </summary>
    public TileData[] LoadTileMapData(string resourcePath, int tileCount)
    {
        if (_tileDataCache.TryGetValue(resourcePath, out TileData[] cachedData))
        {
            _memoryStats.RecordCacheHit();
            return cachedData;
        }

        try
        {
            // 타일 데이터 JSON 또는 바이너리 에셋 로드
            TextAsset tileDataAsset = Resources.Load<TextAsset>(resourcePath);

            if (tileDataAsset == null)
            {
                throw new System.IO.FileNotFoundException($"타일 데이터 에셋 미발견: {resourcePath}");
            }

            // 직렬화된 데이터 역직렬화
            TileDataContainer container = JsonUtility.FromJson<TileDataContainer>(tileDataAsset.text);
            TileData[] tileData = new TileData[tileCount];

            // 메모리 연속성을 위한 배열 초기화
            System.Array.Copy(container.Tiles, tileData, Mathf.Min(tileCount, container.Tiles.Length));

            // 캐시 저장
            _tileDataCache[resourcePath] = tileData;
            _loadStateMap[resourcePath] = new AssetLoadState
            {
                ResourcePath = resourcePath,
                LoadTimestamp = DateTime.UtcNow,
                AssetType = AssetType.TileData,
                MemorySize = tileCount * System.Runtime.InteropServices.Marshal.SizeOf<TileData>(),
                ReferenceCount = 1
            };

            _memoryStats.RecordAssetLoad(_loadStateMap[resourcePath].MemorySize);
            return tileData;
        }
        catch (Exception ex)
        {
            Debug.LogError($"타일맵 데이터 로드 실패: {resourcePath}, 예외: {ex.Message}");
            return null;
        }
    }

    /// <summary>
    /// 텍스처 에셋 로드
    /// GPU 메모리 할당을 위한 Texture2D 로드
    /// </summary>
    public Texture2D LoadTexture(string resourcePath, TextureCompressionFormat format = TextureCompressionFormat.RGBA32)
    {
        string cacheKey = resourcePath;

        if (_textureCache.TryGetValue(cacheKey, out Texture2D cachedTexture))
        {
            _memoryStats.RecordCacheHit();
            return cachedTexture;
        }

        try
        {
            Texture2D loadedTexture = Resources.Load<Texture2D>(resourcePath);

            if (loadedTexture != null)
            {
                // 텍스처 압축 설정
                ApplyTextureCompression(loadedTexture, format);

                _textureCache[cacheKey] = loadedTexture;
                _loadStateMap[cacheKey] = new AssetLoadState
                {
                    ResourcePath = resourcePath,
                    LoadTimestamp = DateTime.UtcNow,
                    AssetType = AssetType.Texture,
                    MemorySize = CalculateTextureMemory(loadedTexture),
                    ReferenceCount = 1
                };

                _memoryStats.RecordAssetLoad(_loadStateMap[cacheKey].MemorySize);
            }

            return loadedTexture;
        }
        catch (Exception ex)
        {
            Debug.LogError($"텍스처 로드 실패: {resourcePath}, 예외: {ex.Message}");
            return null;
        }
    }

    /// <summary>
    /// 배치 로드 - 다중 에셋 동기식 로드
    /// 로드 순서 최적화를 통한 캐시 효율성 증대
    /// </summary>
    public Dictionary<string, Sprite> LoadSpriteBatch(string[] resourcePaths)
    {
        Dictionary<string, Sprite> loadedSprites = new Dictionary<string, Sprite>(resourcePaths.Length);

        foreach (string path in resourcePaths)
        {
            Sprite sprite = LoadSprite(path);
            if (sprite != null)
            {
                loadedSprites[path] = sprite;
            }
        }

        return loadedSprites;
    }

    /// <summary>
    /// 메모리 해제 - 명시적 언로드
    /// 참조 카운팅 기반 메모리 관리
    /// </summary>
    public void UnloadAsset(string resourcePath)
    {
        if (!_loadStateMap.TryGetValue(resourcePath, out AssetLoadState state))
        {
            return;
        }

        state.ReferenceCount--;

        if (state.ReferenceCount <= 0)
        {
            // 캐시에서 제거
            switch (state.AssetType)
            {
                case AssetType.Sprite:
                    _spriteCache.Remove(resourcePath);
                    break;
                case AssetType.Texture:
                    _textureCache.Remove(resourcePath);
                    break;
                case AssetType.TileData:
                    _tileDataCache.Remove(resourcePath);
                    break;
            }

            _loadStateMap.Remove(resourcePath);
            _memoryStats.RecordAssetUnload(state.MemorySize);

            // 명시적 메모리 해제
            Resources.UnloadUnusedAssets();
        }
    }

    /// <summary>
    /// 전체 캐시 초기화 - 메모리 압박 시 호출
    /// </summary>
    public void ClearAllCache()
    {
        _spriteCache.Clear();
        _textureCache.Clear();
        _tileDataCache.Clear();
        _loadStateMap.Clear();
        _memoryStats.Reset();

        Resources.UnloadUnusedAssets();
        GC.Collect();
    }

    /// <summary>
    /// 캐시 키 생성 - 에셋 고유 식별자
    /// </summary>
    private string GenerateCacheKey(string resourcePath, int spriteIndex)
    {
        return spriteIndex >= 0 
            ? $"{resourcePath}[{spriteIndex}]" 
            : resourcePath;
    }

    /// <summary>
    /// 스프라이트 메모리 크기 계산
    /// 텍스처 해상도 및 픽셀 포맷 기반 계산
    /// </summary>
    private long CalculateSpriteMemory(Sprite sprite)
    {
        if (sprite?.texture == null) return 0;

        Texture2D texture = sprite.texture;
        return (long)texture.width * texture.height * GetBytesPerPixel(texture.format);
    }

    /// <summary>
    /// 텍스처 메모리 크기 계산
    /// </summary>
    private long CalculateTextureMemory(Texture2D texture)
    {
        if (texture == null) return 0;

        return (long)texture.width * texture.height * GetBytesPerPixel(texture.format);
    }

    /// <summary>
    /// 텍스처 포맷별 바이트 크기 반환
    /// </summary>
    private int GetBytesPerPixel(TextureFormat format)
    {
        return format switch
        {
            TextureFormat.RGBA32 => 4,
            TextureFormat.RGB24 => 3,
            TextureFormat.Alpha8 => 1,
            TextureFormat.ARGB32 => 4,
            TextureFormat.DXT1 => 1, // 압축
            TextureFormat.DXT5 => 1, // 압축
            _ => 4
        };
    }

    /// <summary>
    /// 텍스처 압축 적용
    /// </summary>
    private void ApplyTextureCompression(Texture2D texture, TextureCompressionFormat format)
    {
        // 플랫폼별 압축 설정
        #if UNITY_ANDROID
            texture.Compress(true);
        #elif UNITY_IOS
            texture.Compress(true);
        #endif
    }

    /// <summary>
    /// 메모리 통계 조회
    /// </summary>
    public AssetMemoryStatistics GetMemoryStatistics()
    {
        return _memoryStats;
    }

    /// <summary>
    /// 로드 상태 조회
    /// </summary>
    public AssetLoadState GetAssetLoadState(string resourcePath)
    {
        _loadStateMap.TryGetValue(resourcePath, out AssetLoadState state);
        return state;
    }
}
```

