# Resources 기반 동기 로딩 매니저 설계

## 1. C# 매니저 클래스 구현

```csharp
using System;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.Tilemaps;

public sealed class ResourceAssetManager : MonoBehaviour
{
    public static ResourceAssetManager Instance { get; private set; }

    // 경로(key) → 로드된 UnityEngine.Object 참조를 보존하는 캐시 딕셔너리
    private readonly Dictionary<string, UnityEngine.Object> _assetCache 
        = new Dictionary<string, UnityEngine.Object>(1024);

    // 참조 카운팅용 사전: 동일 에셋의 다중 사용 추적
    private readonly Dictionary<string, int> _refCount 
        = new Dictionary<string, int>(1024);

    private void Awake()
    {
        if (Instance != null && Instance != this) { Destroy(gameObject); return; }
        Instance = this;
        DontDestroyOnLoad(gameObject);
    }

    /// <summary>
    /// Resources.Load<T>를 통한 동기 로딩.
    /// 호출 스레드(메인 스레드)를 블로킹한 상태에서 디스크 I/O 및
    /// 직렬화된 에셋의 역직렬화(Deserialization)가 즉시 수행된다.
    /// </summary>
    public T Load<T>(string resourcePath) where T : UnityEngine.Object
    {
        if (string.IsNullOrEmpty(resourcePath))
            throw new ArgumentException(nameof(resourcePath));

        if (_assetCache.TryGetValue(resourcePath, out var cached) && cached != null)
        {
            _refCount[resourcePath] = _refCount[resourcePath] + 1;
            return cached as T;
        }

        // Resources.Load는 동기 호출이므로 반환 시점에 객체가 네이티브 힙 및
        // 매니지드 힙 양쪽에 완전히 적재된 상태가 보장된다.
        T asset = Resources.Load<T>(resourcePath);
        if (asset == null)
        {
            Debug.LogError($"[ResourceAssetManager] Load 실패: {resourcePath}");
            return null;
        }

        _assetCache[resourcePath] = asset;
        _refCount[resourcePath] = 1;
        return asset;
    }

    public Sprite LoadSprite(string path) => Load<Sprite>(path);
    public TileBase LoadTile(string path) => Load<TileBase>(path);
    public GameObject LoadPrefab(string path) => Load<GameObject>(path);

    /// <summary>
    /// 일괄 프리로딩. Resources.LoadAll은 지정 디렉터리 내 모든
    /// 직렬화 자산을 단일 동기 호출로 메모리에 적재한다.
    /// </summary>
    public void PreloadDirectory<T>(string directory) where T : UnityEngine.Object
    {
        T[] assets = Resources.LoadAll<T>(directory);
        foreach (var a in assets)
        {
            string key = $"{directory}/{a.name}";
            if (!_assetCache.ContainsKey(key))
            {
                _assetCache[key] = a;
                _refCount[key] = 0;
            }
        }
    }

    /// <summary>
    /// 참조 카운트를 감소시키고 0에 도달 시 언로드 후보로 등록한다.
    /// Resources.UnloadAsset은 네이티브 메모리만 해제 가능하다.
    /// </summary>
    public void Release(string resourcePath)
    {
        if (!_refCount.ContainsKey(resourcePath)) return;
        _refCount[resourcePath]--;
        if (_refCount[resourcePath] <= 0)
        {
            var obj = _assetCache[resourcePath];
            _assetCache.Remove(resourcePath);
            _refCount.Remove(resourcePath);

            if (obj != null && !(obj is GameObject) && !(obj is Component))
                Resources.UnloadAsset(obj);
        }
    }

    /// <summary>
    /// 미참조 에셋의 일괄 회수. 내부적으로 GC.Collect와 결합되어야
    /// 매니지드 측 참조까지 해제된다.
    /// </summary>
    public void UnloadUnused()
    {
        Resources.UnloadUnusedAssets();
        GC.Collect();
    }

    private void OnDestroy()
    {
        _assetCache.Clear();
        _refCount.Clear();
        Resources.UnloadUnusedAssets();
    }
}
```

## 2. 메모리 구조 및 작동 원리

### 2.1 빌드 단계에서의 Resources 폴더 처리
Unity는 빌드 시 `Resources` 디렉터리에 위치한 모든 자산을 의존성 그래프와 함께 단일 직렬화 아카이브로 패키징한다. 이 아카이브는 애플리케이션 시작 시 인덱스 테이블이 메인 메모리에 상주하므로, `Resources` 경로 전체에 비례하는 초기 메타데이터 오버헤드가 발생한다. 자산 수가 수천 단위로 증가하면 인덱스 룩업 비용과 상주 메타데이터 크기가 선형적으로 증가하여 애플리케이션 기동 지연(Startup Latency)을 유발한다.

### 2.2 동기 호출 시점의 메모리 할당 경로
`Resources.Load<T>` 호출 시 다음 절차가 호출 스레드를 블로킹하면서 수행된다.

1. **인덱스 조회**: 직렬화 아카이브의 해시 테이블에서 경로 문자열을 키로 자산 디스크립터를 탐색한다.
2. **네이티브 힙 할당**: `Texture2D`, `Mesh`, `AudioClip` 등 네이티브 리소스 본체가 C++ 측 네이티브 힙(또는 GPU 측 VRAM)에 할당된다.
3. **매니지드 래퍼 생성**: 네이티브 객체를 가리키는 매니지드 측 래퍼 인스턴스가 Mono/IL2CPP 런타임의 매니지드 힙에 생성되며, 양자는 내부 핸들로 연결된다.
4. **참조 반환**: 매니지드 래퍼 참조가 호출자에게 반환된다.

이 절차 전반이 동기적이므로, 대용량 자산 로드 시 프레임 드롭(Frame Hitch)이 가시화된다.

### 2.3 캐싱 계층과 참조 수명
`Resources.Load`는 내부적으로 동일 자산에 대한 중복 로드를 방지하는 캐시를 보유하지만, 매니지드 측 참조가 살아있는 동안에만 보장된다. 본 매니저의 `_assetCache` 딕셔너리는 매니지드 참조를 명시적으로 유지함으로써 GC에 의한 회수와 그에 따른 의도치 않은 언로드를 차단한다. 참조 카운팅(`_refCount`)은 도메인 로직 수준의 수명 관리를 가능하게 하며, 카운트 0 도달 시 `Resources.UnloadAsset`을 통한 네이티브 메모리 회수 트리거 역할을 한다.

### 2.4 언로드 의미론
- `Resources.UnloadAsset(Object)`: 단일 자산의 네이티브 측 데이터만 해제한다. `GameObject` 및 `Component`는 지원되지 않는다.
- `Resources.UnloadUnusedAssets()`: 매니지드 측에서 도달 불가능(Unreachable)한 자산을 전수 스캔하여 일괄 회수한다. 시간 복잡도가 전체 자산 수 및 매니지드 참조 그래프 크기에 의존하므로 빈번한 호출은 부적절하다.
- 매니지드 힙의 래퍼 객체는 GC 수집 시점에만 해제되므로, `GC.Collect`와의 조합이 완전 회수에 필수적이다.

### 2.5 본 패턴의 구조적 한계
1. **메모리 상주 강제성**: `Resources` 폴더의 모든 자산은 빌드 결과물에 포함되며, 의존성 그래프상 참조된 자산은 빌드에서 제거되지 않는다. 수천 개 단위 운용 시 빌드 크기와 초기 메타데이터 비용이 비선형적으로 누적된다.
2. **메인 스레드 블로킹**: 동기 API 특성상 디스크 I/O 및 역직렬화가 렌더링 파이프라인과 동일 스레드에서 진행되어 프레임 타이밍을 침해한다.
3. **메모리 단편화**: 빈번한 로드/언로드 반복은 네이티브 힙 단편화를 유발하여 가용 메모리 총량 대비 할당 실패 확률을 증가시킨다.
4. **확장성 부재**: 패치/DLC 기반 자산 갱신, 플랫폼별 분기 로딩이 불가능하다.

상기 사유로 대규모 자산 운용 환경에서는 `Addressables` 또는 `AssetBundle` 기반 비동기 로딩이 권장 표준이며, `Resources` 동기 패턴은 즉시성과 단순성이 요구되는 소규모 핵심 자산 또는 부트스트랩 단계에 한정 적용함이 합리적이다.

# Unity Resources 기반 동기적 에셋 로딩 시스템 설계

## 1. 핵심 매니저 클래스 구현

```csharp
using System;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.Tilemaps;

/// <summary>
/// Resources 폴더 기반 동기적 에셋 로딩 및 캐싱 매니저
/// </summary>
public class ResourceAssetManager : MonoBehaviour
{
    private static ResourceAssetManager _instance;
    public static ResourceAssetManager Instance
    {
        get
        {
            if (_instance == null)
            {
                GameObject managerObject = new GameObject("ResourceAssetManager");
                _instance = managerObject.AddComponent<ResourceAssetManager>();
                DontDestroyOnLoad(managerObject);
            }
            return _instance;
        }
    }

    // 타일 에셋 캐시 딕셔너리 (Key: 리소스 경로, Value: TileBase 참조)
    private Dictionary<string, TileBase> _tileCache = new Dictionary<string, TileBase>();

    // 스프라이트 에셋 캐시 딕셔너리
    private Dictionary<string, Sprite> _spriteCache = new Dictionary<string, Sprite>();

    // 참조 카운팅 테이블 (메모리 관리용)
    private Dictionary<string, int> _referenceCount = new Dictionary<string, int>();

    // 로딩 통계 데이터
    private int _totalLoadedAssets = 0;
    private long _estimatedMemoryUsage = 0;

    /// <summary>
    /// 타일 에셋 동기적 로딩 및 캐싱
    /// </summary>
    /// <param name="resourcePath">Resources 폴더 기준 상대 경로 (확장자 제외)</param>
    /// <returns>로드된 TileBase 객체</returns>
    public TileBase LoadTile(string resourcePath)
    {
        // 캐시 히트 검사
        if (_tileCache.TryGetValue(resourcePath, out TileBase cachedTile))
        {
            IncrementReference(resourcePath);
            return cachedTile;
        }

        // Resources.Load를 통한 동기적 로딩
        TileBase loadedTile = Resources.Load<TileBase>(resourcePath);

        if (loadedTile == null)
        {
            Debug.LogError($"타일 로딩 실패: {resourcePath}");
            return null;
        }

        // 캐시 등록 및 참조 카운트 초기화
        _tileCache.Add(resourcePath, loadedTile);
        _referenceCount[resourcePath] = 1;
        _totalLoadedAssets++;

        // 메모리 사용량 추정 (대략적 계산)
        _estimatedMemoryUsage += EstimateTileMemorySize(loadedTile);

        return loadedTile;
    }

    /// <summary>
    /// 스프라이트 에셋 동기적 로딩 및 캐싱
    /// </summary>
    public Sprite LoadSprite(string resourcePath)
    {
        if (_spriteCache.TryGetValue(resourcePath, out Sprite cachedSprite))
        {
            IncrementReference(resourcePath);
            return cachedSprite;
        }

        Sprite loadedSprite = Resources.Load<Sprite>(resourcePath);

        if (loadedSprite == null)
        {
            Debug.LogError($"스프라이트 로딩 실패: {resourcePath}");
            return null;
        }

        _spriteCache.Add(resourcePath, loadedSprite);
        _referenceCount[resourcePath] = 1;
        _totalLoadedAssets++;
        _estimatedMemoryUsage += EstimateSpriteMemorySize(loadedSprite);

        return loadedSprite;
    }

    /// <summary>
    /// 배치 로딩: 다수의 타일을 한 번에 로딩
    /// </summary>
    public Dictionary<string, TileBase> LoadTileBatch(string[] resourcePaths)
    {
        Dictionary<string, TileBase> loadedTiles = new Dictionary<string, TileBase>();

        foreach (string path in resourcePaths)
        {
            TileBase tile = LoadTile(path);
            if (tile != null)
            {
                loadedTiles[path] = tile;
            }
        }

        return loadedTiles;
    }

    /// <summary>
    /// 배치 로딩: 다수의 스프라이트를 한 번에 로딩
    /// </summary>
    public Dictionary<string, Sprite> LoadSpriteBatch(string[] resourcePaths)
    {
        Dictionary<string, Sprite> loadedSprites = new Dictionary<string, Sprite>();

        foreach (string path in resourcePaths)
        {
            Sprite sprite = LoadSprite(path);
            if (sprite != null)
            {
                loadedSprites[path] = sprite;
            }
        }

        return loadedSprites;
    }

    /// <summary>
    /// 특정 폴더 내 모든 에셋 동기적 로딩
    /// </summary>
    public T[] LoadAllAssetsInFolder<T>(string folderPath) where T : UnityEngine.Object
    {
        T[] assets = Resources.LoadAll<T>(folderPath);

        foreach (T asset in assets)
        {
            string assetPath = $"{folderPath}/{asset.name}";

            if (asset is TileBase tile && !_tileCache.ContainsKey(assetPath))
            {
                _tileCache[assetPath] = tile;
                _referenceCount[assetPath] = 1;
                _totalLoadedAssets++;
            }
            else if (asset is Sprite sprite && !_spriteCache.ContainsKey(assetPath))
            {
                _spriteCache[assetPath] = sprite;
                _referenceCount[assetPath] = 1;
                _totalLoadedAssets++;
            }
        }

        return assets;
    }

    /// <summary>
    /// 참조 카운트 증가
    /// </summary>
    private void IncrementReference(string resourcePath)
    {
        if (_referenceCount.ContainsKey(resourcePath))
        {
            _referenceCount[resourcePath]++;
        }
    }

    /// <summary>
    /// 에셋 해제 및 참조 카운트 감소
    /// </summary>
    public void ReleaseAsset(string resourcePath)
    {
        if (!_referenceCount.ContainsKey(resourcePath))
        {
            return;
        }

        _referenceCount[resourcePath]--;

        // 참조 카운트가 0이 되면 캐시에서 제거
        if (_referenceCount[resourcePath] <= 0)
        {
            _tileCache.Remove(resourcePath);
            _spriteCache.Remove(resourcePath);
            _referenceCount.Remove(resourcePath);
            _totalLoadedAssets--;

            // Unity의 언로드 정책에 따라 메모리 해제는 Resources.UnloadUnusedAssets() 호출 시 수행됨
        }
    }

    /// <summary>
    /// 사용되지 않는 에셋 강제 언로드
    /// </summary>
    public void UnloadUnusedAssets()
    {
        Resources.UnloadUnusedAssets();
        Debug.Log("미사용 에셋 언로드 완료");
    }

    /// <summary>
    /// 전체 캐시 초기화
    /// </summary>
    public void ClearAllCache()
    {
        _tileCache.Clear();
        _spriteCache.Clear();
        _referenceCount.Clear();
        _totalLoadedAssets = 0;
        _estimatedMemoryUsage = 0;

        Resources.UnloadUnusedAssets();
    }

    /// <summary>
    /// 타일 메모리 크기 추정
    /// </summary>
    private long EstimateTileMemorySize(TileBase tile)
    {
        // 타일 객체 자체의 메타데이터 + 참조 스프라이트 크기
        long baseSize = 128; // 기본 객체 오버헤드

        if (tile is Tile standardTile && standardTile.sprite != null)
        {
            baseSize += EstimateSpriteMemorySize(standardTile.sprite);
        }

        return baseSize;
    }

    /// <summary>
    /// 스프라이트 메모리 크기 추정
    /// </summary>
    private long EstimateSpriteMemorySize(Sprite sprite)
    {
        if (sprite == null || sprite.texture == null)
        {
            return 0;
        }

        Texture2D texture = sprite.texture;
        int width = texture.width;
        int height = texture.height;

        // 텍스처 포맷에 따른 바이트 계산
        int bytesPerPixel = GetBytesPerPixel(texture.format);
        long textureSize = width * height * bytesPerPixel;

        // 밉맵이 활성화된 경우 추가 메모리 (약 33% 증가)
        if (texture.mipmapCount > 1)
        {
            textureSize = (long)(textureSize * 1.33f);
        }

        return textureSize;
    }

    /// <summary>
    /// 텍스처 포맷별 픽셀당 바이트 수 반환
    /// </summary>
    private int GetBytesPerPixel(TextureFormat format)
    {
        switch (format)
        {
            case TextureFormat.RGBA32:
            case TextureFormat.ARGB32:
                return 4;
            case TextureFormat.RGB24:
                return 3;
            case TextureFormat.RGBA4444:
            case TextureFormat.RGB565:
                return 2;
            case TextureFormat.Alpha8:
                return 1;
            case TextureFormat.DXT1:
                return 0; // 압축 포맷 (별도 계산 필요)
            case TextureFormat.DXT5:
                return 0; // 압축 포맷
            default:
                return 4; // 기본값
        }
    }

    /// <summary>
    /// 현재 메모리 상태 조회
    /// </summary>
    public AssetMemoryInfo GetMemoryInfo()
    {
        return new AssetMemoryInfo
        {
            TotalLoadedAssets = _totalLoadedAssets,
            TilesInCache = _tileCache.Count,
            SpritesInCache = _spriteCache.Count,
            EstimatedMemoryUsageBytes = _estimatedMemoryUsage,
            EstimatedMemoryUsageMB = _estimatedMemoryUsage / (1024f * 1024f)
        };
    }
}

/// <summary>
/// 메모리 정보 데이터 구조체
/// </summary>
[Serializable]
public struct AssetMemoryInfo
{
    public int TotalLoadedAssets;
    public int TilesInCache;
    public int SpritesInCache;
    public long EstimatedMemoryUsageBytes;
    public float EstimatedMemoryUsageMB;
}
```

## 2. 실제 사용 예제 클래스

```csharp
using UnityEngine;
using UnityEngine.Tilemaps;

/// <summary>
/// 타일맵 런타임 생성 및 에셋 적용 예제
/// </summary>
public class DynamicTilemapController : MonoBehaviour
{
    [SerializeField] private Tilemap targetTilemap;

    private void Start()
    {
        // 단일 타일 로딩 및 배치
        LoadAndPlaceSingleTile();

        // 배치 로딩을 통한 대량 타일 처리
        LoadAndPlaceMultipleTiles();

        // 메모리 상태 확인
        CheckMemoryStatus();
    }

    /// <summary>
    /// 단일 타일 로딩 및 배치
    /// </summary>
    private void LoadAndPlaceSingleTile()
    {
        string tilePath = "Tiles/Ground/GrassTile";
        TileBase grassTile = ResourceAssetManager.Instance.LoadTile(tilePath);

        if (grassTile != null && targetTilemap != null)
        {
            Vector3Int position = new Vector3Int(0, 0, 0);
            targetTilemap.SetTile(position, grassTile);
        }
    }

    /// <summary>
    /// 배치 로딩을 통한 대량 타일 처리
    /// </summary>
    private void LoadAndPlaceMultipleTiles()
    {
        string[] tilePaths = new string[]
        {
            "Tiles/Ground/GrassTile",
            "Tiles/Ground/DirtTile",
            "Tiles/Ground/StoneTile",
            "Tiles/Walls/BrickWall",
            "Tiles/Walls/WoodWall"
        };

        var loadedTiles = ResourceAssetManager.Instance.LoadTileBatch(tilePaths);

        int x = 0;
        foreach (var kvp in loadedTiles)
        {
            Vector3Int position = new Vector3Int(x, 1, 0);
            targetTilemap.SetTile(position, kvp.Value);
            x++;
        }
    }

    /// <summary>
    /// 전체 폴더 로딩
    /// </summary>
    private void LoadEntireFolder()
    {
        TileBase[] allGroundTiles = ResourceAssetManager.Instance.LoadAllAssetsInFolder<TileBase>("Tiles/Ground");
        Debug.Log($"로드된 타일 수: {allGroundTiles.Length}");
    }

    /// <summary>
    /// 메모리 상태 확인
    /// </summary>
    private void CheckMemoryStatus()
    {
        AssetMemoryInfo memInfo = ResourceAssetManager.Instance.GetMemoryInfo();
        Debug.Log($"총 로드된 에셋: {memInfo.TotalLoadedAssets}");
        Debug.Log($"캐시된 타일: {memInfo.TilesInCache}");
        Debug.Log($"캐시된 스프라이트: {memInfo.SpritesInCache}");
        Debug.Log($"추정 메모리 사용량: {memInfo.EstimatedMemoryUsageMB:F2} MB");
    }

    private void OnDestroy()
    {
        // 사용한 에셋 해제
        ResourceAssetManager.Instance.ReleaseAsset("Tiles/Ground/GrassTile");
    }
}
```

