## 2. 핵심 데이터 구조 정의

```csharp
// AssetEntry.cs
// 개별 에셋의 메타데이터 및 참조 상태를 캡슐화하는 값 타입 레코드
using System;
using UnityEngine;

namespace TopdownGame.ResourceSystem
{
    /// <summary>
    /// 로드된 에셋의 런타임 상태를 기술하는 불변 레코드 구조체.
    /// Managed Heap 상의 GC 추적 대상 참조(reference)와
    /// 참조 카운트(reference count) 정수값을 함께 보관한다.
    /// </summary>
    [Serializable]
    public sealed class AssetEntry
    {
        // ── 식별자 ──────────────────────────────────────────
        public readonly string   ResourcePath;   // Resources 폴더 기준 상대 경로
        public readonly Type     AssetType;      // System.Type 메타데이터 토큰
        public readonly int      AssetID;        // UnityEngine.Object.GetInstanceID()

        // ── 참조 관리 ────────────────────────────────────────
        // UnityEngine.Object는 C# Managed Heap의 래퍼(wrapper) 객체이며,
        // 실제 네이티브 오브젝트(Native Object)는 Unity Native Heap에 별도 존재한다.
        public UnityEngine.Object AssetReference { get; private set; }

        // Interlocked 연산을 통한 스레드-안전 참조 카운트
        private int _referenceCount;
        public  int  ReferenceCount => _referenceCount;

        // ── 타임스탬프 (LRU 정책용) ──────────────────────────
        public long LastAccessTick { get; private set; }   // Environment.TickCount64

        // ── 메모리 통계 ──────────────────────────────────────
        public long EstimatedBytes { get; private set; }   // Profiler.GetRuntimeMemorySizeLong

        // ── 생성자 ───────────────────────────────────────────
        public AssetEntry(string path, UnityEngine.Object asset)
        {
            ResourcePath    = path;
            AssetType       = asset.GetType();
            AssetID         = asset.GetInstanceID();
            AssetReference  = asset;
            _referenceCount = 0;
            LastAccessTick  = Environment.TickCount64;

            // Profiler API를 통해 Native Heap 점유 바이트 수 측정
            EstimatedBytes  = UnityEngine.Profiling.Profiler
                                  .GetRuntimeMemorySizeLong(asset);
        }

        // ── 참조 카운트 조작 (Acquire / Release) ─────────────
        public int Acquire()
        {
            LastAccessTick = Environment.TickCount64;
            return System.Threading.Interlocked.Increment(ref _referenceCount);
        }

        public int Release()
        {
            int val = System.Threading.Interlocked.Decrement(ref _referenceCount);
            if (val < 0)
                throw new InvalidOperationException(
                    $"[AssetEntry] 참조 카운트 언더플로우 감지: path={ResourcePath}");
            return val;
        }

        public void Invalidate()
        {
            AssetReference = null;
            _referenceCount = 0;
        }
    }
}
```

