## 3. 메인 ResourceManager 클래스

```csharp
// ResourceManager.cs
using System;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.Profiling;
using TopdownGame.ResourceSystem.Policy;

namespace TopdownGame.ResourceSystem
{
    /// <summary>
    /// Resources.Load 동기 API 전용 에셋 관리 매니저.
    ///
    /// [메모리 구조]
    ///  - _registry      : Managed Heap, Dictionary<string, AssetEntry>
    ///  - AssetEntry     : Managed Heap, C# 참조 타입 인스턴스
    ///  - UnityEngine.Object (래퍼): Managed Heap, GC 추적 대상
    ///  - Native Object  : Unity Native Heap, GC 추적 불가, Resources.UnloadAsset로만 해제
    ///  - Texture GPU    : VRAM, CPU-side 해제와 독립적으로 드라이버가 관리
    /// </summary>
    public sealed class ResourceManager : MonoBehaviour
    {
        // ── 싱글턴 인스턴스 ──────────────────────────────────
        private static ResourceManager _instance;
        public  static ResourceManager Instance
        {
            get
            {
                if (_instance == null)
                    throw new InvalidOperationException(
                        "[ResourceManager] 인스턴스가 초기화되지 않았습니다.");
                return _instance;
            }
        }

        // ── 설정 파라미터 ────────────────────────────────────
        [Header("메모리 상한 설정 (bytes)")]
        [SerializeField] private long _maxCacheBytes    = 256L * 1024 * 1024; // 256 MiB
        [SerializeField] private int  _maxEntryCount    = 2000;
        [SerializeField] private int  _lruEvictBatchSize = 50;

        // ── 핵심 자료구조 ────────────────────────────────────
        // Key   : ResourcePath (string, intern 풀 활용 권장)
        // Value : AssetEntry (참조 타입, Managed Heap 할당)
        private readonly Dictionary<string, AssetEntry> _registry
            = new Dictionary<string, AssetEntry>(2048, StringComparer.Ordinal);

        // LRU 정책을 위한 접근 순서 추적 (LinkedList = O(1) 노드 이동)
        private readonly LinkedList<string>                      _lruList
            = new LinkedList<string>();
        private readonly Dictionary<string, LinkedListNode<string>> _lruNodeMap
