        ///
        /// [호출 흐름]
        ///  1. _registry 캐시 조회 (O(1) 해시 탐색)
        ///  2. 캐시 미스(cache miss) 시 Resources.Load<T> 동기 호출
        ///     → Unity 내부 AssetBundle 레지스트리 또는 Resources 디렉터리 탐색
        ///     → Native Heap에 오브젝트 역직렬화(deserialization) 수행
        ///     → Managed Heap에 C# 래퍼 객체 할당, GC 루트 등록
        ///  3. AssetEntry 생성 후 _registry에 등록
        ///  4. 메모리 상한 초과 시 Eviction 수행
        ///  5. ReferenceCount.Acquire() 호출 후 반환
        /// </summary>
        public AssetEntry Load<T>(string resourcePath) where T : UnityEngine.Object
        {
            if (string.IsNullOrEmpty(resourcePath))
                throw new ArgumentNullException(nameof(resourcePath));

            _loadCallCount++;

