            T asset = Resources.Load<T>(resourcePath);

            if (asset == null)
                throw new ResourceNotFoundException(
                    $"[ResourceManager] 에셋 로드 실패: path='{resourcePath}', " +
                    $"type={typeof(T).FullName}");

            // ── AssetEntry 생성 및 등록 ──────────────────────
            var entry = new AssetEntry(resourcePath, asset);
            RegisterEntry(resourcePath, entry);

            // ── 메모리 상한 검사 및 Eviction ─────────────────
            EnforceMemoryBudget();

            entry.Acquire();
            return entry;
