## 1. 시스템 설계 개요

타일맵과 스프라이트 에셋의 런타임 관리를 위한 매니저 클래스는 다음과 같은 핵심 요구사항을 충족해야 합니다:
- `Resources` 폴더 내 에셋 경로를 기반으로 한 동기적 로드
- 로드된 에셋의 메모리 내 보관 및 참조 관리
- 중복 로드 방지를 위한 캐싱 메커니즘
- 에셋 식별을 위한 명확한 인터페이스

## 2. 메모리 관리 매니저 클래스 구현

```csharp
using UnityEngine;
using System.Collections.Generic;

public class AssetManager : MonoBehaviour
{
    private static AssetManager _instance;
    public static AssetManager Instance => _instance;

    // 에셋 캐시: 경로를 키로 한 Dictionary
    private Dictionary<string, Object> _assetCache;

    // 타일맵 전용 캐시 (선택적 분리)
    private Dictionary<string, Tilemap> _tilemapCache;

    // 스프라이트 전용 캐시 (선택적 분리)
    private Dictionary<string, Sprite> _spriteCache;

    private void Awake()
    {
        if (_instance != null && _instance != this)
        {
            Destroy(gameObject);
            return;
        }

        _instance = this;
        DontDestroyOnLoad(gameObject);

        _assetCache = new Dictionary<string, Object>();
        _tilemapCache = new Dictionary<string, Tilemap>();
        _spriteCache = new Dictionary<string, Sprite>();
    }

    // 제네릭 로드 메서드
    public T LoadAsset<T>(string resourcePath) where T : Object
    {
        // 캐시 확인
        if (_assetCache.TryGetValue(resourcePath, out Object cachedAsset))
        {
            if (cachedAsset is T typedAsset)
                return typedAsset;

            // 타입 불일치 시 캐시 제거
            _assetCache.Remove(resourcePath);
        }

        // Resources 동기 로드
        T loadedAsset = Resources.Load<T>(resourcePath);

        if (loadedAsset == null)
        {
            Debug.LogError($"Asset not found at path: {resourcePath}");
            return null;
        }

        // 캐시에 저장
        _assetCache[resourcePath] = loadedAsset;

        // 타입별 캐시에 추가 (선택적)
        if (loadedAsset is Tilemap tilemap)
            _tilemapCache[resourcePath] = tilemap;
        else if (loadedAsset is Sprite sprite)
            _spriteCache[resourcePath] = sprite;

        return loadedAsset;
    }

    // 타일맵 전용 로드 메서드
    public Tilemap LoadTilemap(string tilemapPath)
    {
        return LoadAsset<Tilemap>(tilemapPath);
    }

    // 스프라이트 전용 로드 메서드
    public Sprite LoadSprite(string spritePath)
    {
        return LoadAsset<Sprite>(spritePath);
    }

    // 캐시 클리어 메서드
    public void ClearCache()
    {
        _assetCache.Clear();
        _tilemapCache.Clear();
        _spriteCache.Clear();

        // 가비지 컬렉션 강제 실행 (선택적)
        Resources.UnloadUnusedAssets();
        System.GC.Collect();
    }

    // 특정 에셋 캐시 제거
    public bool UnloadAsset(string resourcePath)
    {
        bool removed = _assetCache.Remove(resourcePath);
        _tilemapCache.Remove(resourcePath);
        _spriteCache.Remove(resourcePath);

        return removed;
    }

    // 캐시 상태 확인
    public int GetCacheSize()
    {
        return _assetCache.Count;
    }
}
