## 1. 에셋 매니저 클래스 설계

```csharp
using UnityEngine;
using System.Collections.Generic;

public class ResourceManager : MonoBehaviour
{
    private static ResourceManager _instance;
    public static ResourceManager Instance
    {
        get
        {
            if (_instance == null)
            {
                GameObject go = new GameObject("ResourceManager");
                _instance = go.AddComponent<ResourceManager>();
                DontDestroyOnLoad(go);
            }
            return _instance;
        }
    }

    // 캐시: 로드된 에셋의 참조를 보관하여 GC 및 중복 로드 방지
    private Dictionary<string, Object> _loadedAssets = new Dictionary<string, Object>();

    // 제네릭 동기 로드 메서드
    public T LoadAsset<T>(string resourcesPath) where T : Object
    {
        // 이미 로드된 경우 캐시에서 반환
        if (_loadedAssets.TryGetValue(resourcesPath, out Object cached))
        {
            if (cached is T valid)
                return valid;
            else
            {
                Debug.LogError($"Type mismatch. Requested {typeof(T)} but cached type is {cached.GetType()} for path: {resourcesPath}");
                return null;
            }
        }

        // Resources.Load 동기 호출 (호출 스레드 블로킹)
        T loaded = Resources.Load<T>(resourcesPath);
        if (loaded == null)
        {
            Debug.LogError($"Failed to load asset at Resources path: {resourcesPath}");
            return null;
        }

        // 캐시에 저장 (Unity Object 참조 유지)
        _loadedAssets.Add(resourcesPath, loaded);
        return loaded;
    }

    // 특정 경로의 에셋 언로드 (참조 제거)
    public void UnloadAsset(string resourcesPath)
    {
        if (_loadedAssets.ContainsKey(resourcesPath))
        {
            _loadedAssets.Remove(resourcesPath);
        }
    }

    // 모든 에셋 언로드 및 Resources 시스템 정리
    public void UnloadAllAssets()
    {
        _loadedAssets.Clear();          // 모든 참조 해제
        Resources.UnloadUnusedAssets(); // Unity 엔진 내부에서 사용되지 않는 에셋 메모리 해제
    }

    // 특정 타입별 로드 편의 메서드 (타일맵 에셋 예시)
    public TileBase LoadTile(string resourcesPath) => LoadAsset<TileBase>(resourcesPath);
    public Sprite LoadSprite(string resourcesPath) => LoadAsset<Sprite>(resourcesPath);
    // 필요 시 Tilemap, Texture2D 등 추가
}
```

