```csharp
using UnityEngine;
using System.Collections.Generic;

public class AssetLoadManager : MonoBehaviour
{
    // 싱글톤 패턴 구현을 위한 인스턴스
    private static AssetLoadManager _instance;
    public static AssetLoadManager Instance
    {
        get
        {
            if (_instance == null)
            {
                _instance = FindObjectOfType<AssetLoadManager>();
                if (_instance == null)
                {
                    GameObject singletonObject = new GameObject("AssetLoadManager");
                    _instance = singletonObject.AddComponent<AssetLoadManager>();
                }
            }
            return _instance;
        }
    }

    // 로드된 에셋을 저장할 딕셔너리 (Key: 에셋 경로, Value: 로드된 에셋 객체)
    private Dictionary<string, Object> loadedAssets = new Dictionary<string, Object>();

    void Awake()
    {
        // 싱글톤 인스턴스 초기화 및 중복 방지
        if (_instance != null && _instance != this)
        {
            Destroy(this.gameObject);
        }
        else
        {
            _instance = this;
            DontDestroyOnLoad(this.gameObject); // 씬 전환 시에도 매니저 유지
        }
    }

    /// <summary>
    /// Resources 폴더에서 지정된 경로의 에셋을 동기적으로 로드합니다.
    /// </summary>
    /// <typeparam name="T">로드할 에셋의 타입 (예: Sprite, Tilemap)</typeparam>
    /// <param name="assetPath">Resources 폴더 내 에셋의 상대 경로 (확장자 제외)</param>
    /// <returns>로드된 에셋 객체. 실패 시 null 반환.</returns>
    public T LoadAsset<T>(string assetPath) where T : Object
    {
        // 에셋 경로의 유효성 검사 (간단한 예시)
        if (string.IsNullOrEmpty(assetPath))
        {
            Debug.LogError("Asset path cannot be null or empty.");
            return null;
        }

        // 이미 로드된 에셋인지 확인
        if (loadedAssets.ContainsKey(assetPath))
        {
            // 타입 캐스팅하여 반환
            return loadedAssets[assetPath] as T;
        }
        else
        {
            // Resources.Load를 사용하여 동기적으로 에셋 로드
            T asset = Resources.Load<T>(assetPath);

            if (asset != null)
            {
                // 로드 성공 시, 딕셔너리에 추가
                loadedAssets.Add(assetPath, asset);
                Debug.Log($"Asset loaded: {assetPath}");
                return asset;
            }
            else
            {
                Debug.LogError($"Failed to load asset at path: {assetPath}");
                return null;
            }
        }
    }

    /// <summary>
    /// 특정 경로의 에셋을 메모리에서 해제합니다.
    /// </summary>
    /// <param name="assetPath">해제할 에셋의 상대 경로 (확장자 제외)</param>
    public void UnloadAsset(string assetPath)
    {
        if (loadedAssets.ContainsKey(assetPath))
        {
            Object asset = loadedAssets[assetPath];
            loadedAssets.Remove(assetPath);

            // Resources.UnloadAsset은 에셋 자체를 메모리에서 해제합니다.
            // 더 이상 참조되지 않는 에셋은 가비지 컬렉션될 수 있습니다.
            Resources.UnloadAsset(asset);
            Debug.Log($"Asset unloaded: {assetPath}");
        }
        else
        {
            Debug.LogWarning($"Asset not found in loaded assets for unloading: {assetPath}");
        }
    }

    /// <summary>
    /// 모든 로드된 에셋을 메모리에서 해제합니다.
    /// </summary>
    public void UnloadAllAssets()
    {
        List<string> keys = new List<string>(loadedAssets.Keys);
        foreach (string assetPath in keys)
        {
            UnloadAsset(assetPath);
        }
        loadedAssets.Clear();
        Debug.Log("All assets unloaded.");
    }

    /// <summary>
    /// 지정된 경로의 에셋이 현재 로드되어 있는지 확인합니다.
    /// </summary>
    /// <param name="assetPath">확인할 에셋의 상대 경로 (확장자 제외)</param>
    /// <returns>로드되어 있으면 true, 아니면 false.</returns>
    public bool IsAssetLoaded(string assetPath)
    {
        return loadedAssets.ContainsKey(assetPath);
    }
}
```

### 2. 메모리 구조의 작동 원리

본 `AssetLoadManager` 클래스는 Unity의 `Resources` 폴더와 `Resources.Load` API를 중심으로 에셋을 관리합니다. 이 시스템의 핵심적인 메모리 구조는 다음과 같은 요소들로 구성됩니다.

#### 2.1. `Resources` 폴더

*   **정의:** `Resources` 폴더는 Unity 프로젝트 내에서 특별한 의미를 가지는 디렉토리입니다. 이 폴더 내에 저장된 모든 에셋은 Unity 에디터에 의해 빌드 프로세스의 일부로 포함되며, 런타임 시 `Resources.Load` API를 통해 접근 가능하게 됩니다.
*   **메모리 할당:** `Resources` 폴더 내의 에셋 자체는 프로젝트 빌드 시점에 Unity의 에셋 번들(Asset Bundle) 또는 최종 빌드 데이터에 포함됩니다. 그러나 이 시점에서는 아직 실제 런타임 메모리에 로드되지 않습니다. `Resources.Load`가 호출될 때 비로소 해당 에셋의 데이터가 **힙(Heap)** 메모리 영역에 할당되어 객체 인스턴스가 생성됩니다.
*   **단일 인스턴스:** `Resources` 폴더의 특성상, 동일한 경로의 에셋은 `Resources.Load`를 여러 번 호출하더라도 Unity 내부적으로 동일한 에셋 객체에 대한 참조를 반환합니다. 이는 메모리 중복 할당을 방지하고 효율성을 높입니다.

#### 2.2. `Resources.Load<T>(string assetPath)` API

*   **기능:** 이 API는 `Resources` 폴더 내에서 지정된 `assetPath`에 해당하는 에셋을 찾아 **동기적으로(synchronously)** 로드하는 역할을 수행합니다. `T`는 로드하고자 하는 에셋의 구체적인 타입(예: `Sprite`, `GameObject`, `Texture2D`, `Tilemap` 등)을 명시합니다.
*   **동기적 로딩:** 동기적 호출은 `Resources.Load` 호출이 완료될 때까지 현재 실행 스레드를 차단합니다. 즉, 에셋 로딩이 진행되는 동안 프로그램의 다른 작업은 대기 상태에 놓입니다. 이는 특히 크거나 복잡한 에셋을 로드할 때 프레임 드랍(frame drop)을 유발할 수 있으므로, 로딩 시점과 빈도에 대한 신중한 고려가 필요합니다.
*   **메모리 할당:** `Resources.Load`가 성공적으로 에셋을 찾으면, 해당 에셋의 데이터를 메모리(힙)에 로드하고, 해당 에셋 객체에 대한 참조를 반환합니다. 만약 에셋이 이미 메모리에 로드되어 있다면, 기존의 로드된 객체에 대한 참조를 반환합니다.

#### 2.3. `AssetLoadManager.loadedAssets` (Dictionary)

*   **구조:** `Dictionary<string, Object>` 타입의 `loadedAssets`는 `AssetLoadManager`가 직접 관리하는 **메모리 내 캐시(in-memory cache)** 역할을 수행합니다.
*   **용도:**
    *   **중복 로딩 방지:** `LoadAsset` 메서드는 에셋을 로드하기 전에 `loadedAssets` 딕셔너리에서 해당 경로의 에셋이 이미 존재하는지 확인합니다. 만약 존재한다면, `Resources.Load`를 다시 호출하지 않고 딕셔너리에 저장된 기존 에셋 객체의 참조를 반환합니다. 이는 불필요한 `Resources.Load` 호출 및 메모리 할당을 방지하여 성능을 최적화합니다.
    *   **참조 관리:** `loadedAssets` 딕셔너리는 현재 `AssetLoadManager`에 의해 추적되고 있는 모든 로드된 에셋에 대한 참조를 유지합니다.
    *   **메모리 해제 제어:** `UnloadAsset` 및 `UnloadAllAssets` 메서드는 이 딕셔너리를 사용하여 특정 에셋 또는 모든 에셋을 식별하고, `Resources.UnloadAsset`을 호출하여 해당 에셋의 메모리 할당을 해제하도록 지시합니다.
*   **메모리 할당:** `loadedAssets` 딕셔너리 자체는 힙 메모리에 할당되며, 각 키-값 쌍은 문자열 키와 `Object` 타입의 참조를 저장합니다. `Object` 타입의 값은 실제 로드된 에셋 객체(Sprite, Tilemap 등)에 대한 참조입니다.

#### 2.4. `Resources.UnloadAsset(Object asset)` API

*   **기능:** 이 API는 Unity에게 특정 에셋 객체(`Object` 타입)를 메모리에서 해제하도록 지시합니다.
*   **메모리 해제:** `Resources.UnloadAsset`이 호출되면, 해당 에셋 객체와 관련된 원시 데이터(텍스처 데이터, 메시 데이터 등)가 힙 메모리에서 제거됩니다. 이 작업은 비동기적으로 수행될 수 있으며, 즉시 메모리가 해제되지 않을 수도 있습니다.
*   **참조 관리의 중요성:** `Resources.UnloadAsset`은 해당 에셋에 대한 **다른 참조가 없을 때** 효과적으로 메모리를 해제합니다. 만약 다른 스크립트나 컴포넌트에서 해당 에셋 객체에 대한 참조를 여전히 가지고 있다면, 가비지 컬렉션(Garbage Collection)에 의해 메모리가 해제되지 않거나, 해제되더라도 즉시 회수되지 않을 수 있습니다. 따라서 `AssetLoadManager`는 `loadedAssets` 딕셔너리를 통해 자체적으로 참조를 관리하며, `UnloadAsset` 호출 시 이 딕셔너리에서 해당 참조를 제거함으로써 관리 대상에서 제외시킵니다.

### 3. 시스템의 동작 흐름 요약

1.  **에셋 로딩 요청:** 게임 내에서 특정 에셋(타일맵, 스프라이트 등)이 필요할 때, 해당 에셋의 `Resources` 폴더 내 상대 경로를 사용하여 `AssetLoadManager.Instance.LoadAsset<T>(assetPath)` 메서드를 호출합니다.
2.  **캐시 확인:** `AssetLoadManager`는 먼저 `loadedAssets` 딕셔너리에서 해당 `assetPath`를 키로 하는 항목이 있는지 확인합니다.
3.  **캐시 히트 (Cache Hit):** 만약 딕셔너리에 해당 에셋이 이미 존재한다면, 저장된 `Object` 참조를 캐스팅하여 즉시 반환합니다. 이 경우 `Resources.Load`는 호출되지 않습니다.
4.  **캐시 미스 (Cache Miss):** 만약 딕셔너리에 해당 에셋이 없다면, `Resources.Load<T>(assetPath)` API를 호출하여 `Resources` 폴더에서 에셋을 **동기적으로** 로드합니다.
5.  **에셋 로드 및 할당:** `Resources.Load`가 성공하면, 해당 에셋의 데이터가 힙 메모리에 할당되고, `AssetLoadManager`는 이 로드된 에셋 객체에 대한 참조를 `loadedAssets` 딕셔너리에 `assetPath`를 키로 하여 저장합니다. 이후 로드된 에셋 객체의 참조를 반환합니다.
6.  **에셋 사용:** 반환된 에셋 객체는 게임 로직에서 타일맵 컴포넌트의 `sprite` 속성을 설정하거나, 스프라이트 렌더러의 `sprite` 속성을 설정하는 등 즉시 사용됩니다.
7.  **에셋 해제 요청:** 더 이상 필요하지 않은 에셋은 `AssetLoadManager.Instance.UnloadAsset(assetPath)` 메서드를 호출하여 메모리에서 해제를 요청합니다.
8.  **메모리 해제:** `AssetLoadManager`는 `loadedAssets` 딕셔너리에서 해당 에셋의 참조를 제거하고, `Resources.UnloadAsset`을 호출하여 Unity에게 해당 에셋의 메모리 할당을 해제하도록 지시합니다.

이러한 구조를 통해 `AssetLoadManager`는 `Resources` 폴더의 에셋들을 효율적으로 관리하며, 동기적 로딩 패턴을 통해 즉각적인 상태 업데이트를 보장합니다. 다만, 동기적 로딩의 특성상 대규모 에셋 로딩 시 성능 저하 가능성을 인지하고, 로딩 시점을 신중하게 설계해야 합니다.

수천 개의 타일맵 및 스프라이트 에셋을 `Resources` 시스템을 통해 관리하는 것은 메모리 관리 측면에서 객체 생명주기(Lifecycle)의 명시적 제어가 필수적입니다. 요청하신 설계안과 작동 원리는 다음과 같습니다.

### 1. 리소스 매니저 클래스 (C#)

본 설계는 `Dictionary<string, Object>`를 사용하여 리소스의 캐싱 계층을 구현하며, 메모리 중복 할당을 방지합니다.

```csharp
using System.Collections.Generic;
using UnityEngine;

public class ResourceManager
{
    private readonly Dictionary<string, Object> _resourceCache = new Dictionary<string, Object>();

    /// <summary>
    /// Resources.Load를 통한 동기적 에셋 로드 및 캐싱
    /// </summary>
    public T Load<T>(string path) where T : Object
    {
        if (_resourceCache.TryGetValue(path, out Object cachedAsset))
        {
            return (T)cachedAsset;
        }

        T asset = Resources.Load<T>(path);
        if (asset != null)
        {
            _resourceCache.Add(path, asset);
        }
        return asset;
    }

    /// <summary>
    /// 특정 에셋의 메모리 할당 해제 및 캐시 제거
    /// </summary>
    public void Unload(string path)
    {
        if (_resourceCache.TryGetValue(path, out Object asset))
        {
            _resourceCache.Remove(path);
            Resources.UnloadAsset(asset);
        }
    }

    /// <summary>
    /// 사용되지 않는 모든 에셋 정리
    /// </summary>
    public void UnloadAll()
    {
        _resourceCache.Clear();
        Resources.UnloadUnusedAssets();
    }
}
```

---

### 2. 메모리 구조 및 작동 원리

#### 1) Resources 시스템의 메모리 할당 (Allocation)
`Resources.Load`는 Unity의 `Resources` 폴더 내 에셋을 가상 파일 시스템에서 식별하여 **힙(Heap) 메모리** 영역으로 복사합니다. 이 과정에서 에셋은 `UnityEngine.Object`를 상속받는 구체 클래스(예: `Sprite`, `Texture2D`, `TileBase`) 형태로 인스턴스화됩니다. 호출 즉시 동기적으로 메인 스레드에서 처리가 완료되므로, 에셋의 크기가 클 경우 프레임 드롭(Frame Drop)이 발생할 수 있습니다.

#### 2) 캐싱 계층 (Caching Layer)
`Dictionary`를 통한 캐싱은 동일한 에셋에 대한 다중 로드 요청 시, 중복된 메모리 할당을 방지하는 **참조 카운팅(Reference Counting)**의 보조 수단으로 작동합니다. 메모리 주소(Reference)를 키-값 쌍으로 유지함으로써, 런타임 중에 동일한 자산을 재사용할 때 발생할 수 있는 I/O 부하와 메모리 파편화(Fragmentation)를 억제합니다.

#### 3) 가비지 컬렉션 및 메모리 해제 (Deallocation)
*   **Resources.UnloadAsset**: 특정 에셋에 대한 메모리 참조를 즉각적으로 해제합니다. 이는 `Resources.Load`로 로드된 에셋에 한하여 명시적으로 메모리를 비울 수 있는 수단입니다.
*   **Resources.UnloadUnusedAssets**: 현재 씬의 객체 그래프(Object Graph)를 순회하며, 더 이상 참조되지 않는 객체를 식별하여 메모리에서 제거합니다. 이는 엔진 내부의 **가비지 컬렉터(Garbage Collector)**와 연동되어 작동하며, 힙 메모리의 가용 공간을 확보합니다.

#### 4) 런타임 관리의 제약사항
`Resources` 폴더는 빌드 시 모든 에셋을 단일 아카이브 파일로 묶어 관리합니다. 따라서 에셋의 개수가 수천 단위로 증가할 경우, 인덱싱 테이블의 크기가 비대해져 초기 로딩 속도가 저하될 수 있습니다. 또한, `Resources.Load`를 통한 동기적 방식은 에셋의 참조가 끊어지지 않는 한 메모리에 잔류하므로, `Unload` 메서드를 호출하지 않을 경우 메모리 누수(Memory Leak)가 발생할 가능성이 높습니다. 따라서 `Dictionary`의 생명주기를 게임의 씬 전환이나 구역(Zone) 이동 시점에 맞추어 동기화하는 로직이 필수적입니다.

Unity 2D 탑뷰 게임 프로젝트에서 `Resources` API를 활용하여 수천 개의 타일맵 및 스프라이트 에셋을 동기적으로 로드, 캐싱, 관리 및 해제하는 시스템 설계안과 C# 구현 코드, 그리고 이에 따른 Unity 엔진 내부의 메모리 구조 작동 원리를 설명합니다.

