### 1. 에셋 관리 매니저 클래스 (`ResourceManager.cs`)

아래 클래스는 싱글톤 패턴(Singleton Pattern)을 기반으로 하며, `Dictionary` 자료구조를 사용하여 로드된 에셋의 메모리 주소를 참조(Reference) 형태로 캐싱합니다. 이를 통해 중복 로드를 방지하고 CPU 사이클 및 가비지 컬렉션(GC) 부하를 최소화합니다.

```csharp
using System;
using System.Collections.Generic;
using UnityEngine;

public class ResourceManager : MonoBehaviour
{
    private static ResourceManager _instance;
    public static ResourceManager Instance
    {
        get
        {
            if (_instance == null)
            {
                GameObject go = new GameObject("@ResourceManager");
                _instance = go.AddComponent<ResourceManager>();
                DontDestroyOnLoad(go);
            }
            return _instance;
        }
    }

    // 에셋 타입별 캐시 컨테이너 (메모리 주소 참조 보존)
    private readonly Dictionary<string, Sprite> _spriteCache = new Dictionary<string, Sprite>();
    private readonly Dictionary<string, Texture2D> _textureCache = new Dictionary<string, Texture2D>();
    private readonly Dictionary<string, GameObject> _prefabCache = new Dictionary<string, GameObject>();

    /// <summary>
    /// Resources 폴더로부터 T 타입의 에셋을 동기적으로 로드 및 캐싱하여 반환합니다.
    /// </summary>
    public T Load<T>(string path) where T : UnityEngine.Object
    {
        if (string.IsNullOrEmpty(path))
        {
            Debug.LogError("[ResourceManager] Path is null or empty.");
            return null;
        }

        Type type = typeof(T);

        // 캐시 확인 및 반환 (캐시 히트)
        if (type == typeof(Sprite))
        {
            if (_spriteCache.TryGetValue(path, out Sprite sprite))
                return sprite as T;
        }
        else if (type == typeof(Texture2D))
        {
            if (_textureCache.TryGetValue(path, out Texture2D texture))
                return texture as T;
        }
        else if (type == typeof(GameObject))
        {
            if (_prefabCache.TryGetValue(path, out GameObject prefab))
                return prefab as T;
        }

        // 캐시 미스 시 Resources.Load 동기 호출 실행
        T resource = Resources.Load<T>(path);

        if (resource == null)
        {
            Debug.LogError($"[ResourceManager] Failed to load resource at: {path}");
            return null;
        }

        // 로드된 에셋의 참조를 각 딕셔너리에 등록
        RegisterToCache(path, resource);

        return resource;
    }

    private void RegisterToCache<T>(string path, T resource) where T : UnityEngine.Object
    {
        if (resource is Sprite sprite)
        {
            _spriteCache[path] = sprite;
        }
        else if (resource is Texture2D texture)
        {
            _textureCache[path] = texture;
        }
        else if (resource is GameObject prefab)
        {
            _prefabCache[path] = prefab;
        }
    }

    /// <summary>
    /// 특정 단일 에셋에 대한 캐시 참조를 제거하고 메모리에서 해제합니다.
    /// </summary>
    public void UnloadAsset<T>(string path) where T : UnityEngine.Object
    {
        Type type = typeof(T);

        if (type == typeof(Sprite))
        {
            if (_spriteCache.TryGetValue(path, out Sprite sprite))
            {
                _spriteCache.Remove(path);
                Resources.UnloadAsset(sprite);
            }
        }
        else if (type == typeof(Texture2D))
        {
            if (_textureCache.TryGetValue(path, out Texture2D texture))
            {
                _textureCache.Remove(path);
                Resources.UnloadAsset(texture);
            }
        }
    }

    /// <summary>
    /// 캐시된 모든 에셋 참조를 초기화하고, 참조가 유실된 에셋들을 가비지 컬렉션을 통해 비디오 메모리 및 힙 메모리에서 완전 언로드합니다.
    /// </summary>
    public void ClearAllCache()
    {
        _spriteCache.Clear();
        _textureCache.Clear();
        _prefabCache.Clear();

        // 참조가 끊긴 Unused Assets에 대한 물리 메모리 해제 프로세스 트리거 (비동기 수행되나 동기식 흐름 제어 가능)
        AsyncOperation unloadOp = Resources.UnloadUnusedAssets();

        // 동기적 흐름 보장을 위해 언로드 완료 시점까지 블로킹 루프 수행 (필요 시 선택적 사용)
        while (!unloadOp.isDone)
        {
            // 동기식 대기 프로세스
        }

        GC.Collect();
    }
}
```

