### 1. 시스템 설계: `ResourceManager` 클래스 구현

본 클래스는 `Resources` 폴더 내의 에셋을 런타임에 동기적으로 로드하여 메모리에 상주시키고, 이를 키(Key) 값으로 관리하여 중복 로드를 방지하고 빠른 접근을 보장하는 싱글톤(Singleton) 패턴으로 설계되었습니다.

```csharp
using System.Collections.Generic;
using UnityEngine;

public class ResourceManager : MonoBehaviour
{
    // 싱글톤 인스턴스: 전역 접근점을 제공하여 객체 생성을 제한합니다.
    private static ResourceManager _instance;
    public static ResourceManager Instance
    {
        get
        {
            if (_instance == null)
            {
                var go = new GameObject("ResourceManager");
                _instance = go.AddComponent<ResourceManager>();
                DontDestroyOnLoad(go); // 씬 전환 시에도 객체가 파괴되지 않도록 설정
            }
            return _instance;
        }
    }

    // 메모리에 로드된 에셋을 관리하는 해시 테이블(Hash Table) 기반의 컬렉션입니다.
    // Key: 에셋의 상대 경로 및 이름 (문자열)
    // Value: 로드된 UnityEngine.Object (스프라이트, 타일맵 등)
    private Dictionary<string, Object> _resourceCache = new Dictionary<string, Object>();

    /// <summary>
    /// 지정된 경로의 에셋을 동기적으로 로드하여 캐시에 저장하고 반환합니다.
    /// </summary>
    /// <typeparam name="T">로드할 에셋의 타입 (Sprite, Tilemap 등)</typeparam>
    /// <param name="path">Resources 폴더 하위의 상대 경로 (확장자 제외)</param>
    /// <returns>로드된 에셋 객체</returns>
    public T Load<T>(string path) where T : Object
    {
        // 1. 캐시 확인: 이미 로드된 에셋인지 검사하여 중복 로드를 방지합니다.
        if (_resourceCache.TryGetValue(path, out Object cachedAsset))
        {
            // 캐시된 객체를 요청한 타입으로 캐스팅하여 반환합니다.
            return cachedAsset as T;
        }

        // 2. 동기적 로드: Resources.Load API를 호출하여 파일 시스템으로부터 에셋을 로드합니다.
        // 이 호출은 메인 스레드를 차단(Blocking)하며 즉시 완료됩니다.
        T loadedAsset = Resources.Load<T>(path);

        if (loadedAsset == null)
        {
            Debug.LogError($"[ResourceManager] 에셋 로드 실패: 경로 '{path}'에 해당하는 리소스가 존재하지 않습니다.");
            return null;
        }

        // 3. 캐시 등록: 로드된 에셋을 딕셔너리에 등록하여 추후 접근 시 검색 비용을 절감합니다.
        _resourceCache.Add(path, loadedAsset);

        return loadedAsset;
    }

    /// <summary>
    /// 특정 에셋 또는 전체 캐시를 해제하고 메모리를 정리합니다.
    /// </summary>
    /// <param name="path">특정 에셋 경로 (null일 경우 전체 해제)</param>
    public void Unload(string path = null)
    {
        if (string.IsNullOrEmpty(path))
        {
            // 전체 해제: 캐시 내 모든 에셋을 순회하며 언로드 수행
            foreach (var pair in _resourceCache)
            {
                Resources.UnloadAsset(pair.Value);
            }
            _resourceCache.Clear();
        }
        else if (_resourceCache.TryGetValue(path, out Object asset))
        {
            // 개별 해제
            Resources.UnloadAsset(asset);
            _resourceCache.Remove(path);
        }
    }
}
```

