# 5. 사용 예시

## 5.1 스프라이트 로드

```csharp
using UnityEngine;

public class SpriteConsumer : MonoBehaviour
{
    [SerializeField] private SpriteRenderer spriteRenderer;

    private const string SpritePath = "Sprites/Terrain/grass_01";

    private void Start()
    {
        Sprite sprite = ResourceManager.Instance.Load<Sprite>(SpritePath);
        spriteRenderer.sprite = sprite;
    }

    private void OnDestroy()
    {
        if (ResourceManager.Instance != null)
            ResourceManager.Instance.Release(SpritePath);
    }
}
```

## 5.2 타일맵 프리팹 로드 및 인스턴스화

```csharp
using UnityEngine;

public class TilemapChunkLoader : MonoBehaviour
{
    [SerializeField] private Transform parentTransform;
    private GameObject currentChunkInstance;

    private string currentChunkPath;

    public void LoadChunk(string chunkPath)
    {
        if (!string.IsNullOrEmpty(currentChunkPath))
        {
            UnloadChunk();
        }

        GameObject prefab = ResourceManager.Instance.Load<GameObject>(chunkPath);
        currentChunkInstance = Instantiate(prefab, parentTransform);
        currentChunkPath = chunkPath;
    }

    public void UnloadChunk()
    {
        if (currentChunkInstance != null)
        {
            Destroy(currentChunkInstance);
            currentChunkInstance = null;
        }

        if (!string.IsNullOrEmpty(currentChunkPath))
        {
            ResourceManager.Instance.Release(currentChunkPath);
            ResourceManager.Instance.Unload(currentChunkPath);
            currentChunkPath = null;
        }
    }
}
```

