## 3) 에셋 매니저 클래스 예시

아래 코드는 다음을 지원합니다.
- `Sprite`, `TileBase`, `Tilemap`, `GameObject` 등의 동기 로드
- 제네릭 기반 타입 안전성
- 캐시 저장
- 참조 카운트 기반 해제
- 전체 해제 기능

> 참고: 실제 타일맵 데이터는 보통 `Tilemap` 컴포넌트 자체보다 `TileBase`, `Tile`, `Tilemap`이 포함된 프리팹 또는 `ScriptableObject` 형태로 관리하는 편이 더 일반적입니다. 아래 예시는 로드/캐시 구조를 보여주기 위한 것입니다.

```csharp
using System;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.Tilemaps;

public sealed class ResourceAssetManager : MonoBehaviour
{
    public static ResourceAssetManager Instance { get; private set; }

    // 경로 + 타입 기준 캐시
    private readonly Dictionary<string, UnityEngine.Object> _cache = new Dictionary<string, UnityEngine.Object>();

    // 참조 횟수 관리
    private readonly Dictionary<string, int> _refCount = new Dictionary<string, int>();

    // 선택적: 타입별 등록 목록
    private readonly HashSet<string> _loadedKeys = new HashSet<string>();

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            Destroy(gameObject);
            return;
        }

        Instance = this;
        DontDestroyOnLoad(gameObject);
    }

    private string MakeKey<T>(string path) where T : UnityEngine.Object
    {
        return $"{typeof(T).FullName}:{path}";
    }

    public T Load<T>(string path) where T : UnityEngine.Object
    {
        if (string.IsNullOrWhiteSpace(path))
        {
            Debug.LogError("Load path is null or empty.");
            return null;
        }

        string key = MakeKey<T>(path);

        if (_cache.TryGetValue(key, out UnityEngine.Object cached))
        {
            _refCount[key]++;
            return cached as T;
        }

        T asset = Resources.Load<T>(path);

        if (asset == null)
        {
            Debug.LogError($"Resources.Load failed: {typeof(T).Name} / {path}");
            return null;
        }

        _cache[key] = asset;
        _refCount[key] = 1;
        _loadedKeys.Add(key);

        return asset;
    }

    public T[] LoadAll<T>(string path) where T : UnityEngine.Object
    {
        if (string.IsNullOrWhiteSpace(path))
        {
            Debug.LogError("LoadAll path is null or empty.");
            return Array.Empty<T>();
        }

        string key = MakeKey<T>(path);

        if (_cache.TryGetValue(key, out UnityEngine.Object cached) && cached is T[] typedArray)
        {
            _refCount[key]++;
            return typedArray;
        }

        T[] assets = Resources.LoadAll<T>(path);

        if (assets == null || assets.Length == 0)
        {
            Debug.LogWarning($"Resources.LoadAll returned empty: {typeof(T).Name} / {path}");
            return Array.Empty<T>();
        }

        // 배열 자체를 캐시
        _cache[key] = assets as UnityEngine.Object;
        _refCount[key] = 1;
        _loadedKeys.Add(key);

        return assets;
    }

    public void Release<T>(string path) where T : UnityEngine.Object
    {
        string key = MakeKey<T>(path);

        if (!_refCount.TryGetValue(key, out int count))
            return;

        count--;
        if (count <= 0)
        {
            _refCount.Remove(key);

            if (_cache.TryGetValue(key, out UnityEngine.Object obj))
            {
                _cache.Remove(key);
                _loadedKeys.Remove(key);
                Resources.UnloadAsset(obj);
            }
        }
        else
        {
            _refCount[key] = count;
        }
    }

    public void ReleaseAll()
    {
        foreach (var kv in _cache)
        {
            if (kv.Value != null)
                Resources.UnloadAsset(kv.Value);
        }

        _cache.Clear();
        _refCount.Clear();
        _loadedKeys.Clear();

        Resources.UnloadUnusedAssets();
    }

    public bool IsLoaded<T>(string path) where T : UnityEngine.Object
    {
        return _cache.ContainsKey(MakeKey<T>(path));
    }

    public T GetLoaded<T>(string path) where T : UnityEngine.Object
    {
        string key = MakeKey<T>(path);
        if (_cache.TryGetValue(key, out UnityEngine.Object obj))
            return obj as T;

        return null;
    }
}
```

