## **2. 구현 코드: `TilemapSpriteManager.cs`**

```csharp
using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// 수천 개의 타일맵과 스프라이트 에셋을 동기적 로드 및 캐시 관리하는 매니저 클래스입니다.
/// </summary>
public class TilemapSpriteManager : MonoBehaviour
{
    // Singleton 인스턴스
    public static TilemapSpriteManager Instance { get; private set; }

    // 에셋 캐시를 위한 딕셔너리
    private Dictionary<string, UnityEngine.Object> _cachedAssets = new Dictionary<string, UnityEngine.Object>();

    // 에셋 로드 경로 전위부
    private const string TILEMAP_PATH = "Tilemaps/";
    private const string SPRITE_PATH = "Sprites/";

    private void Awake()
    {
        // Singleton 패턴 초기화
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }
        else
        {
            Destroy(gameObject);
        }
    }

    /// <summary>
    /// 지정된 경로에서 타일맵 에셋을 로드하고 캐시에 저장합니다.
    /// </summary>
    /// <typeparam name="T">로드할 에셋 유형 (예: Tilemap, Tile)</typeparam>
    /// <param name="tilemapName">에셋 이름</param>
    /// <returns>로드된 에셋</returns>
    public T LoadTilemapAsset<T>(string tilemapName) where T : UnityEngine.Object
    {
        string fullPath = TILEMAP_PATH + tilemapName;

        // 캐시 확인
        if (_cachedAssets.TryGetValue(fullPath, out UnityEngine.Object cachedAsset) && cachedAsset != null)
        {
            return cachedAsset as T;
        }

        // 동기적 로드
        T asset = Resources.Load<T>(fullPath);

        // 로드 실패 시 처리
        if (asset == null)
        {
            Debug.LogError($"[TilemapSpriteManager] 에셋 로드 실패: {fullPath}");
            return null;
        }

        // 캐시에 저장
        _cachedAssets[fullPath] = asset;

        return asset;
    }

    /// <summary>
    /// 지정된 경로에서 스프라이트 에셋을 로드하고 캐시에 저장합니다.
    /// </summary>
    /// <param name="spriteName">에셋 이름</param>
    /// <returns>로드된 스프라이트</returns>
    public Sprite LoadSpriteAsset(string spriteName)
    {
        string fullPath = SPRITE_PATH + spriteName;

        // 캐시 확인
        if (_cachedAssets.TryGetValue(fullPath, out UnityEngine.Object cachedAsset) && cachedAsset != null)
        {
            return cachedAsset as Sprite;
        }

        // 동기적 로드
        Sprite sprite = Resources.Load<Sprite>(fullPath);

        // 로드 실패 시 처리
        if (sprite == null)
        {
            Debug.LogError($"[TilemapSpriteManager] 에셋 로드 실패: {fullPath}");
            return null;
        }

        // 캐시에 저장
        _cachedAssets[fullPath] = sprite;

        return sprite;
    }

    /// <summary>
    /// 지정된 경로에서 일반 에셋을 로드하고 캐시에 저장합니다.
    /// </summary>
    /// <typeparam name="T">로드할 에셋 유형</typeparam>
    /// <param name="assetPath">에셋 경로</param>
    /// <returns>로드된 에셋</returns>
    public T LoadAsset<T>(string assetPath) where T : UnityEngine.Object
    {
        // 캐시 확인
        if (_cachedAssets.TryGetValue(assetPath, out UnityEngine.Object cachedAsset) && cachedAsset != null)
        {
            return cachedAsset as T;
        }

        // 동기적 로드
        T asset = Resources.Load<T>(assetPath);

        // 로드 실패 시 처리
        if (asset == null)
        {
            Debug.LogError($"[TilemapSpriteManager] 에셋 로드 실패: {assetPath}");
            return null;
        }

        // 캐시에 저장
        _cachedAssets[assetPath] = asset;

        return asset;
    }

    /// <summary>
    /// 캐시된 모든 에셋을 메모리에서 해제합니다.
    /// </summary>
    public void ReleaseAllAssets()
    {
        foreach (var kvp in _cachedAssets)
        {
            if (kvp.Value != null)
            {
                Resources.UnloadUnusedAssets();
            }
        }
        _cachedAssets.Clear();
    }

    /// <summary>
    /// 지정된 경로의 캐시된 에셋을 메모리에서 해제합니다.
    /// </summary>
    /// <param name="assetPath">해제할 에셋 경로</param>
    public void ReleaseAsset(string assetPath)
    {
        if (_cachedAssets.TryGetValue(assetPath, out UnityEngine.Object asset))
        {
            _cachedAssets.Remove(assetPath);
            Resources.UnloadUnusedAssets();
        }
    }
}
```

