## 7. 고급 예제: 커스텀 Deleter

```cpp
#include <memory>
#include <cstdlib>

class CustomResource {
public:
    CustomResource() { std::cout << "Custom resource acquired\n"; }
    ~CustomResource() { std::cout << "Custom resource destroyed\n"; }
};

// 커스텀 삭제 전략
struct CustomDeleter {
    void operator()(CustomResource* ptr) const {
        std::cout << "Custom deleter invoked\n";
        delete ptr;
    }
};

int main() {
    // 1. 기본 Deleter (delete)
    std::unique_ptr<CustomResource> res1(new CustomResource());

    // 2. 커스텀 Deleter
    std::unique_ptr<CustomResource, CustomDeleter> res2(
        new CustomResource(), CustomDeleter()
    );

    // 3. Lambda Deleter
    auto lambda_deleter = [](CustomResource* ptr) {
        std::cout << "Lambda deleter\n";
        delete ptr;
    };
    std::unique_ptr<CustomResource, decltype(lambda_deleter)> res3(
        new CustomResource(), lambda_deleter
    );

    return 0;
}
```

