## 3. C++17 표준 준수 구현: `std::unique_ptr` 기반 독점 소유권 이전

### 3.1 `std::unique_ptr`의 내부 구현 원리

```cpp
// unique_ptr의 개념적 구현 (설명 목적)
template <typename T, typename Deleter = std::default_delete<T>>
class unique_ptr {
private:
    T*      ptr_;      // 관리 대상 객체의 포인터
    Deleter deleter_;  // 자원 해제 정책 (기본: delete 호출)

public:
    // 복사 생성자 = delete → 복사 불가능 (독점 소유권 보장)
    unique_ptr(const unique_ptr&)            = delete;
    unique_ptr& operator=(const unique_ptr&) = delete;

    // 이동 생성자: 소유권 이전 (rvalue reference 활용)
    unique_ptr(unique_ptr&& other) noexcept
        : ptr_(other.ptr_), deleter_(std::move(other.deleter_)) {
        other.ptr_ = nullptr; // 원본의 소유권 박탈
    }

    // 이동 대입 연산자
    unique_ptr& operator=(unique_ptr&& other) noexcept {
        if (this != &other) {
            reset();                          // 기존 자원 해제
            ptr_     = other.ptr_;
            deleter_ = std::move(other.deleter_);
            other.ptr_ = nullptr;
        }
        return *this;
    }

    ~unique_ptr() noexcept {
        if (ptr_) deleter_(ptr_); // 커스텀 삭제자 또는 기본 delete 호출
    }
};
```

### 3.2 완전한 C++17 소유권 이전 모듈 구현

```cpp
/**
 * @file ownership_transfer_module.cpp
 * @brief C++17 표준 준수 독점 소유권 이전 모듈
 * @standard ISO/IEC 14882:2017 (C++17)
 */

#include <memory>
#include <utility>
#include <stdexcept>
#include <string>
#include <vector>
#include <iostream>
#include <cassert>
#include <type_traits>

// ============================================================
// Section 1: 관리 대상 도메인 객체 정의
// ============================================================

class ManagedResource {
public:
    explicit ManagedResource(int id, std::string label)
        : resource_id_(id)
        , label_(std::move(label))
        , is_valid_(true)
    {
        std::cout << "[CONSTRUCT] ManagedResource id=" 
                  << resource_id_ << "\n";
    }

    ~ManagedResource() noexcept {
        std::cout << "[DESTRUCT]  ManagedResource id=" 
                  << resource_id_ << "\n";
    }

    // 복사 비활성화: 자원의 복제 방지
    ManagedResource(const ManagedResource&)            = delete;
    ManagedResource& operator=(const ManagedResource&) = delete;

    // 이동 허용: 소유권 이전 지원
    ManagedResource(ManagedResource&& other) noexcept
        : resource_id_(other.resource_id_)
        , label_(std::move(other.label_))
        , is_valid_(other.is_valid_)
    {
        other.is_valid_ = false;
    }

    void execute() const {
        if (!is_valid_) {
            throw std::runtime_error("무효 상태의 자원에 접근 시도");
        }
        std::cout << "[EXECUTE]   id=" << resource_id_ 
                  << " label=" << label_ << "\n";
    }

    [[nodiscard]] int  id()       const noexcept { return resource_id_; }
    [[nodiscard]] bool is_valid() const noexcept { return is_valid_;    }

private:
    int         resource_id_;
    std::string label_;
    bool        is_valid_;
};

// ============================================================
// Section 2: 소유권 이전 정책 추상화
// ============================================================

/**
 * @brief 소유권 이전 인터페이스
 * 
 * 소유권의 단방향 이전(transfer)을 명시적으로 표현하기 위한
 * 순수 가상 인터페이스. 반환 타입으로 unique_ptr을 사용하여
 * 컴파일 타임에 소유권 이전 의도를 명시.
 */
class IResourceConsumer {
public:
    virtual ~IResourceConsumer() = default;

    /**
     * @brief 소유권 수신 인터페이스
     * @param resource rvalue reference로 전달된 unique_ptr
     *        → 호출 시점에 소유권이 이 함수로 이전됨
     */
    virtual void acquire(std::unique_ptr<ManagedResource> resource) = 0;

    [[nodiscard]] virtual bool has_resource() const noexcept = 0;
};

// ============================================================
// Section 3: 소유권 수신 객체 구현
// ============================================================

class ResourceProcessor final : public IResourceConsumer {
public:
    explicit ResourceProcessor(std::string name)
        : processor_name_(std::move(name))
        , owned_resource_(nullptr)
    {}

    /**
     * @brief 소유권 이전 수신
     * 
     * std::move를 통해 unique_ptr의 이동 생성자가 호출됨:
     * 1. 호출자의 unique_ptr.ptr_ → this->owned_resource_.ptr_
     * 2. 호출자의 unique_ptr.ptr_ = nullptr (소유권 박탈)
     * 
     * 결과: 단일 힙 객체에 대한 소유권이 정확히 하나의
     *       unique_ptr에만 귀속됨 (불변 조건 유지)
     */
    void acquire(std::unique_ptr<ManagedResource> resource) override {
        if (!resource) {
            throw std::invalid_argument(
                "nullptr 소유권 이전 시도: 유효하지 않은 연산"
            );
        }
        owned_resource_ = std::move(resource);
        std::cout << "[ACQUIRE]   " << processor_name_ 
                  << " → resource id=" << owned_resource_->id() << "\n";
    }

    void process() const {
        if (!owned_resource_) {
            throw std::logic_error("소유 자원 없음: process() 호출 불가");
        }
        owned_resource_->execute();
    }

    /**
     * @brief 소유권 방출
     * @return 소유하던 unique_ptr (호출 후 this는 nullptr 상태)
     * 
     * std::move 적용 후 owned_resource_는 nullptr로 전이됨.
     * 반환된 unique_ptr이 새로운 소유자가 됨.
     */
    [[nodiscard]] std::unique_ptr<ManagedResource> release() noexcept {
        std::cout << "[RELEASE]   " << processor_name_ << " 소유권 방출\n";
        return std::move(owned_resource_);
    }

    [[nodiscard]] bool has_resource() const noexcept override {
        return owned_resource_ != nullptr;
    }

private:
    std::string                      processor_name_;
    std::unique_ptr<ManagedResource> owned_resource_;
};

// ============================================================
// Section 4: 소유권 이전 팩토리 및 전달 함수
// ============================================================

/**
 * @brief 팩토리 함수
 * 
 * std::make_unique 사용:
 * - new 연산자 직접 사용 대비 예외 안전성 보장
 * - 할당과 unique_ptr 초기화가 단일 표현식 내에서 완료됨
 * - 반환 시 NRVO(Named Return Value Optimization) 또는
 *   이동 의미론에 의해 추가 복사 없이 소유권 이전
 */
[[nodiscard]]
std::unique_ptr<ManagedResource> create_resource(int id, std::string label) {
    return std::make_unique<ManagedResource>(id, std::move(label));
}

/**
 * @brief 소유권 이전 체인 함수
 * 
 * 함수 매개변수로 unique_ptr을 값으로 수신:
 * → 호출 시점에 인자의 소유권이 이 함수의 지역 변수로 이전됨
 * → 함수 반환 시 다시 호출자에게 소유권 이전 (이동 반환)
 */
[[nodiscard]]
std::unique_ptr

# C++17 환경에서의 메모리 관리와 스마트 포인터

## 중요 선행 공지

**C++17 표준에서 `std::auto_ptr`은 공식적으로 제거(deprecated)되었습니다.** 따라서 이 응답은 학술적 목적으로 `std::auto_ptr`의 작동 원리를 설명하고, 동시에 C++17 준수 코드로는 `std::unique_ptr`을 사용한 구현을 제시합니다.

---

## 1. std::auto_ptr의 내부 메모리 관리 원리

### 1.1 소유권 이전 메커니즘 (Move Semantics의 전신)

```cpp
template<typename T>
class AutoPtr {
private:
    T* ptr;

public:
    // 생성자
    explicit AutoPtr(T* p = nullptr) : ptr(p) {}

    // 소유권 이전 복사 생성자
    // 핵심: 원본 객체의 포인터를 nullptr로 설정
    AutoPtr(AutoPtr& other) noexcept : ptr(other.release()) {}

    // 소유권 이전 할당 연산자
    AutoPtr& operator=(AutoPtr& other) noexcept {
        reset(other.release());
        return *this;
    }

    // 소유권 해제 및 반환
    T* release() noexcept {
        T* temp = ptr;
        ptr = nullptr;
        return temp;
    }

    // 기존 자원 해제 후 새 자원 설정
    void reset(T* p = nullptr) noexcept {
        if (ptr != nullptr) {
            delete ptr;
        }
        ptr = p;
    }

    // 소멸자
    ~AutoPtr() {
        delete ptr;
    }

    T& operator*() const { return *ptr; }
    T* operator->() const { return ptr; }
};
```

### 1.2 메모리 관리의 핵심 원리

| 단계 | 메커니즘 | 상태 변화 |
|------|---------|---------|
| **초기화** | 생 포인터를 AutoPtr 객체로 래핑 | 동적 할당 메모리 → AutoPtr 소유 |
| **소유권 이전** | `release()` 호출 시 포인터 값 반환 + 내부 포인터 nullptr 설정 | 소유권 원본 → 대상 |
| **자원 해제** | 소멸자에서 `delete` 연산 수행 | 메모리 반환 → 자유 저장소 |

---

## 2. C++17 준수 구현 (std::unique_ptr 사용)

```cpp
#include <memory>
#include <iostream>
#include <vector>

// 자원 관리 대상 클래스
class DatabaseConnection {
private:
    int connectionId;
    bool isActive;

public:
    explicit DatabaseConnection(int id) 
        : connectionId(id), isActive(true) {
        std::cout << "DatabaseConnection " << connectionId 
                  << " 생성됨\n";
    }

    ~DatabaseConnection() {
        std::cout << "DatabaseConnection " << connectionId 
                  << " 소멸됨\n";
        isActive = false;
    }

    void executeQuery(const char* query) const {
        if (isActive) {
            std::cout << "연결 " << connectionId 
                      << "에서 쿼리 실행: " << query << "\n";
        }
    }
};

// 모듈 A: 데이터베이스 연결 생성
class ConnectionPool {
public:
    // 소유권 이전을 통한 자원 반환
    std::unique_ptr<DatabaseConnection> acquireConnection(int poolId) {
        auto conn = std::make_unique<DatabaseConnection>(poolId);
        return conn; // RVO(Return Value Optimization)에 의한 효율적 이전
    }
};

// 모듈 B: 연결 소유권 수용 및 관리
class QueryExecutor {
private:
    std::unique_ptr<DatabaseConnection> connection;

public:
    // 소유권 이전을 통한 초기화
    void setConnection(std::unique_ptr<DatabaseConnection> conn) {
        connection = std::move(conn);
        // 기존 connection이 존재했다면 자동으로 소멸
    }

    void executeOperation(const char* query) {
        if (connection) {
            connection->executeQuery(query);
        }
    }

    // 소유권 반환
    std::unique_ptr<DatabaseConnection> releaseConnection() {
        return std::move(connection);
    }
};

// 모듈 C: 배열 기반 소유권 관리
class ConnectionManager {
private:
    std::vector<std::unique_ptr<DatabaseConnection>> connections;

public:
    void addConnection(std::unique_ptr<DatabaseConnection> conn) {
        connections.push_back(std::move(conn));
    }

    size_t getConnectionCount() const {
        return connections.size();
    }
};

// 실행 흐름 예시
int main() {
    {
        ConnectionPool pool;
        QueryExecutor executor;
        ConnectionManager manager;

        // 1단계: 소유권 이전 (pool → executor)
        auto conn1 = pool.acquireConnection(1);
        executor.setConnection(std::move(conn1));
        // conn1은 이제 nullptr 상태 (소유권 상실)

        // 2단계: 연산 수행
        executor.executeOperation("SELECT * FROM users");

        // 3단계: 소유권 이전 (executor → manager)
        auto retrievedConn = executor.releaseConnection();
        manager.addConnection(std::move(retrievedConn));

        // 4단계: 추가 연결 생성 및 관리
        manager.addConnection(pool.acquireConnection(2));
        manager.addConnection(pool.acquireConnection(3));

        std::cout << "관리 중인 연결: " 
                  << manager.getConnectionCount() << "\n";

    } // 블록 종료 시 모든 unique_ptr 자동 소멸

    return 0;
}
```

