## `std::auto_ptr`를 사용한 메모리 관리 및 소유권 이전 코드 예시

```cpp
#include <memory>
#include <iostream>

class Resource {
public:
    Resource(int id) : id_(id) {
        std::cout << "Resource " << id_ << " constructed\n";
    }

    ~Resource() {
        std::cout << "Resource " << id_ << " destroyed\n";
    }

    void process() const {
        std::cout << "Processing resource " << id_ << "\n";
    }

private:
    int id_;
};

// 소유권을 받아서 처리하는 함수
void takeOwnership(std::auto_ptr<Resource> res) {
    if (res.get()) {
        std::cout << "Function now owns the resource\n";
        res->process();
    }
    // 함수 종료 시 res의 소멸자가 호출되어 메모리 해제
}

// 소유권을 반환하는 함수
std::auto_ptr<Resource> createResource(int id) {
    std::auto_ptr<Resource> ptr(new Resource(id));
    return ptr; // 소유권 이전
}

int main() {
    // 1. 자원 생성 및 소유권 획득
    std::auto_ptr<Resource> ptr1(new Resource(1));

    // 2. 소유권을 함수로 이전
    takeOwnership(ptr1); // ptr1에서 소유권이 이전됨

    // ptr1은 이제 nullptr를 가리킴
    if (!ptr1.get()) {
        std::cout << "ptr1 no longer owns any resource\n";
    }

    // 3. 함수에서 반환된 소유권 획득
    std::auto_ptr<Resource> ptr2 = createResource(2);

    // 4. 소유권을 다른 auto_ptr로 이전
    std::auto_ptr<Resource> ptr3;
    ptr3 = ptr2; // ptr2에서 ptr3으로 소유권 이전

    if (!ptr2.get()) {
        std::cout << "ptr2 no longer owns any resource\n";
    }

    // 5. 명시적 소유권 해제
    Resource* rawPtr = ptr3.release();
    delete rawPtr; // 수동 메모리 해제

    return 0;
}
