### 2. C++17 준수 소유권 이전 모듈 구현 코드

아래 코드는 `std::auto_ptr`의 복사 생성자(Copy Constructor) 및 복사 대입 연산자(Copy Assignment Operator)가 가졌던 **파괴적 복사(Destructive Copy)** 메커니즘을 그대로 재현하여, 자원의 독점적 소유권을 이전하는 모듈입니다.

```cpp
#include <iostream>
#include <utility>

// std::auto_ptr의 내부 동작 메커니즘을 모방한 사용자 정의 클래스 template
template <typename T>
class auto_ptr {
private:
    T* m_ptr; // 관리 대상 객체를 가리키는 원시 포인터 (Raw Pointer)

public:
    // 생성자 (Constructor)
    explicit auto_ptr(T* ptr = nullptr) noexcept : m_ptr(ptr) {}

    // 소멸자 (Destructor): 자원 해제 및 메모리 누수 방지
    ~auto_ptr() noexcept {
        delete m_ptr;
    }

    // 파괴적 복사 생성자 (Destructive Copy Constructor)
    // 매개변수가 const 참조가 아님에 유의 (소유권 이전을 위해 원본 객체 수정 필요)
    auto_ptr(auto_ptr& other) noexcept : m_ptr(other.release()) {}

    // 파괴적 복사 대입 연산자 (Destructive Copy Assignment Operator)
    auto_ptr& operator=(auto_ptr& other) noexcept {
        if (this != &other) {
            reset(other.release());
        }
        return *this;
    }

    // 역참조 연산자 (Dereference Operator)
    T& operator*() const noexcept {
        return *m_ptr;
    }

    // 멤버 접근 연산자 (Member Access Operator)
    T* operator->() const noexcept {
        return m_ptr;
    }

    // 포인터 반환 (Getter)
    T* get() const noexcept {
        return m_ptr;
    }

    // 소유권 포기 및 원시 포인터 반환 (Release)
    T* release() noexcept {
        T* temp = m_ptr;
        m_ptr = nullptr;
        return temp;
    }

    // 자원 교체 및 기존 자원 해제 (Reset)
    void reset(T* ptr = nullptr) noexcept {
        if (m_ptr != ptr) {
            delete m_ptr;
            m_ptr = ptr;
        }
    }
};

// 테스트를 위한 시스템 자원 클래스
class SystemResource {
private:
    int m_id;

public:
    explicit SystemResource(int id) : m_id(id) {
        std::cout << "SystemResource " << m_id << " Allocated.\n";
    }
    ~SystemResource() {
        std::cout << "SystemResource " << m_id << " Deallocated.\n";
    }
    void Execute() const {
        std::cout << "Executing resource " << m_id << " operations.\n";
    }
};

// 소유권을 이전받아 작업을 수행하는 함수
void ConsumeResource(auto_ptr<SystemResource> res) {
    std::cout << "Inside ConsumeResource function.\n";
    if (res.get() != nullptr) {
        res->Execute();
    }
    // 함수 종료 시 res의 수명이 다하여 소멸자가 호출되고 자원이 해제됨
}

int main() {
    std::cout << "--- Program Start ---\n";

    // 1. 자원 생성 및 auto_ptr 초기화
    auto_ptr<SystemResource> ptr1(new SystemResource(101));

    // 2. 소유권 이전 (Destructive Copy 발생)
    // ptr1에서 ConsumeResource의 매개변수로 소유권이 이전됨
    ConsumeResource(ptr1);

    // 3. 소유권 이전 후 상태 검증
    if (ptr1.get() == nullptr) {
        std::cout << "ptr1 no longer owns the resource (Null Pointer).\n";
    }

    std::cout << "--- Program End ---\n";
    return 0;
}
```

