## 3. 실제로 동작하는 코드: 각 접근법의 구현

요구 사항의 각 제약을 **하나씩 완화**하여 실제로 동작하는 구현을 제시합니다.

### 3.1 구현 A: Multi-process (Blocking I/O 유지, fork 기반)

```c
/* high_perf_server_fork.c
 * 
 * Blocking I/O를 유지하면서 동시성을 달성하는 방법:
 * 각 connection마다 새로운 process를 fork()
 * 
 * 한계: 수천 개의 동시 연결 시 프로세스 생성/소멸 오버헤드,
 *       메모리 오버헤드가 선형적으로 증가
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/socket.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <netinet/in.h>
#include <signal.h>
#include <errno.h>

#define PORT 8080
#define BACKLOG 4096
#define BUFFER_SIZE 65536

/* SIGCHLD 핸들러: zombie process 방지 */
static void sigchld_handler(int signo) {
    (void)signo;
    /* WNOHANG: waitpid가 블로킹되지 않도록 */
    while (waitpid(-1, NULL, WNOHANG) > 0);
}

/* HTTP 요청 처리 함수 (자식 프로세스에서 실행) */
static void handle_connection(int client_fd) {
    char buffer[BUFFER_SIZE];
    ssize_t bytes_read;

    /* 
     * 이 read()는 blocking syscall이지만,
     * 각 자식 프로세스가 독립적인 execution context를 가지므로
     * 다른 연결의 처리를 블로킹하지 않음
     */
    bytes_read = read(client_fd, buffer, sizeof(buffer) - 1);
    if (bytes_read <= 0) {
        close(client_fd);
        return;
    }
    buffer[bytes_read] = '\0';

    /* HTTP 응답 생성 및 전송 */
    const char *response = 
        "HTTP/1.1 200 OK\r\n"
        "Content-Type: text/plain\r\n"
        "Content-Length: 13\r\n"
        "Connection: close\r\n"
        "\r\n"
        "Hello, World!";

    /* write()도 blocking이지만 자식 프로세스에서 독립 실행 */
    write(client_fd, response, strlen(response));
    close(client_fd);
}

int main(void) {
    int server_fd, client_fd;
    struct sockaddr_in server_addr, client_addr;
    socklen_t client_len = sizeof(client_addr);
    pid_t pid;

    /* SIGCHLD 핸들러 등록 */
    struct sigaction sa;
    sa.sa_handler = sigchld_handler;
    sigemptyset(&sa.sa_mask);
    sa.sa_flags = SA_RESTART;
    sigaction(SIGCHLD, &sa, NULL);

    /* 소켓 생성 */
    server_fd = socket(AF_INET, SOCK_STREAM, 0);
    if (server_fd < 0) {
        perror("socket");
        exit(EXIT_FAILURE);
    }

    /* SO_REUSEADDR: TIME_WAIT 상태의 포트 재사용 허용 */
    int opt = 1;
    setsockopt(server_fd, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));

    /* TCP_NODELAY: Nagle 알고리즘 비활성화 (레이턴시 감소) */
    setsockopt(server_fd, IPPROTO_TCP, TCP_NODELAY, &opt, sizeof(opt));

    memset(&server_addr, 0, sizeof(server_addr));
    server_addr.sin_family = AF_INET;
    server_addr.sin_addr.s_addr = INADDR_ANY;
    server_addr.sin_port = htons(PORT);

    if (bind(server_fd, (struct sockaddr *)&server_addr, 
             sizeof(server_addr)) < 0) {
        perror("bind");
        exit(EXIT_FAILURE);
    }

    /* backlog 값을 크게 설정: SYN queue + accept queue 크기 */
    if (listen(server_fd, BACKLOG) < 0) {
        perror("listen");
        exit(EXIT_FAILURE);
    }

    printf("Server listening on port %d (fork-based)\n", PORT);

    while (1) {
        /* 
         * accept()는 blocking syscall:
         * 연결 요청이 없으면 메인 프로세스가 여기서 대기
         * 그러나 이미 fork된 자식들은 독립적으로 실행 중
         */
        client_fd = accept(server_fd, 
                          (struct sockaddr *)&client_addr, 
                          &client_len);
        if (client_fd < 0) {
            if (errno == EINTR) continue; /* 시그널에 의한 인터럽트 */
            perror("accept");
            continue;
        }

        pid = fork();
        if (pid < 0) {
            perror("fork");
            close(client_fd);
            continue;
        }

        if (pid == 0) {
            /* 자식 프로세스: 서버 소켓 닫고 클라이언트 처리 */
            close(server_fd);
            handle_connection(client_fd);
            exit(EXIT_SUCCESS);
        } else {
            /* 부모 프로세스: 클라이언트 소켓 닫고 다음 연결 대기 */
            close(client_fd);
        }
    }

    close(server_fd);
    return 0;
}
```

