## 6단계: 검증 테스트벤치

```verilog
// =====================================================
// Module: tb_combinational_counter
// Description: 순수 조합 논리 카운터 기능 검증
// =====================================================
`timescale 1ns/1ps

module tb_combinational_counter;

    reg  Count_en;
    reg  Reset;
    wire [7:0] Count;

    // DUT 인스턴스
    combinational_counter_8bit DUT (
        .Count_en (Count_en),
        .Reset    (Reset),
        .Count    (Count)
    );

    // 펄스 생성 태스크 (클럭이 아닌 단발 펄스)
    task pulse_count;
        begin
            Count_en = 1'b1;
            #10;              // 10ns 유지 (전파 지연 수렴 대기)
            Count_en = 1'b0;
            #10;              // 래치 안정화 대기
        end
    endtask

    initial begin
        // 초기화
        Count_en = 1'b0;
        Reset    = 1'b1;
        #20;
        Reset    = 1'b0;
        #10;

        $display("=== 순수 조합 논리 카운터 검증 ===");
        $display("시간\t\tCount_en\tCount(Dec)\tCount(Hex)");

        // 10회 카운트 펄스 인가
        repeat (10) begin
            pulse_count;
            $display("%0t ns\t\t%b\t\t%0d\t\t0x%02H",
                     $time, Count_en, Count, Count);
        end

        // 리셋 검증
        $display("\n--- 리셋 인가 ---");
        Reset = 1'b1;
        #5;
        $display("Reset 후 Count = %0d (기대값: 0)", Count);
        Reset = 1'b0;
        #5;

        // 리셋 후 재카운트
        repeat (5) begin
            pulse_count;
            $display("%0t ns\t\t%b\t\t%0d\t\t0x%02H",
                     $time, Count_en, Count, Count);
        end

        // 255→0 오버플로우 검증
        $display("\n--- 오버플로우 검증 (250까지 빠른 증가) ---");
        repeat (245) pulse_count;
        repeat (10) begin
            pulse_count;
            $display("오버플로우 근처: Count = %0d", Count);
        end

        $finish;
    end

    // 파형 덤프
    initial begin
        $dumpfile("comb_counter.vcd");
        $dumpvars(0, tb_combinational_counter);
    end

endmodule
```

