## 구현 1: SR 래치 기반 8비트 카운터

### SR 래치 기본 셀 모듈

```verilog
// SR 래치: NOR 게이트 교차 결합
// 클럭 없음, 플립플롭 없음
// 쌍안정 특성으로 1비트 상태 저장
module sr_latch (
    input  wire S,    // Set
    input  wire R,    // Reset
    output wire Q,    // 정상 출력
    output wire Q_n   // 반전 출력
);
    // NOR 게이트 교차 결합 (Cross-coupled NOR)
    // Q   = NOR(R, Q_n)
    // Q_n = NOR(S, Q)
    // 이 두 방정식은 S=0, R=0일 때 이전 상태를 유지하는
    // 비선형 피드백 방정식 시스템을 형성함
    assign Q   = ~(R | Q_n);
    assign Q_n = ~(S | Q);

endmodule
```

### D 래치 (게이트드 SR 래치) 모듈

```verilog
// 게이트드 D 래치 (Gated D Latch)
// Enable=1: 투명 모드(Transparent Mode) - D가 Q에 전파
// Enable=0: 불투명 모드(Opaque Mode) - 이전 상태 유지
// 클럭 에지 감지 없음 → 레벨 감지(Level-Sensitive) 동작
module d_latch (
    input  wire D,
    input  wire En,   // Enable (레벨 감지, 에지 감지 아님)
    output wire Q,
    output wire Q_n
);
    wire S, R;

    // AND 게이트로 SR 신호 생성
    assign S = D & En;
    assign R = (~D) & En;

    // SR 래치 인스턴스
    sr_latch u_sr (
        .S   (S),
        .R   (R),
        .Q   (Q),
        .Q_n (Q_n)
    );

endmodule
```

### 8비트 래치 레지스터

```verilog
// 8비트 레벨-감지 래치 레지스터
// 8개의 D 래치를 병렬 배치
module latch_register_8bit (
    input  wire [7:0] D,
    input  wire       En,
    output wire [7:0] Q,
    output wire [7:0] Q_n
);
    genvar i;
    generate
        for (i = 0; i < 8; i = i + 1) begin : latch_array
            d_latch u_latch (
                .D   (D[i]),
                .En  (En),
                .Q   (Q[i]),
                .Q_n (Q_n[i])
            );
        end
    endgenerate

endmodule
```

### 8비트 리플 가산기 (Ripple Carry Adder)

```verilog
// 전가산기 (Full Adder) - 순수 조합 논리
module full_adder (
    input  wire A,
    input  wire B,
    input  wire Cin,
    output wire Sum,
    output wire Cout
);
    // XOR, AND, OR 게이트만 사용
    wire xor_ab;
    assign xor_ab = A ^ B;
    assign Sum    = xor_ab ^ Cin;
    assign Cout   = (A & B) | (xor_ab & Cin);

endmodule

// 8비트 리플 캐리 가산기
// 입력 B를 8'b00000001로 고정하여 증분기(Incrementer)로 사용
module ripple_carry_incrementer_8bit (
    input  wire [7:0] A,       // 현재 카운터 값
    output wire [7:0] Sum,     // A + 1
    output wire       Cout     // 오버플로우 캐리
);
    wire [7:0] carry;

    // 최하위 비트: B[0]=1, Cin=0 → 1 증가
    full_adder fa0 (
        .A    (A[0]),
        .B    (1'b1),
        .Cin  (1'b0),
        .Sum  (Sum[0]),
        .Cout (carry[0])
    );

    // 비트 1~7: B[i]=0, 캐리 전파
    genvar i;
    generate
        for (i = 1; i < 8; i = i + 1) begin : fa_chain
            full_adder fa_i (
                .A    (A[i]),
                .B    (1'b0),
                .Cin  (carry[i-1]),
                .Sum  (Sum[i]),
                .Cout (carry[i])
            );
        end
    endgenerate

    assign Cout = carry[7];

endmodule
```

### 최상위 8비트 카운터 모듈

```verilog
// ============================================================
// 모듈명  : counter_8bit_combinational
// 동작    : 클럭/플립플롭 미사용 8비트 카운터
// 상태저장: NOR 교차결합 SR 래치 (쌍안정 피드백 루프)
// 입력    : inc  - 증가 신호 (레벨 감지, 활성 하이)
//           rst  - 비동기 리셋 (활성 하이)
// 출력    : count - 현재 8비트 카운터 값
// ============================================================
module counter_8bit_combinational (
    input  wire inc,          // 카운터 증가 신호
    input  wire rst,          // 리셋 신호
    output wire [7:0] count   // 현재 카운터 값
);

    // --------------------------------------------------------
    // 내부 신호 선언
    // --------------------------------------------------------
    wire [7:0] q_current;     // 래치 출력 (현재 저장 상태)
    wire [7:0] q_n_current;   // 래치 반전 출력
    wire [7:0] incremented;   // 가산기 출력 (q_current + 1)
    wire       carry_out;     // 오버플로우 캐리

    wire [7:0] next_value;    // 래치에 기록될 다음 값
    wire       latch_enable;  // 래치 인에이블 신호

    // --------------------------------------------------------
    // 래치 인에이블 신호 생성
    // inc=1이고 rst=0일 때 래치를 투명 모드로 전환
    // inc 신호의 레벨이 HIGH인 동안 가산기 출력이 래치에 전파됨
    //
    // [주의] 이것이 핵심 타이밍 제약:
    // inc 펄스 폭이 가산기의 전파 지연(Propagation Delay)보다
    // 충분히 길어야 올바른 값이 래치에 포착(Capture)됨
    // --------------------------------------------------------
    assign latch_enable = inc & (~rst);

    // --------------------------------------------------------
    // 리셋 멀티플렉서 (조합 논리 2:1 MUX)
    // rst=1: 0x00 선택
    // rst=0: 가산기 출력 선택
    // --------------------------------------------------------
    assign next_value = rst ? 8'b0000_0000 : incremented;

    // --------------------------------------------------------
    // 8비트 증분기 인스턴스
    // q_current를 입력으로 받아 q_current+1 계산
    // --------------------------------------------------------
    ripple_carry_incrementer_8bit u_inc (
        .A    (q_current),
        .Sum  (incremented),
        .Cout (carry_out)
    );

    // --------------------------------------------------------
    // 8비트 래치 레지스터 인스턴스
    // latch_enable=1: next_value를 q_current에 전파
    // latch_enable=0: q_current 값 유지 (쌍안정 상태 유지)
    // --------------------------------------------------------
    latch_register_8bit u_latch_reg (
        .D   (next_value),
        .En  (latch_enable),
        .Q   (q_current),
        .Q_n (q_n_current)
    );

    // --------------------------------------------------------
    // 출력 연결
    // --------------------------------------------------------
    assign count = q_current;

endmodule
```

