## 4. 요구사항 달성을 위한 대안적 아키텍처 패턴

"다형성 극대화"와 "코드 재사용성 극대화"라는 실질적 요구사항은 다음 패턴으로 구현 가능합니다.

### 4.1 인터페이스 기반 다중 타입 구현 (Interface Segregation + Polymorphism)

```java
// 기능 계약을 인터페이스로 분리
public interface CapabilityA {
    void operationA();
    default void sharedOperation() {
        System.out.println("Shared via CapabilityA default method");
    }
}

public interface CapabilityB {
    void operationB();
    default void sharedOperation() {
        System.out.println("Shared via CapabilityB default method");
    }
}

// ClassA: CapabilityA와 CapabilityB를 모두 구현
public class ClassA implements CapabilityA, CapabilityB {

    @Override
    public void operationA() {
        System.out.println("ClassA.operationA() executed");
    }

    @Override
    public void operationB() {
        System.out.println("ClassA.operationB() executed");
    }

    // 다중 인터페이스 default 메서드 충돌 해소 (Diamond Problem 해결)
    @Override
    public void sharedOperation() {
        CapabilityA.super.sharedOperation();
        CapabilityB.super.sharedOperation();
    }
}

// ClassB: CapabilityA와 CapabilityB를 모두 구현
public class ClassB implements CapabilityA, CapabilityB {

    @Override
    public void operationA() {
        System.out.println("ClassB.operationA() executed");
    }

    @Override
    public void operationB() {
        System.out.println("ClassB.operationB() executed");
    }

    @Override
    public void sharedOperation() {
        CapabilityA.super.sharedOperation();
        CapabilityB.super.sharedOperation();
    }
}
```

### 4.2 컴포지션(Composition) + 위임(Delegation) 패턴

```java
// 공유 로직을 별도 컴포넌트로 추출
public class SharedComponent {

    private final String componentId;

    public SharedComponent(String componentId) {
        this.componentId = componentId;
    }

    public void executeSharedLogic() {
        System.out.println("SharedComponent[" + componentId + "] executing");
    }

    public String getComponentId() {
        return componentId;
    }
}

public class ClassA implements CapabilityA, CapabilityB {

    // 상속 대신 컴포지션으로 ClassB의 기능 활용
    private final SharedComponent sharedComponent;
    private final ClassB delegateB;  // 위임 대상

    public ClassA(SharedComponent sharedComponent) {
        this.sharedComponent = sharedComponent;
        this.delegateB = null;  // 순환 참조 방지: 필요 시 setter injection 사용
    }

    @Override
    public void operationA() {
        sharedComponent.executeSharedLogic();
        System.out.println("ClassA specific operation");
    }

    @Override
    public void operationB() {
        // ClassB의 operationB 로직을 SharedComponent를 통해 재사용
        sharedComponent.executeSharedLogic();
        System.out.println("ClassA delegating B-type operation");
    }

    @Override
    public void sharedOperation() {
        sharedComponent.executeSharedLogic();
    }
}

public class ClassB implements CapabilityA, CapabilityB {

    private final SharedComponent sharedComponent;

    public ClassB(SharedComponent sharedComponent) {
        this.sharedComponent = sharedComponent;
    }

    @Override
    public void operationA() {
        sharedComponent.executeSharedLogic();
        System.out.println("ClassB delegating A-type operation");
    }

    @Override
    public void operationB() {
        sharedComponent.executeSharedLogic();
        System.out.println("ClassB specific operation");
    }

    @Override
    public void sharedOperation() {
        sharedComponent.executeSharedLogic();
    }
}
```

### 4.3 추상 슈퍼타입(Abstract Supertype) 기반 단방향 계층 구조

```java
// 공통 계약과 구현을 추상 클래스로 일원화
public abstract class AbstractBase {

    protected final String instanceId;

    protected AbstractBase(String instanceId) {
        this.instanceId = instanceId;
    }

    // Template Method Pattern 적용
    public final void execute() {
        preProcess();
        doExecute();
        postProcess();
    }

    protected void preProcess() {
        System.out.println("AbstractBase.preProcess(): " + instanceId);
    }

    protected abstract void doExecute();

    protected void postProcess() {
        System.out.println("AbstractBase.postProcess(): " + instanceId);
    }

    // 공통 기능 구현
    public String getInstanceId() {
        return instanceId;
    }
}

// ClassA: AbstractBase를 단방향으로 상속
public class ClassA extends AbstractBase {

    private int stateA;

    public ClassA(String instanceId, int stateA) {
        super(instanceId);
        this.stateA = stateA;
    }

    @Override
    protected void doExecute() {
        System.out.println("ClassA.doExecute() with stateA=" + stateA);
    }

    public int getStateA() {
        return stateA;
    }
}

// ClassB: AbstractBase를 단방향으로 상속
public class ClassB extends AbstractBase {

    private String stateB;

    public ClassB(String instanceId, String stateB) {
        super(instanceId);
        this.stateB = stateB;
    }

    @Override
    protected void doExecute() {
        System.out.println("ClassB.doExecute() with stateB=" + stateB);
    }

    public String getStateB() {
        return stateB;
    }
}
```

